-- Poems batch 386
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('8669ebed-b68e-43f4-9a16-e6cf965ca1d8','有懷山中  其一','沈與求','宋','宋诗','song-poetry','','[]','可奈風埃老客游，故山歸思日悠悠。',32,'全唐诗/poet.song.96000.json','["可奈風埃老客游，故山歸思日悠悠。", "軒裳結裹非吾事，野性從來在一丘。"]'),
('68ee2ab9-fb4e-4a81-ba72-c8c5ee2209ad','有懷山中  其二','沈與求','宋','宋诗','song-poetry','','[]','冠卷塵埃亦漫彈，勒移終復愧家山。',32,'全唐诗/poet.song.96000.json','["冠卷塵埃亦漫彈，勒移終復愧家山。", "它年猿鶴應相笑，倦羽卑飛久未還。"]'),
('f54e0a2c-e065-440d-a2a6-39223480e9ee','次韻宏父喜雨','沈與求','宋','宋诗','song-poetry','','[]','黄壟初看卷麥禾，老農還復厭晴多。',64,'全唐诗/poet.song.96000.json','["黄壟初看卷麥禾，老農還復厭晴多。", "四郊戽尾開新瀆，一雨苗根長舊科。", "已發政聲歸召杜，更驚詩律鬬陰何。", "王孫欲識田家樂，水亂溝塍涉可過。"]'),
('292db3d5-1fa7-4ad4-87e4-7bd02055215c','行簡以曾守韻見貽復和一篇','沈與求','宋','宋诗','song-poetry','','[]','續經無復補嘉禾，老去忘懷及見多。',64,'全唐诗/poet.song.96000.json','["續經無復補嘉禾，老去忘懷及見多。", "摘尾簿書寧問署，點頭章句僅成科。", "求田下澤吾行且，招隱空山子謂何。", "千萬買鄰真左計，一丘端約老相過。"]'),
('8b0128c7-8d27-4e91-8bbc-43a4bbf7eb5a','申應時以圖尋山圖所載湖之西溪也爲作二絕句  其一','沈與求','宋','宋诗','song-poetry','','[]','王維買宅先成畫，申子尋山亦載圖。',32,'全唐诗/poet.song.96000.json','["王維買宅先成畫，申子尋山亦載圖。", "它日真能營小築，此山佳處着儂無。"]'),
('5870f558-2047-4dd6-9b42-756d32b56fd4','申應時以圖尋山圖所載湖之西溪也爲作二絕句  其二','沈與求','宋','宋诗','song-poetry','','[]','故國山川真可老，十年塵土負歸期。',32,'全唐诗/poet.song.96000.json','["故國山川真可老，十年塵土負歸期。", "而今更笑申夫子，似我平生費夢思。"]'),
('372007a3-2a51-4ad4-bbe5-80cc89cb405a','客至具餉庖中止有豚肝客不食','沈與求','宋','宋诗','song-poetry','','[]','三九家風故自寒，朝來饌客到豚肝。',32,'全唐诗/poet.song.96000.json','["三九家風故自寒，朝來饌客到豚肝。", "不須凖擬供塗竈，口腹那能累長官。"]'),
('8e5f90d9-4226-43e1-9f17-0fd756328ccd','次律兄持節燕山且調兩河兵賦喜而作詩  其一','沈與求','宋','宋诗','song-poetry','','[]','伯也吾宗秀，心期萬里侯。',48,'全唐诗/poet.song.96000.json','["伯也吾宗秀，心期萬里侯。", "燕民方築郡，漢使果鳴騶。", "更借牙籌計，聊寛玉座憂。", "平生揮翰手，此意莫淹留。"]'),
('a376646a-a8b0-4a05-ba98-2e63ec3ee586','次律兄持節燕山且調兩河兵賦喜而作詩  其二','沈與求','宋','宋诗','song-poetry','','[]','中年情緒惡，遠別信音疏。',48,'全唐诗/poet.song.96000.json','["中年情緒惡，遠別信音疏。", "聞道陰山路，貪迎使者車。", "騎羊厭鳴鏑，佩犢欲扶鋤。", "願上螭頭奏，煩苛一切除。"]'),
('e9db0405-7a98-4f2e-a21a-67d1492b3a38','喜次律兄見過','沈與求','宋','宋诗','song-poetry','','[]','大艑軻{車我}許暫留，一樽相屬話牢愁。',67,'全唐诗/poet.song.96000.json','["大艑軻{車我}許暫留，一樽相屬話牢愁。", "封胡羯末名終在，許史金張迹浪投。", "遵陸漸看鴻雁集，在原當記鶺鴒求。", "它年會有相從樂，泛宅浮家萬事休。"]'),
('f92db8c1-5591-49a1-a547-0915c0c139a6','倦夜','沈與求','宋','宋诗','song-poetry','','[]','獨坐苦無賴，開軒懷抱空。',48,'全唐诗/poet.song.96000.json','["獨坐苦無賴，開軒懷抱空。", "徘徊簾上月，淅瀝竹間風。", "清影迷篝火，哀音咽砌蟲。", "怪來寒次骨，霜氣已冥濛。"]'),
('0c2fb212-c1f7-4d36-8b7c-f19821f5641f','單顔徒以盜失邑被譴赦令復官喜而有詩次其韻','沈與求','宋','宋诗','song-poetry','','[]','千里風雷起放臣，反騷端欲陋靈均。',64,'全唐诗/poet.song.96000.json','["千里風雷起放臣，反騷端欲陋靈均。", "宦情遽逐鵬程遠，喜氣猶驚鵲語新。", "它日鍾魚應落夢，半生塵土未酬身。", "會須更整青雲步，往事當令問水濱。"]'),
('2952880d-bedb-4049-a84c-1502dbe5bd2a','土人腊蛙見餉爲作此詩','沈與求','宋','宋诗','song-poetry','','[]','此族知何族，生涯一廢池。',48,'全唐诗/poet.song.96000.json','["此族知何族，生涯一廢池。", "似能矜喜怒，那復辨官私。", "暑雨浮萍閙，秋風牡菊遲。", "肯嫌同腊鼠，小嚼爲紛披。"]'),
('484752eb-ac86-40b5-a077-2e349fc7e9d1','送別','沈與求','宋','宋诗','song-poetry','','[]','老覺交情重，貧知世路高。',48,'全唐诗/poet.song.96000.json','["老覺交情重，貧知世路高。", "相看心已折，此別夢應勞。", "未用脂長轂，須聽詠大刀。", "平生故人意，能費幾綈袍。"]'),
('5caa0a35-cf16-4fd3-868c-e3dc6670f847','莊于經解官作二詩道別有江湖蓑笠之句次其韻兼敘離索  其一','沈與求','宋','宋诗','song-poetry','','[]','雨餘千里見秋毫，綠漲西陂湧浪濤。',64,'全唐诗/poet.song.96000.json','["雨餘千里見秋毫，綠漲西陂湧浪濤。", "桂楫蘭舟驚送別，鸞篦象齒記分曹。", "官游莫漫嗟流落，人事方將困驛騷。", "亦欲江湖理烟艇，不知何處可容篙。"]'),
('64abe099-1262-4af4-bd8f-58166f1a2015','莊于經解官作二詩道別有江湖蓑笠之句次其韻兼敘離索  其二','沈與求','宋','宋诗','song-poetry','','[]','自許論交絕比周，向來傾蓋喜同流。',64,'全唐诗/poet.song.96000.json','["自許論交絕比周，向來傾蓋喜同流。", "俗間久矣無青白，客裏終然有去留。", "能事要須槃礴臝，廋詞何必畔牢愁。", "看君躍馬章臺道，肯爲滄波夢棹謳。"]'),
('b6d813ab-7ba5-4bca-ba47-ca1cc6f9a77f','秉元以按田至村落有詩次其韻','沈與求','宋','宋诗','song-poetry','','[]','竹戶連村閉，官何此榜舟。',48,'全唐诗/poet.song.96000.json','["竹戶連村閉，官何此榜舟。", "蒿萊半殘壟，風露溢清愁。", "試爲歌田畯，那知餞蓐收。", "老盆如見領，應作小遲留。"]'),
('a7c2a964-3c0b-43dc-ac30-207b0f6c028e','巖桂','沈與求','宋','宋诗','song-poetry','','[]','小軒巖桂露香乾，秋蘂扶疏碧玉寒。',32,'全唐诗/poet.song.96000.json','["小軒巖桂露香乾，秋蘂扶疏碧玉寒。", "章句那能如許樣，夜深渾作月中看。"]'),
('46b90715-312f-4eaa-b393-37318ed3ef54','次韻行簡北城登眺述懷','沈與求','宋','宋诗','song-poetry','','[]','東觀無人數伏虔，一臞塵土獨凄然。',64,'全唐诗/poet.song.96000.json','["東觀無人數伏虔，一臞塵土獨凄然。", "高情自欲侵天半，清夢何由到日邊。", "顧我書空嗟咄咄，知君捫腹笑便便。", "登高懷遠無窮意，故合春容賦大篇。"]'),
('eb3612be-a0ff-4a9c-8125-aedf69426fb6','行簡釋奠學宮登北城眺覧有詩嘗次其韻再和二章  其一','沈與求','宋','宋诗','song-poetry','','[]','奠幣儒宫已告虔，城樓遠想獨悠然。',64,'全唐诗/poet.song.96000.json','["奠幣儒宫已告虔，城樓遠想獨悠然。", "陰陰古木回潭外，渺渺平蕪落照邊。", "野色向人聊嫵媚，笻枝入手自輕便。", "興來不暇尋思嬾，酒後狂歌定幾篇。"]'),
('a6c1ea8c-52be-423c-9c7f-f083e0f7efb2','行簡釋奠學宮登北城眺覧有詩嘗次其韻再和二章  其二','沈與求','宋','宋诗','song-poetry','','[]','當年蠟鳳識僧虔，晚歲相從意惘然。',64,'全唐诗/poet.song.96000.json','["當年蠟鳳識僧虔，晚歲相從意惘然。", "更笑豎儒多敗事，稍聞上郡已開邊。", "酒醪窮巷誰能載，簡牘平生自不便。", "風月兩溪真可老，待收功業付詩篇。"]'),
('cc368bd7-07b7-4ff6-ba13-6ecaaf718c2f','曾守置酒月波樓以張倅至有詩命坐客同賦','沈與求','宋','宋诗','song-poetry','','[]','詞語平生故自蕪，登高重愧賦成初。',64,'全唐诗/poet.song.96000.json','["詞語平生故自蕪，登高重愧賦成初。", "諸君此處識老子，右衛向來煩長輿。", "波上旌旗飛退鷁，樓前歌管出金魚。", "回欄後夜同延月，直下方池可更疏。"]'),
('2af2cf5b-cc97-4bf3-a7f3-8f8ecaa51caf','夜坐  其一','沈與求','宋','宋诗','song-poetry','','[]','娟娟微月小窗東，竹裏寒聲嘯夕風。',32,'全唐诗/poet.song.96000.json','["娟娟微月小窗東，竹裏寒聲嘯夕風。", "孤客坐來驚歲晚，推愁不去酒杯空。"]'),
('7ef51cc2-9d85-4cda-8eea-ed0b8dcb1c4c','夜坐  其二','沈與求','宋','宋诗','song-poetry','','[]','虛堂夜寂自神清，更僕無端倦觸屏。',32,'全唐诗/poet.song.96000.json','["虛堂夜寂自神清，更僕無端倦觸屏。", "多謝短檠隨我老，更温檀火校黄庭。"]'),
('50bf96db-c23d-4b38-9310-5a19b783b468','曾守病目以治法與之有詩見貽次其韻','沈與求','宋','宋诗','song-poetry','','[]','聞道牙籤檢校頻，昏花錯莫亂驚塵。',64,'全唐诗/poet.song.96000.json','["聞道牙籤檢校頻，昏花錯莫亂驚塵。", "未須止酒妨投轄，便可捐書當徙薪。", "肘後有方餘幾所，眼中無障更何人。", "須公舊觀神明復，凖擬花前一笑春。"]'),
('833a7482-4a04-4bfa-8da8-7c1520a86dd4','次韻曾守立春席上七絕句  其一','沈與求','宋','宋诗','song-poetry','','[]','澤國春歸早，連門競築臺。',24,'全唐诗/poet.song.96000.json','["澤國春歸早，連門競築臺。", "夜來風力峭，疏片半飄梅。"]'),
('a7c6e886-e256-42e6-8174-bada8ad61aff','次韻曾守立春席上七絕句  其二','沈與求','宋','宋诗','song-poetry','','[]','曉凍穿流急，晨光照火新。',24,'全唐诗/poet.song.96000.json','["曉凍穿流急，晨光照火新。", "四郊和氣合，歌吹待班春。"]'),
('41005019-54f8-4943-993b-fe6f272ce00c','次韻曾守立春席上七絕句  其三','沈與求','宋','宋诗','song-poetry','','[]','花光浮翦勝，酒色動雕觴。',24,'全唐诗/poet.song.96000.json','["花光浮翦勝，酒色動雕觴。", "欲識邦侯喜，眉間照席黄。"]'),
('d653a580-0e9e-4e43-9916-977c1dc3b384','次韻曾守立春席上七絕句  其四','沈與求','宋','宋诗','song-poetry','','[]','跨臘纔更歲，經宵併是春。',24,'全唐诗/poet.song.96000.json','["跨臘纔更歲，經宵併是春。", "黄堂清訟缿，欲助發生仁。"]'),
('2fdf9a39-b566-47d7-9ac8-a9560bff54cb','次韻曾守立春席上七絕句  其五','沈與求','宋','宋诗','song-poetry','','[]','日應東風轉，春隨北斗回。',24,'全唐诗/poet.song.96000.json','["日應東風轉，春隨北斗回。", "不須鄒子律，餘暖到寒荄。"]'),
('f20aa8cd-fef1-4071-b5db-40c379d6e4fc','次韻曾守立春席上七絕句  其六','沈與求','宋','宋诗','song-poetry','','[]','曉卜農祥正，遙知歲事豐。',24,'全唐诗/poet.song.96000.json','["曉卜農祥正，遙知歲事豐。", "小桃如有意，欲吐故時紅。"]'),
('c3483a0a-3ad6-442d-994e-b80e68455ffe','次韻曾守立春席上七絕句  其七','沈與求','宋','宋诗','song-poetry','','[]','曲席紛羅綺，中腔度管絲。',24,'全唐诗/poet.song.96000.json','["曲席紛羅綺，中腔度管絲。", "歡聲連萬井，一一擁春祺。"]'),
('423ca15b-3a24-4ca2-a7ae-0f93cd65f5e8','月波樓','沈與求','宋','宋诗','song-poetry','','[]','突兀晴樓壓郡城，樓前波面縠紋生。',32,'全唐诗/poet.song.96000.json','["突兀晴樓壓郡城，樓前波面縠紋生。", "何人合作佳從事，來伴胡床看月明。"]'),
('9951c9f4-7819-443b-aa52-0a931619f1ab','會景亭','沈與求','宋','宋诗','song-poetry','','[]','柳株高下隔桃蹊，萬頃烟波似渼陂。',32,'全唐诗/poet.song.96000.json','["柳株高下隔桃蹊，萬頃烟波似渼陂。", "畫手無人貌平遠，小亭風冷立移時。"]'),
('f0df995c-c456-4fbd-b9c1-a64a27ee5802','次韻楊縣丞見寄','沈與求','宋','宋诗','song-poetry','','[]','雙瞳炯炯四筵傾，少日才堪賦兩京。',64,'全唐诗/poet.song.96000.json','["雙瞳炯炯四筵傾，少日才堪賦兩京。", "花縣署曹聊試可，鱣堂傳德尚流清。", "横琴勿寫峩峩志，引水當令㶁㶁鳴。", "後夜扁舟同泛月，野田端見綠蕪平。"]'),
('eff72668-0bd7-48c9-b965-5886caf005d1','次曾宏父韻  其一','沈與求','宋','宋诗','song-poetry','','[]','小雨經旬戶不開，隔牆青子滿江梅。',32,'全唐诗/poet.song.96000.json','["小雨經旬戶不開，隔牆青子滿江梅。", "幽禽葉底如相識，睥睨空庭欲下來。"]'),
('ae7c6ba3-9a58-4428-be68-f163515a837f','次曾宏父韻  其二','沈與求','宋','宋诗','song-poetry','','[]','三楚浮魂不可招，夢游赤壁夜停橈。',32,'全唐诗/poet.song.96000.json','["三楚浮魂不可招，夢游赤壁夜停橈。", "朝來快讀黄州賦，猶喜周郎得小喬。"]'),
('1578dee8-5e27-4569-a2b0-bc2d00eab3c5','次曾宏父韻  其三','沈與求','宋','宋诗','song-poetry','','[]','微官似有不如無，老去因循負壯圖。',32,'全唐诗/poet.song.96000.json','["微官似有不如無，老去因循負壯圖。", "但得誅茅三畝宅，世緣端欲付軒渠。"]'),
('63ea3572-7c2d-4f7c-ac7b-93e34dd85b97','次曾宏父韻  其四','沈與求','宋','宋诗','song-poetry','','[]','未用欣然念可人，世間那有白頭新。',32,'全唐诗/poet.song.96000.json','["未用欣然念可人，世間那有白頭新。", "出門更復推葱麥，笑殺扶風井大春。"]'),
('8e336835-f5be-463d-9b61-8578b2854de7','曾宏父作詩別行簡索僕同賦','沈與求','宋','宋诗','song-poetry','','[]','俗間忘勝踐，客裏度春愁。',144,'全唐诗/poet.song.96000.json','["俗間忘勝踐，客裏度春愁。", "拄頰真狂計，焦頭乏遠謀。", "剛疏徒自許，德怨浪相求。", "奏乏三千牘，詩慚一百籌。", "豈能資宦達，端合辦歸休。", "遣興鵝兒酒，銷魂燕子樓。", "枯笻青草渡，老屋白蘋洲。", "此意無窮樂，今懷未滿憂。", "轉喉寧問諱，繞指叵思柔。", "二妙看騰踏，頻年歎滯留。", "花時閉深院，雲際渺輕舟。", "應念騎曹掾，平生信謬悠。"]'),
('0fc337f7-c800-4cbe-9760-9c2b94fa3b3d','曾宏父將往霅川見內相葉公以詩爲別次其韻以自見  其一','沈與求','宋','宋诗','song-poetry','','[]','客裏思家且罷休，無聊懷抱不禁愁。',32,'全唐诗/poet.song.96000.json','["客裏思家且罷休，無聊懷抱不禁愁。", "鰣魚苦筍過百六，又到一年春盡頭。"]'),
('9310f0ab-73d7-4f8e-a5dc-e7454bdfb43d','曾宏父將往霅川見內相葉公以詩爲別次其韻以自見  其二','沈與求','宋','宋诗','song-poetry','','[]','腸斷故園春到時，澆花日日遶芳蹊。',32,'全唐诗/poet.song.96000.json','["腸斷故園春到時，澆花日日遶芳蹊。", "而今夢逐東風去，小榼深杯手自攜。"]'),
('d6890765-7166-4e0a-8d23-792b6cc9af1a','曾宏父將往霅川見內相葉公以詩爲別次其韻以自見  其三','沈與求','宋','宋诗','song-poetry','','[]','兩溪以南無數山，興來徑造無時闌。',32,'全唐诗/poet.song.96000.json','["兩溪以南無數山，興來徑造無時闌。", "空餘日蠟幾兩屐，日暮雲深天小寒。"]'),
('9fe3e3b4-f549-4ed0-bedb-32b72cdb16da','曾宏父將往霅川見內相葉公以詩爲別次其韻以自見  其四','沈與求','宋','宋诗','song-poetry','','[]','隔溪花柳自無賴，烟淡風微惱殺人。',32,'全唐诗/poet.song.96000.json','["隔溪花柳自無賴，烟淡風微惱殺人。", "走向西家覓酒伴，芒鞋竹杖去尋春。"]'),
('6dbb0df9-8d27-4bee-af9f-fe7c2e455641','曾宏父將往霅川見內相葉公以詩爲別次其韻以自見  其五','沈與求','宋','宋诗','song-poetry','','[]','牆根啁啾百鳥閙，最愛乳鳩來喚晴。',32,'全唐诗/poet.song.96000.json','["牆根啁啾百鳥閙，最愛乳鳩來喚晴。", "日永春閑深院落，渠能便當管絃聲。"]'),
('3d46c317-dbe5-4d23-ba1b-90371cedb503','曾宏父將往霅川見內相葉公以詩爲別次其韻以自見  其六','沈與求','宋','宋诗','song-poetry','','[]','揚舲送子下苕霅，繫纜沙頭多柳株。',32,'全唐诗/poet.song.96000.json','["揚舲送子下苕霅，繫纜沙頭多柳株。", "十載風埃老行客，不知鷗鳥記人無。"]'),
('0529c8a9-4e4e-41b8-b893-e55bfe102da9','曾宏父將往霅川見內相葉公以詩爲別次其韻以自見  其七','沈與求','宋','宋诗','song-poetry','','[]','前溪溪頭玉色魚，羊酪豈可比鮮腴。',32,'全唐诗/poet.song.96000.json','["前溪溪頭玉色魚，羊酪豈可比鮮腴。", "江黄會中有勝處，健步走置煩長鬚。"]'),
('0b42396e-84c7-41db-bbb8-f39848c081c7','曾宏父將往霅川見內相葉公以詩爲別次其韻以自見  其八','沈與求','宋','宋诗','song-poetry','','[]','野店山茶亦可口，試敲松火煮石泉。',32,'全唐诗/poet.song.96000.json','["野店山茶亦可口，試敲松火煮石泉。", "相逢故人如問訊，但道老去多煩煎。"]'),
('d0242be2-ca3f-436d-b029-a69df02daba7','曾宏父將往霅川見內相葉公以詩爲別次其韻以自見  其九','沈與求','宋','宋诗','song-poetry','','[]','翰林胸中浩千古，筆頭戲作江海潮。',32,'全唐诗/poet.song.96000.json','["翰林胸中浩千古，筆頭戲作江海潮。", "子行造膝可問法，門前烟浪拍溪橋。"]'),
('00af8479-f04a-45ba-b7fa-b53fd49ede0f','曾宏父將往霅川見內相葉公以詩爲別次其韻以自見  其一○','沈與求','宋','宋诗','song-poetry','','[]','邦侯言語妙天下，學海故自吞百川。',32,'全唐诗/poet.song.96000.json','["邦侯言語妙天下，學海故自吞百川。", "傳杯擊鉢盡具眼，醉中莫漫思逃禪。"]'),
('ab49a1d3-3074-4aaf-86a7-d1fb1818d45a','舟行即事','沈與求','宋','宋诗','song-poetry','','[]','逗帆風借力，入坐水浮光。',48,'全唐诗/poet.song.96000.json','["逗帆風借力，入坐水浮光。", "村落知多少，郵亭自短長。", "跳魚吹暗浪，浴鷺耿殘陽。", "又是吾廬遠，相看思渺茫。"]'),
('ecc3e3dc-3c38-4203-a070-98164d466213','舟過北塘','沈與求','宋','宋诗','song-poetry','','[]','嫋嫋輕颸動，娟娟佳月升。',48,'全唐诗/poet.song.96000.json','["嫋嫋輕颸動，娟娟佳月升。", "岸回雙樹暗，村遠一燈明。", "過雁參差影，跳魚撥刺聲。", "停橈且勿去，吾意不勝清。"]'),
('f381c252-7471-4618-a825-12b879d6a03f','羞墓','沈與求','宋','宋诗','song-poetry','','[]','富貴因人德未酬，繡衣歸去竟何求。',32,'全唐诗/poet.song.96000.json','["富貴因人德未酬，繡衣歸去竟何求。", "荒墳三尺斜陽裏，千古徒增女子羞。"]'),
('47fc55cd-a82f-4f25-b68b-77f91e58adb1','舟次吳淞江','沈與求','宋','宋诗','song-poetry','','[]','棹發鱸鄉晚，頻經桂子秋。',48,'全唐诗/poet.song.96000.json','["棹發鱸鄉晚，頻經桂子秋。", "嬾投青玉案，政敝黑貂裘。", "水落喧漁市，雲微辨橘洲。", "五湖烟浪静，誰復泛扁舟。"]'),
('b00bc61b-35fe-4254-a2a5-d833ab5e9494','吳江阻雨過豁然閣次周廉彦韻  其一','沈與求','宋','宋诗','song-poetry','','[]','花鴨呼群自拍浮，何人蓑笠在孤舟。',32,'全唐诗/poet.song.96000.json','["花鴨呼群自拍浮，何人蓑笠在孤舟。", "半生已負江湖約，不爲經行肯蹔留。"]'),
('268b863d-dcef-45e3-94f0-919f024da380','吳江阻雨過豁然閣次周廉彦韻  其二','沈與求','宋','宋诗','song-poetry','','[]','濛濛小雨麥秋天，江上人家欲暮烟。',32,'全唐诗/poet.song.96000.json','["濛濛小雨麥秋天，江上人家欲暮烟。", "行客未能忘勝處，繫舡來伴白鷗眠。"]'),
('2f6efdcd-2798-4278-9c08-c04b79ee14ea','吳江阻雨過豁然閣次周廉彦韻  其三','沈與求','宋','宋诗','song-poetry','','[]','我本三生一散人，翩然小棹五湖春。',32,'全唐诗/poet.song.96000.json','["我本三生一散人，翩然小棹五湖春。", "何從便結滄浪伴，纓上而今有宿塵。"]'),
('2e71cf69-24a9-48a0-bf0c-af1972968467','燈上人頤齋','沈與求','宋','宋诗','song-poetry','','[]','道人小室要觀身，兀坐蒲團莫欠伸。',32,'全唐诗/poet.song.96000.json','["道人小室要觀身，兀坐蒲團莫欠伸。", "縱有諸天來應供，靈龜納息自爲真。"]'),
('8574313e-c0c2-4772-a43b-bef1052dcee6','次韻江元壽題寧境寺湖光亭','沈與求','宋','宋诗','song-poetry','','[]','客行終日厭區區，蹔借晴光照坐隅。',64,'全唐诗/poet.song.96000.json','["客行終日厭區區，蹔借晴光照坐隅。", "水漾龍鱗浮窣堵，蓴開雉尾供伊蒲。", "欲隨漁子飛雙槳，似與仙翁在一壺。", "目亂風埃知有幾，肯來幽處濯纓無。"]'),
('0ac35ea3-6395-461a-8a76-e71b2e45c282','舟中聞元用遂魁天下士論歸之輒成五十六字呈宏父車馬至中都當舉似也','沈與求','宋','宋诗','song-poetry','','[]','翰林發策冠諸儒，再世重歸汗血駒。',64,'全唐诗/poet.song.96000.json','["翰林發策冠諸儒，再世重歸汗血駒。", "醉後揮毫凌月窟，夢中插翼上天衢。", "半生懷抱吞餘子，一日聲名振八區。", "歸去玉堂清夜直，也應憐我老江湖。"]'),
('e3c94ff3-5492-4d8d-a7ed-4e58e3da3848','吳門別曾宏父','沈與求','宋','宋诗','song-poetry','','[]','招手湖山初識君，眼中已復見輪囷。',64,'全唐诗/poet.song.96000.json','["招手湖山初識君，眼中已復見輪囷。", "清言自是一時傑，豪氣欲無千載人。", "客路臨分隨夢遠，老懷論舊覺情親。", "心期不免功名逼，儻記江南草樹春。"]'),
('1a86a441-55dd-4ab9-9e81-ee76a5e686ff','還憩湖光亭復次江元壽韻','沈與求','宋','宋诗','song-poetry','','[]','羊酪蓴羹本異區，江湖隨俗語娵隅。',64,'全唐诗/poet.song.96000.json','["羊酪蓴羹本異區，江湖隨俗語娵隅。", "紫鱗撥刺衝文荇，翠羽翩翾過綠蒲。", "舴艋興饒青絡馬，笭箵自當紫微壺。", "叢書校罷頻搔首，天末孤帆去欲無。"]'),
('3324a48a-1406-4149-9e41-e09991b0c9a7','次韻錢德初九日旅懷三絕  其一','沈與求','宋','宋诗','song-poetry','','[]','西風江面荻花秋，鱠玉頻年念昔游。',32,'全唐诗/poet.song.96000.json','["西風江面荻花秋，鱠玉頻年念昔游。", "客帽只今無地落，黄花滿眼漫供愁。"]'),
('04a23a27-0fde-42b9-807c-6535033b5d44','次韻錢德初九日旅懷三絕  其二','沈與求','宋','宋诗','song-poetry','','[]','登高虛欲夸能賦，樂事何曾副賞心。',32,'全唐诗/poet.song.96000.json','["登高虛欲夸能賦，樂事何曾副賞心。", "斜日孤雲兩愁絕，一觴聊爲盍朋簮。"]'),
('9cd58a3b-246b-4aed-bead-f866e2c7bdde','次韻錢德初九日旅懷三絕  其三','沈與求','宋','宋诗','song-poetry','','[]','濁醪自稱和山藥，小令新能坼水花。',32,'全唐诗/poet.song.96000.json','["濁醪自稱和山藥，小令新能坼水花。", "況有阿戎供細雨，豈知秋思滿天涯。"]'),
('f362c0c7-183b-4fc4-9da7-06bae8334ca9','過嘉禾野塘','沈與求','宋','宋诗','song-poetry','','[]','木末孤烟起夕炊，茅簷直下釣魚磯。',32,'全唐诗/poet.song.96000.json','["木末孤烟起夕炊，茅簷直下釣魚磯。", "蒼茫遠水連天碧，一葉短篷何處歸。"]'),
('4bd75232-bc0f-4543-8af0-f01d819bcc27','僕夫自燕山來云有次律兄書被盜失去','沈與求','宋','宋诗','song-poetry','','[]','投曉平安使，倉皇扣倚廬。',48,'全唐诗/poet.song.96000.json','["投曉平安使，倉皇扣倚廬。", "修塗幸及此，細語問何如。", "云自三關道，曾持一紙書。", "崎嶇經寇難，隻影到鄉閭。"]'),
('4c7de022-5c4d-4302-b144-e74376ca556c','杜季習遊恒山謁府帥劉公輒次劉彦常韻作二詩送之  其一','沈與求','宋','宋诗','song-poetry','','[]','勇往都忘去路難，胸吞螭虎氣桓桓。',64,'全唐诗/poet.song.96000.json','["勇往都忘去路難，胸吞螭虎氣桓桓。", "吳頭楚尾三年夢，塞北江南五月寒。", "痩馬繫門留我別，明珠攜袖許誰看。", "書生自有西江量，何止能濡舌本乾。"]'),
('ded2a6e1-92b8-4789-9461-b073da46a2d8','杜季習遊恒山謁府帥劉公輒次劉彦常韻作二詩送之  其二','沈與求','宋','宋诗','song-poetry','','[]','上相平胡不作難，已開亭障徹烏桓。',64,'全唐诗/poet.song.96000.json','["上相平胡不作難，已開亭障徹烏桓。", "公朝問罪知誰敵，窮虜要盟故自寒。", "烽燧報安千徼肅，羽書飛捷萬人看。", "書生夢想從軍樂，雋語銘功墨未乾。"]'),
('18c6b41b-ef9f-4faa-8486-fcb2a49334f3','董深大有詩紀吳江豁然閣舊遊索僕繼和','沈與求','宋','宋诗','song-poetry','','[]','湖陰舊雨記重來，小閣深明傍水開。',64,'全唐诗/poet.song.96000.json','["湖陰舊雨記重來，小閣深明傍水開。", "螮蝀横空橋倒影，琉璃拍岸浪成堆。", "勝遊君復羹魚婢，幽屏予方飯芋魁。", "遙想經行斷堤曲，野花漂盡雪玫瑰。"]'),
('86cd07c4-6859-4f36-820e-69730368a3cf','次韻河陽張先父秀才','沈與求','宋','宋诗','song-poetry','','[]','雲疏日薄九秋深，故國懸知詠稾砧。',64,'全唐诗/poet.song.96000.json','["雲疏日薄九秋深，故國懸知詠稾砧。", "試拂青萍憐氣在，更攜綠綺覺塵侵。", "浮家泛宅三年夢，臨水登山萬里心。", "小騎羨君盤谷去，肯如思越費清吟。"]'),
('66b859a2-71d7-46c7-bb76-96f139867527','託長興吳宰僦居','沈與求','宋','宋诗','song-poetry','','[]','一區無地可經營，宦牒東西寄此行。',64,'全唐诗/poet.song.96000.json','["一區無地可經營，宦牒東西寄此行。", "問舍它時聊爾耳，浮家今日太勞生。", "肯將口腹累安邑，正欲絃歌聞武城。", "爲我三間卜茅屋，夜深來聽讀書聲。"]'),
('ff527b98-c946-4c75-8aba-6edc1c513f91','寄次律兄學士柯田山新居','沈與求','宋','宋诗','song-poetry','','[]','柯田一曲抱清灣，兩角孤雲擁髻鬟。',64,'全唐诗/poet.song.96000.json','["柯田一曲抱清灣，兩角孤雲擁髻鬟。", "猿鶴驚心招舊隱，桑麻掠眼接通闤。", "似聞小築終年就，應是幽扉盡日關。", "爲報添丁護鵶觜，夜寒歸夢遶家山。"]'),
('83e2f0e6-69c2-4cc0-8357-acf3c71115f3','沈景修宗博示試院書事二章次其韻  其一','沈與求','宋','宋诗','song-poetry','','[]','巖谷何人歎久幽，紵袍一一赴兼收。',64,'全唐诗/poet.song.96000.json','["巖谷何人歎久幽，紵袍一一赴兼收。", "銜枚盡欲成堅敵，懷璧渾疑忌暗投。", "獨訝終篇惜鷄肋，更須添燭校蠅頭。", "文章到此無殊律，共賦菁莪汎汎舟。"]'),
('6dd31f03-91c6-4a1c-8a59-7f560c5d4059','沈景修宗博示試院書事二章次其韻  其二','沈與求','宋','宋诗','song-poetry','','[]','探簾山鳥一聲幽，斗覺晴光爛不收。',64,'全唐诗/poet.song.96000.json','["探簾山鳥一聲幽，斗覺晴光爛不收。", "好夢已尋江上去，清篇更許坐中投。", "欣逢阮籍開青眼，肯學虞卿賦白頭。", "聞道月波春色滿，好攜行客住行舟。"]'),
('5c6709a7-32ef-43c9-9d07-903d82311d81','次韻院中四絕句  其一','沈與求','宋','宋诗','song-poetry','','[]','行盡江山不記村，卻隨花信到重門。',32,'全唐诗/poet.song.96000.json','["行盡江山不記村，卻隨花信到重門。", "也知春色嬌無賴，取次先來綠草根。"]'),
('4a8faa19-c263-4b72-997e-99af20e5bf79','次韻院中四絕句  其二','沈與求','宋','宋诗','song-poetry','','[]','一尊相屬語黄昏，密雪飄零正滿門。',32,'全唐诗/poet.song.96000.json','["一尊相屬語黄昏，密雪飄零正滿門。", "記得江橋回馬處，冷香應斷玉梅魂。"]'),
('9898a0e3-5b43-4b52-b860-38894f8c3b74','次韻院中四絕句  其三','沈與求','宋','宋诗','song-poetry','','[]','要知春色到池塘，深院無人午夢長。',32,'全唐诗/poet.song.96000.json','["要知春色到池塘，深院無人午夢長。", "已覺此身便静樂，自温檀火炷爐香。"]'),
('538229b7-91c5-44d5-b9f9-269fd1a31bc4','次韻院中四絕句  其四','沈與求','宋','宋诗','song-poetry','','[]','荳蔻梢頭春意濃，輕狂無奈賺花風。',32,'全唐诗/poet.song.96000.json','["荳蔻梢頭春意濃，輕狂無奈賺花風。", "今年拚卻尋芳晚，凖擬殘枝占晚紅。"]'),
('6bc0a503-ea14-4949-a71a-13c00ee353cd','石壁寺山房即事  其一','沈與求','宋','宋诗','song-poetry','','[]','雲根斸翠接山椒，小築初營一束茅。',32,'全唐诗/poet.song.96000.json','["雲根斸翠接山椒，小築初營一束茅。", "未放野泉縈曲磵，旋移寒綠引春梢。"]'),
('f20451bb-cd92-41ca-be23-cb734ef0bac3','石壁寺山房即事  其二','沈與求','宋','宋诗','song-poetry','','[]','望斷南崗遠水通，客檣來往酒旗風。',32,'全唐诗/poet.song.96000.json','["望斷南崗遠水通，客檣來往酒旗風。", "畫橋依約垂楊外，映带殘霞一抹紅。"]'),
('65318235-69c7-4814-838f-e61b5328d19f','石壁寺','沈與求','宋','宋诗','song-poetry','','[]','山縈細路走修蛇，峭壁連雲只蘚花。',64,'全唐诗/poet.song.96000.json','["山縈細路走修蛇，峭壁連雲只蘚花。", "木末忽看幡影亂，馬頭初見殿陰斜。", "迴廊迤迤穿危嶠，側澗娟娟露淺沙。", "秀色可餐吾事辦，粥魚茶板莫相誇。"]'),
('41914bba-c6e6-409d-9827-6e7d1c6c562f','無言頒政以詩寄行簡輒次韻  其一','沈與求','宋','宋诗','song-poetry','','[]','鑴磨文律似攻駒，十載相從亦數予。',64,'全唐诗/poet.song.96000.json','["鑴磨文律似攻駒，十載相從亦數予。", "卷白欲傾東海酒，閉門貪鈔北堂書。", "風烟入眼山圍座，鷗鷺驚心水滿渠。", "此樂定非公所有，爲聞鼇禁席頻虛。"]'),
('9ded3f5e-64f8-41a1-a47f-9c1fda17c316','無言頒政以詩寄行簡輒次韻  其二','沈與求','宋','宋诗','song-poetry','','[]','平生狗曲視驪駒，妙語琅琅獨起予。',64,'全唐诗/poet.song.96000.json','["平生狗曲視驪駒，妙語琅琅獨起予。", "酒面那能伴從事，筆頭翻欲戲中書。", "官曹似是驚蓮幕，問訊何如念石渠。", "只恐浮名不論數，要須人識士非虛。"]'),
('709f1be9-1ea1-4a04-9c0b-56c475bf19d3','行簡用前韻見貽復和酬之','沈與求','宋','宋诗','song-poetry','','[]','歲月如馳鬬隙駒，星星著鬢故欺予。',64,'全唐诗/poet.song.96000.json','["歲月如馳鬬隙駒，星星著鬢故欺予。", "身宜丘壑長經夢，語到軒裳輒廢書。", "扃步共嗟妨遠趾，清溝自覺映汙渠。", "黄麻白簡公心事，此去聲名定不虛。"]'),
('1619af68-b07a-4d9b-bae1-5de42b92e37a','過卞山次韻朱仰止澗亭絕句  其一','沈與求','宋','宋诗','song-poetry','','[]','曲澗潺潺隱石堤，玉虯雙引戲晴漪。',32,'全唐诗/poet.song.96000.json','["曲澗潺潺隱石堤，玉虯雙引戲晴漪。", "相思後夜添清絕，木落山空月半規。"]'),
('64eab6ce-c864-4440-8606-b9ddb255870d','過卞山次韻朱仰止澗亭絕句  其二','沈與求','宋','宋诗','song-poetry','','[]','環珮琮琤落斷崖，水清石痩没平沙。',32,'全唐诗/poet.song.96000.json','["環珮琮琤落斷崖，水清石痩没平沙。", "幽人散策經過地，草閣柴扉趁水斜。"]'),
('18ce764b-9762-4f10-9c0c-0927c03af843','昔年','沈與求','宋','宋诗','song-poetry','','[]','昔年尋賀老，同泛越溪航。',48,'全唐诗/poet.song.96000.json','["昔年尋賀老，同泛越溪航。", "雨發千巖秀，風供五月涼。", "目因秦望斷，心爲禹祠傷。", "聞道東湖地，新來足稻粱。"]'),
('3c28b25a-56e6-4208-bbca-283f69b04bbc','秋懷二首  其一','沈與求','宋','宋诗','song-poetry','','[]','庭柯脱翳葉，歸翼斷經過。',48,'全唐诗/poet.song.96000.json','["庭柯脱翳葉，歸翼斷經過。", "水檻清漁罟，風櫺響藥羅。", "傲霜荷柄少，團露橘叢多。", "秋色遂如此，愁成今幾何。"]'),
('2f2188f3-abab-4651-bba6-73b2751ed57a','秋懷二首  其二','沈與求','宋','宋诗','song-poetry','','[]','林梢吐寒月，清絕不勝任。',48,'全唐诗/poet.song.96000.json','["林梢吐寒月，清絕不勝任。", "蠻榼憑誰共，胡笳秖自吟。", "探簾風似翦，切戶斗如斟。", "何處行舟動，澄波自委金。"]'),
('41661d6d-1ecb-4965-a54a-5fbdcc2b0952','即事','沈與求','宋','宋诗','song-poetry','','[]','夘酒賸澆胸礧磈，晨梳聊理髪鬅鬙。',32,'全唐诗/poet.song.96000.json','["夘酒賸澆胸礧磈，晨梳聊理髪鬅鬙。", "方床自岸烏巾坐，欲校黄庭嬾未能。"]'),
('ec332a03-dbf6-440c-9037-3ab46f716b5d','秋日閑居','沈與求','宋','宋诗','song-poetry','','[]','茅屋秋風斗破除，蕭騷渾似浣溪居。',64,'全唐诗/poet.song.96000.json','["茅屋秋風斗破除，蕭騷渾似浣溪居。", "青山侍坐從吾好，黄帽籠頭與俗疏。", "賴有園官能送菜，可無溪友解留魚。", "從今輒莫慚枵腹，一飽須煩插架書。"]'),
('c3cbcddf-59db-4f3a-968a-3ccc62bd7be5','送盧左司赴闕舟中口占','沈與求','宋','宋诗','song-poetry','','[]','胸中渺渺九夢澤，筆底滔滔三峽流。',64,'全唐诗/poet.song.96000.json','["胸中渺渺九夢澤，筆底滔滔三峽流。", "自合勳盟真易與，漫回詩律付冥捜。", "平生所慕李君御，今日聊登郭泰舟。", "去矣相望重搔首，百年心事小遲留。"]'),
('f92dde03-f315-4984-a502-c69ff0189fd3','野外罕人事','沈與求','宋','宋诗','song-poetry','','[]','野外罕人事，雖貧心自寛。',48,'全唐诗/poet.song.96000.json','["野外罕人事，雖貧心自寛。", "霜蔬供綠節，社酒泛黄團。", "日落歸牛近，風微宿鳥安。", "展書遮老眼，燈火砌儒酸。"]'),
('14c3fba0-6e98-4efb-a300-630f6e55ed92','過竹西','沈與求','宋','宋诗','song-poetry','','[]','百折清灣抱野田，竹西風物故依然。',32,'全唐诗/poet.song.96000.json','["百折清灣抱野田，竹西風物故依然。", "歸牛更背斜陽去，牧笛一聲吹暮天。"]'),
('28c011d0-de4e-4218-a5cf-b295638a4919','贈老禪','沈與求','宋','宋诗','song-poetry','','[]','霜根刺刺蝟圓顱，猶倚禪床聽木魚。',64,'全唐诗/poet.song.96000.json','["霜根刺刺蝟圓顱，猶倚禪床聽木魚。", "底事世緣能老我，到頭塵事不關渠。", "磨甎幾日能成鍳，閉戶何人欲造車。", "若有小參重問訊，試尋消息向真如。"]'),
('0d3be207-b34a-4f66-9482-de716354c3fe','成士瑴校登真訣垂就爲作此詩問訊','沈與求','宋','宋诗','song-poetry','','[]','硬黄親校大還書，巖石相看已甚臞。',64,'全唐诗/poet.song.96000.json','["硬黄親校大還書，巖石相看已甚臞。", "會遣五丁供給使，聊煩六甲奉庖厨。", "仙風自昔人何有，靈氣於今子豈無。", "知得茅卿近消息，應驂白鵠到清都。"]'),
('8cfb9f72-0257-4497-b750-495c44abbb51','謝葛魯卿雪中遣介送酒','沈與求','宋','宋诗','song-poetry','','[]','雪舞白衣朝扣門，一車送酒借春温。',64,'全唐诗/poet.song.96000.json','["雪舞白衣朝扣門，一車送酒借春温。", "寒威任減東陽带，和氣全歸北海尊。", "應爲半生憐麴糵，更留它日燕鷄豚。", "是中可飲公須記，報字如鴉醉眼昏。"]'),
('b0ada9db-a04a-4d8f-9890-69ee1fcbf360','正月十四夜觀燈南寺子虛有詩次其韻兼呈駿發次顔','沈與求','宋','宋诗','song-poetry','','[]','娟娟佳月掛南樓，蕭寺真成秉燭遊。',64,'全唐诗/poet.song.96000.json','["娟娟佳月掛南樓，蕭寺真成秉燭遊。", "火樹忽驚新節物，春衫不趁舊風流。", "公方高卧追三已，我亦狂歌發四愁。", "爲報襟期得名勝，何妨著處一開眸。"]'),
('3f1e7b26-a9c1-430e-83d4-fb9669e7741d','再用子虛韻和呈駿發次顔  其一','沈與求','宋','宋诗','song-poetry','','[]','燈市燒春接郡樓，歲豐人樂事遨遊。',64,'全唐诗/poet.song.96000.json','["燈市燒春接郡樓，歲豐人樂事遨遊。", "繁絃急管方連夕，痛飲高談自一流。", "短帽縱堪陪勝賞，長檠那解照牢愁。", "歸來卧對西窗月，獨想清光燭電眸。"]'),
('f1879b18-22f1-4517-bbb1-02a2a9f9cae7','再用子虛韻和呈駿發次顔  其二','沈與求','宋','宋诗','song-poetry','','[]','十里笙簫沸市樓，已占風物兩優游。',64,'全唐诗/poet.song.96000.json','["十里笙簫沸市樓，已占風物兩優游。", "人從月窟開青嶂，燈挾星河映碧流。", "曲席深杯成徑醉，長廊古寺溢清愁。", "暗中我亦知公在，彊對蘭膏爲舉眸。"]'),
('2b7e660e-ebd0-4b14-a564-ad3e01474308','子虛復有詩再次其韻','沈與求','宋','宋诗','song-poetry','','[]','誰能延月倚危樓，細履相將偶當游。',64,'全唐诗/poet.song.96000.json','["誰能延月倚危樓，細履相將偶當游。", "倦聽山歌懷舊俗，閑看水戲濺寒流。", "燈光競作千門曉，酒力微寛一掬愁。", "明日八分疲阿買，詩饞元只在清眸。"]'),
('041341aa-09ca-48f3-a489-fb5b8d802565','次夕雨作用子虛韻奉懷次顔知魚軒小集','沈與求','宋','宋诗','song-poetry','','[]','夾道繒山聳蜃樓，小軒終憶數條游。',64,'全唐诗/poet.song.96000.json','["夾道繒山聳蜃樓，小軒終憶數條游。", "月將人意十分滿，雨入溪光一派流。", "静聽屐聲喧夜市，旋挑燈灺醖春愁。", "閉關不問陰晴事，時怪玄花掠病眸。"]'),
('3b714f49-bb95-4993-a0e8-cbc8d97b147e','別群從','沈與求','宋','宋诗','song-poetry','','[]','十年勞遠夢，今日又征鞍。',48,'全唐诗/poet.song.96000.json','["十年勞遠夢，今日又征鞍。", "雨入花梢困，風生麥浪寒。", "飄零逢酒怯，老大別家難。", "去矣功名事，終須把鏡看。"]'),
('c3bab17c-1432-4a0c-95d9-b94578b513e0','瓜步','沈與求','宋','宋诗','song-poetry','','[]','呼聲漸逐潮頭遠，帆影低隨日腳斜。',32,'全唐诗/poet.song.96000.json','["呼聲漸逐潮頭遠，帆影低隨日腳斜。", "已喜扁舟近瓜步，江鷗無數立寒沙。"]'),
('63c28a74-d87c-4580-b19c-023f87192807','將達行在所','沈與求','宋','宋诗','song-poetry','','[]','潮落江城暮，帆開一葦輕。',48,'全唐诗/poet.song.96000.json','["潮落江城暮，帆開一葦輕。", "雲屯六龍駐，天近五星明。", "率土朝方岳，何年洗甲兵。", "君王似光武，折箠看昇平。"]'),
('e0efb04b-49da-4cd1-90b5-b984c81fcb92','陳子尚博士休官還京口作此詩餞之  其一','沈與求','宋','宋诗','song-poetry','','[]','勇退曾無屋數椽，掛冠神武便飄然。',64,'全唐诗/poet.song.96000.json','["勇退曾無屋數椽，掛冠神武便飄然。", "陶潛去家一百里，張翰收名四十年。", "平世深知還有幾，少時健決已無前。", "侏儒飽食堪羞死，莫浪狂言爲著鞭。"]'),
('7ad295a1-63ec-4167-a6b4-6bc2b178830e','陳子尚博士休官還京口作此詩餞之  其二','沈與求','宋','宋诗','song-poetry','','[]','西風江上荻花秋，鱠玉頻年念昔逰。',64,'全唐诗/poet.song.96000.json','["西風江上荻花秋，鱠玉頻年念昔逰。", "世事真成一可慟，身名那問二宜休。", "公卿禮餞何爲者，僮僕歡迎有此不。", "鬢影毿毿紛翠葆，晚來鐘漏亦懷羞。"]'),
('0ccde152-d847-40f1-9192-96dd26bc4c35','得家書','沈與求','宋','宋诗','song-poetry','','[]','國步猶艱棘，不堪頻問家。',48,'全唐诗/poet.song.96000.json','["國步猶艱棘，不堪頻問家。", "霜毛失翠葆，蒿目亂玄花。", "孤客知時節，殊方度歲華。", "干戈就休息，歸理邵平瓜。"]'),
('4cbab414-f2f6-4252-bc03-dbd20f97f22a','觀瓊花','沈與求','宋','宋诗','song-poetry','','[]','千里隨河走濁流，檣烏東下指迷樓。',32,'全唐诗/poet.song.96000.json','["千里隨河走濁流，檣烏東下指迷樓。", "春風簾幕今何在，只有瓊花伴客愁。"]'),
('818e205f-bf17-468e-a03f-b2636067b1af','即事和卓彦翼','沈與求','宋','宋诗','song-poetry','','[]','曈曨曉日上簾旌，簾外幽禽作意鳴。',32,'全唐诗/poet.song.96000.json','["曈曨曉日上簾旌，簾外幽禽作意鳴。", "呼斷故鄉千里夢，起來搔首問歸程。"]'),
('ec821d9a-62c2-44db-bf67-531587205822','即事','沈與求','宋','宋诗','song-poetry','','[]','造物勞人亦懵哉，又驅疲馬上崔嵬。',64,'全唐诗/poet.song.96000.json','["造物勞人亦懵哉，又驅疲馬上崔嵬。", "經從野店初嘗筍，行盡江村始見梅。", "千里短書先夢寐，半生多難足風埃。", "桔橰俯仰成何事，已念漁蓑歸去來。"]'),
('2dbe0725-ce78-4bd0-804f-4a539911d69a','次桐廬  其一','沈與求','宋','宋诗','song-poetry','','[]','決決溪流不滿灘，獨憐舟子上風灣。',32,'全唐诗/poet.song.96000.json','["決決溪流不滿灘，獨憐舟子上風灣。", "日斜指點西村渡，竹戶茅牆趁碧山。"]'),
('142065b9-15e0-4d0b-8cc4-7d8f9bd96eec','次桐廬  其二','沈與求','宋','宋诗','song-poetry','','[]','吏鞅縈人未許閑，當游聊復到春山。',32,'全唐诗/poet.song.96000.json','["吏鞅縈人未許閑，當游聊復到春山。", "倡條冶葉無風味，賴有寒梅醒病顔。"]'),
('6a78b0ba-947c-47af-9029-261ef43735a8','於潛道中','沈與求','宋','宋诗','song-poetry','','[]','首路潛溪驛，鷄聲欲曙天。',48,'全唐诗/poet.song.96000.json','["首路潛溪驛，鷄聲欲曙天。", "籃輿衝宿霧，棧閣寄層巔。", "高下林端屋，横斜石罅田。", "野泉隨處有，草木盡蒼然。"]'),
('51255730-5dbf-457b-9d2f-aedfc75c2d26','新城道中','沈與求','宋','宋诗','song-poetry','','[]','馬蹄隨意到，回首隔南崗。',48,'全唐诗/poet.song.96000.json','["馬蹄隨意到，回首隔南崗。", "日落鳥猶語，春歸花自香。", "長紅媚幽谷，新綠漲回塘。", "假榻知何地，昏鐘出上方。"]'),
('519e4718-33d5-4d3b-9488-2e5639649fc3','宿葉璋橋庵舍','沈與求','宋','宋诗','song-poetry','','[]','渡澗穿林夕未休，野人篝火引前騶。',64,'全唐诗/poet.song.96000.json','["渡澗穿林夕未休，野人篝火引前騶。", "驚從略彴灘聲急，喜見廜㢝草蓋修。", "雲臥自驚魂夢冷，星馳先惱肺肝愁。", "乞身老我雙溪上，記取端能賦遠遊。"]'),
('6420dbf2-5b96-41f5-b5cf-d674f130e02c','水閣小憩','沈與求','宋','宋诗','song-poetry','','[]','雲氣昏昏雨腳垂，客行終日倦奔馳。',32,'全唐诗/poet.song.96000.json','["雲氣昏昏雨腳垂，客行終日倦奔馳。", "竹間小閣臨清瀨，俯檻觀魚立許時。"]'),
('f0fc8959-ca74-4edb-908d-9bcf126358c2','祁門道中遇雨','沈與求','宋','宋诗','song-poetry','','[]','了事癡人有底忙，箯輿勃窣到南岡。',64,'全唐诗/poet.song.96000.json','["了事癡人有底忙，箯輿勃窣到南岡。", "樵風槭槭群狙喜，山雨蕭蕭萬木僵。", "谷底暗分冰澗落，舍旁時度野梅香。", "殊方歲晚多悲感，歸老丘園此計長。"]'),
('2e719526-9da7-46e4-978b-beed3fba0622','東西二林寺  其一','沈與求','宋','宋诗','song-poetry','','[]','湓浦維舟訪梵宫，香爐峰下暫從容。',32,'全唐诗/poet.song.96000.json','["湓浦維舟訪梵宫，香爐峰下暫從容。", "重來不爲二林景，永遠禪師有舊蹤。"]'),
('352f2c14-dc1a-4fa9-a552-a83c7e3baa46','東西二林寺  其二','沈與求','宋','宋诗','song-poetry','','[]','在昔得名齊，連牆亦共蹊。',48,'全唐诗/poet.song.96000.json','["在昔得名齊，連牆亦共蹊。", "修篁同碧嶂，寒溜合清溪。", "閣影高低並，鐘聲左右迷。", "遊人俄省悟，東即是林西。"]'),
('4ecf497c-588e-4659-871c-505372a56359','東西二林寺  其三','沈與求','宋','宋诗','song-poetry','','[]','遊人多入東林寺，將謂西林景不如。',32,'全唐诗/poet.song.96000.json','["遊人多入東林寺，將謂西林景不如。", "我策短笻行半日，水聲松韻更清虛。"]'),
('b81528e8-86d6-4701-a620-43f13476e594','千秋嶺  其一','沈與求','宋','宋诗','song-poetry','','[]','山河四塞限中原，籬落而今不復存。',32,'全唐诗/poet.song.96000.json','["山河四塞限中原，籬落而今不復存。", "豺虎晝行何日息，但餘征戍滿荒村。"]'),
('4190f487-abe2-4f97-b13e-cb0ef6105013','千秋嶺  其二','沈與求','宋','宋诗','song-poetry','','[]','吳越江南絕壁間，可憐争國似蝸蠻。',32,'全唐诗/poet.song.96000.json','["吳越江南絕壁間，可憐争國似蝸蠻。", "百年父老陶王化，尚記流傳一醉顔。"]'),
('156f3118-25ac-4ee2-90aa-d115cc9d1a25','次韻鄭維心臘月十六日有作  其一','沈與求','宋','宋诗','song-poetry','','[]','國難更頻歲，邉塵動四溟。',48,'全唐诗/poet.song.96000.json','["國難更頻歲，邉塵動四溟。", "豺狼飽吞噬，天地失清寜。", "黄屋無安所，霜笳不忍聽。", "使臣歸路阻，慟絕鬢星星。"]'),
('1b9158ca-5e99-4413-99fa-3ad71c0aa2bf','次韻鄭維心臘月十六日有作  其二','沈與求','宋','宋诗','song-poetry','','[]','朝廷歸叛將，關塞失簽軍。',48,'全唐诗/poet.song.96000.json','["朝廷歸叛將，關塞失簽軍。", "銅馬猶逋命，沙蟲亦占群。", "上心存廟略，兵氣亂天文。", "誰挽斜河水，通宵洗赤氛。"]'),
('cb7cceb6-6c08-44c1-8087-4683c1c4a9a8','次韻鄭維心臘月十六日有作  其三','沈與求','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','血戰遮東道，今誰廟食雙。',48,'全唐诗/poet.song.96000.json','["血戰遮東道，今誰廟食雙。", "無人扞彊敵，縱馬飲長江。", "寇掠元干紀，兵臨反誘降。", "將軍自不武，慚色上旌幢。"]'),
('0159abdf-0b55-4934-ac9f-e5efdacca764','次韻避寇二首  其一','沈與求','宋','宋诗','song-poetry','','[]','窮途厭遷次，歲晚惜分攜。',48,'全唐诗/poet.song.96000.json','["窮途厭遷次，歲晚惜分攜。", "茅舍荒村北，柴門曲港西。", "鷄豚蹔同社，桃李舊成蹊。", "那得干戈定，浮家著兩溪。"]'),
('b4dc72b3-dc8b-49a2-ae38-e1336ccc4692','次韻避寇二首  其二','沈與求','宋','宋诗','song-poetry','','[]','宦遊成屢卻，戎壘悵頻遭。',48,'全唐诗/poet.song.96000.json','["宦遊成屢卻，戎壘悵頻遭。", "聞詔趨吳會，經途事董逃。", "心期紓國難，力欲挽人豪。", "漂泊多危涕，真成失木猱。"]'),
('03c12a39-8509-4784-894d-a56d0aaedb36','游城山夜歸泛舟南溪','沈與求','宋','宋诗','song-poetry','','[]','杖藜尋勝款禪扃，歸去扁舟伴月明。',64,'全唐诗/poet.song.96000.json','["杖藜尋勝款禪扃，歸去扁舟伴月明。", "卧樹低摧山腳轉，跳魚撥刺艣牙驚。", "烟埋橋影雙霓斷，風熨溪光一鏡平。", "聚落半空無市井，在亡燈火短長更。"]'),
('658d2b10-31cc-4f56-a4a4-7abd5c2398f7','次韻李通直題慈相寺雪月亭','沈與求','宋','宋诗','song-poetry','','[]','曲檻飛甍界碧空，盡供勝覧屬禪翁。',64,'全唐诗/poet.song.96000.json','["曲檻飛甍界碧空，盡供勝覧屬禪翁。", "蒼藤翠木四圍外，遠水平蕪一望中。", "幽鳥林梢鳴不斷，亂雲天末去無窮。", "素娥青女今何在，歸步聊乘兩腋風。"]'),
('8d6dd2c2-c516-43e2-8ed9-83fee7b864ee','扈御舟泊錢清江口值雨  其一','沈與求','宋','宋诗','song-poetry','','[]','打窗悉窣連江雨，吹柁嘔啞拍岸風。',32,'全唐诗/poet.song.96000.json','["打窗悉窣連江雨，吹柁嘔啞拍岸風。", "篷底醉眼那得隱，時聞鷄唱夢魂中。"]'),
('e2c19f62-bafc-489f-ba64-0ec555424692','扈御舟泊錢清江口值雨  其二','沈與求','宋','宋诗','song-poetry','','[]','法駕親巡海上還，鈎陳萬騎列江干。',32,'全唐诗/poet.song.96000.json','["法駕親巡海上還，鈎陳萬騎列江干。", "潮生風熟樓船過，雨助洪濤失故灘。"]'),
('e8dd1aaf-5216-4e5b-b42f-dd30b7424c87','過平望','沈與求','宋','宋诗','song-poetry','','[]','未辦扁舟掛綠蓑，人間何處不風波。',32,'全唐诗/poet.song.96000.json','["未辦扁舟掛綠蓑，人間何處不風波。", "終須徑爲鱸魚去，笠釣歸尋張志和。"]'),
('6dbda98f-c6c4-493e-bec1-cf55ce2b412e','次吳江  其一','沈與求','宋','宋诗','song-poetry','','[]','水闊風豪浪拍天，魚龍戲舞墮饞涎。',32,'全唐诗/poet.song.96000.json','["水闊風豪浪拍天，魚龍戲舞墮饞涎。", "尋常行處多翻覆，看我孤舟得隱眠。"]'),
('aa441622-1338-4630-9bd9-9eb67706b3d2','次吳江  其二','沈與求','宋','宋诗','song-poetry','','[]','小邑蕭條兵火餘，狐狸入市自相呼。',32,'全唐诗/poet.song.96000.json','["小邑蕭條兵火餘，狐狸入市自相呼。", "茅牆竹戶斜陽裏，十室生涯久已無。"]'),
('10c6e63d-f62e-4fae-b753-70ee494b368e','冬至遇雪題明因寺僧房  其一','沈與求','宋','宋诗','song-poetry','','[]','宦學差池已倦游，一犁真欲老西疇。',32,'全唐诗/poet.song.96000.json','["宦學差池已倦游，一犁真欲老西疇。", "天公爲作豐年信，更喜將軍入蔡州。"]'),
('09fa9205-7777-4c31-9fc2-640460fe85f0','冬至遇雪題明因寺僧房  其二','沈與求','宋','宋诗','song-poetry','','[]','遙想燕山落大花，更堪直北渡龍沙。',32,'全唐诗/poet.song.96000.json','["遙想燕山落大花，更堪直北渡龍沙。", "六師挾纊懷輕煖，取日誰能反翠華。"]'),
('a87ff2a8-8508-4fd0-ba91-4b8097637f8c','方允迪隱鸕鶿谷江子我子之劉希顔行簡皆往依焉爲此詩寄贈','沈與求','宋','宋诗','song-poetry','','[]','脱葉驚飛海角秋，君王虛佇急良籌。',64,'全唐诗/poet.song.96000.json','["脱葉驚飛海角秋，君王虛佇急良籌。", "列仙山澤底無用，孺子滄浪渠不憂。", "百鷙可能如一鶚，二江知復带雙流。", "渺然相望暮雲碧，兀坐蒲團搔白頭。"]'),
('84e0cfbe-645b-43b4-92dc-9660ee61896c','八月十七日扁舟渡錢塘江  其一','沈與求','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','一言初欲寤明君，去矣終緣丞相嗔。',64,'全唐诗/poet.song.96000.json','["一言初欲寤明君，去矣終緣丞相嗔。", "鳬雁江湖真我輩，龍蛇山澤定何人。", "市中未識馮延壽，門外已呼祁孔賓。", "尚有憂時心未歇，西風吹淚濕綸巾。"]'),
('1e32e0d5-6c2b-4e64-ac27-e60b2afb5044','八月十七日扁舟渡錢塘江  其二','沈與求','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','沙觜波生柁腳開，扁舟老去許歸來。',64,'全唐诗/poet.song.96000.json','["沙觜波生柁腳開，扁舟老去許歸來。", "風帆一點日邊下，雪浪千堆天際迴。", "城郭荒蕪迷舊隱，江山寂寞寫餘哀。", "此心元自無機事，寄語輕鷗莫見猜。"]'),
('2c5214c1-393d-4dbf-89d3-436b1695c1db','允迪招行簡卜居鸕鶿谷僕意羨之作詩送行兼以自見  其一','沈與求','宋','宋诗','song-poetry','','[]','嚴陵灘下鸕鶿谷，聞道元英舊隱廬。',64,'全唐诗/poet.song.96000.json','["嚴陵灘下鸕鶿谷，聞道元英舊隱廬。", "鼻祖名高詩格在，耳孫才傑宦情疏。", "漫山松桂雁行立，入隖茅茨星散居。", "知爲劉郎賦招隱，莫教花落到通渠。"]'),
('78534374-002d-4382-93fb-cf4782ae4a79','允迪招行簡卜居鸕鶿谷僕意羨之作詩送行兼以自見  其二','沈與求','宋','宋诗','song-poetry','','[]','少日長懷社稷憂，怪來饒舌漫多仇。',64,'全唐诗/poet.song.96000.json','["少日長懷社稷憂，怪來饒舌漫多仇。", "風塵冉冉百年老，霜雪蕭蕭兩鬢秋。", "不辦癡床供一笑，方營隱谷賦三休。", "添丁護得金鴉觜，佳處端能著我不。"]'),
('d8d21596-4f6f-4200-b88e-0657afbcfff5','維心過邵子非溪亭夜話有傷時感舊之作索余次韻  其一','沈與求','宋','宋诗','song-poetry','','[]','官儀全復漢，盟會競尊周。',48,'全唐诗/poet.song.96000.json','["官儀全復漢，盟會競尊周。", "郊野多戎壘，衣冠半客游。", "地偏朋舊鮮，人老歲時遒。", "莫厭經過數，相看又麥秋。"]'),
('c56a0b08-7acc-4573-86da-1900ca84a28d','維心過邵子非溪亭夜話有傷時感舊之作索余次韻  其二','沈與求','宋','宋诗','song-poetry','','[]','朝廷策數馬，寇盜谷量牛。',48,'全唐诗/poet.song.96000.json','["朝廷策數馬，寇盜谷量牛。", "世亂思奇畫，身閑喜勝流。", "鵷鸞霄漢侶，鳬雁稻粱謀。", "得趣皆爲達，那能陸盪舟。"]'),
('ba81d809-88f0-466f-a80d-e834836600b8','維心過邵子非溪亭夜話有傷時感舊之作索余次韻  其三','沈與求','宋','宋诗','song-poetry','','[]','聞道津亭集，青燈夜色浮。',48,'全唐诗/poet.song.96000.json','["聞道津亭集，青燈夜色浮。", "鸛鳴驚獨鶴，魚伏避群鶖。", "月澹帆歸浦，風腥網挂洲。", "語深投匕立，此意得無憂。"]'),
('a04ca26b-26a0-47ff-9ab6-9c9098f4df5f','維心過邵子非溪亭夜話有傷時感舊之作索余次韻  其四','沈與求','宋','宋诗','song-poetry','','[]','虜帳師頻衂，民窮粟屢捜。',48,'全唐诗/poet.song.96000.json','["虜帳師頻衂，民窮粟屢捜。", "會須夷喪亂，寧敢厭征求。", "黄屋中天立，彤弓幾日酬。", "寸心終耿耿，不獨爲春愁。"]'),
('c03f73b3-72db-46d1-918a-fa7e5f9d9151','維心過邵子非溪亭夜話有傷時感舊之作索余次韻  其五','沈與求','宋','宋诗','song-poetry','','[]','心事空牢落，身名盍罷休。',48,'全唐诗/poet.song.96000.json','["心事空牢落，身名盍罷休。", "得閑羞彊聒，避謗巧淹留。", "老矣嗟如此，誰歟問以不。", "儻容親杖履，不擬向丹丘。"]'),
('8bef108d-ab2e-4eec-bcde-d7a62b74dc96','劉希顔持節按縣招維心舟中小酌次維心韻  其一','沈與求','宋','宋诗','song-poetry','','[]','大艑浮溪曲，華旌暎道周。',48,'全唐诗/poet.song.96000.json','["大艑浮溪曲，華旌暎道周。", "勞農纔徹警，問俗偶成游。", "王事今云棘，官稱古號遒。", "正須哀疾苦，輒莫詫防秋。"]'),
('c2b0569c-82a9-4747-985d-9d56f1d4738a','劉希顔持節按縣招維心舟中小酌次維心韻  其二','沈與求','宋','宋诗','song-poetry','','[]','隨處喧銅馬，何人炫木牛。',48,'全唐诗/poet.song.96000.json','["隨處喧銅馬，何人炫木牛。", "輕捐小山句，急捍大江流。", "行邁心疑醉，周爰事喜謀。", "招呼隱君子，高浪兀虛舟。"]'),
('67588121-3cda-49eb-bce2-663f179f2449','劉希顔持節按縣招維心舟中小酌次維心韻  其三','沈與求','宋','宋诗','song-poetry','','[]','故國真如寄，餘生宛若浮。',48,'全唐诗/poet.song.96000.json','["故國真如寄，餘生宛若浮。", "巢鳩不護鵲，池鳳肯容鶖。", "老木低春水，孤花带晚洲。", "杯行應酹我，知復念幽憂。"]'),
('603a29ee-71bf-4179-9220-259ef73836d0','劉希顔持節按縣招維心舟中小酌次維心韻  其四','沈與求','宋','宋诗','song-poetry','','[]','山林懷獨往，圖史縱旁捜。',48,'全唐诗/poet.song.96000.json','["山林懷獨往，圖史縱旁捜。", "此士俗間忌，吾儕句裏求。", "大篇終寡和，小酌漫相酬。", "腳踏溪流亂，端能醒客愁。"]'),
('f7e1e3f8-0350-4e0a-9063-c914980c95f8','劉希顔持節按縣招維心舟中小酌次維心韻  其五','沈與求','宋','宋诗','song-poetry','','[]','大邦通間道，小縣得中休。',48,'全唐诗/poet.song.96000.json','["大邦通間道，小縣得中休。", "交分傷離合，王程惜去留。", "索居垂老矣，劇飲尚能不。", "倦夜評今古，誰憐貉一丘。"]'),
('41d0c709-0d3c-4b3a-bdab-f07c0c59da26','子虛航重湖之險遠過山中輒次維心韻以謝  其一','沈與求','宋','宋诗','song-poetry','','[]','客裏傷爲別，相望歲一周。',48,'全唐诗/poet.song.96000.json','["客裏傷爲別，相望歲一周。", "冕旒存異顧，丘壑老英游。", "憂國心長折，驚人語太遒。", "年來有公事，合眼注春秋。"]'),
('92eeb9e4-fb07-4a02-bd79-6a6dadfdd6af','子虛航重湖之險遠過山中輒次維心韻以謝  其二','沈與求','宋','宋诗','song-poetry','','[]','小窗眼蠍虎，敗壁上蝸牛。',48,'全唐诗/poet.song.96000.json','["小窗眼蠍虎，敗壁上蝸牛。", "老樹陰垂合，前山翠欲流。", "狂言違世用，彊飯了身謀。", "不謂輕千里，能迂訪戴舟。"]'),
('135f3de6-60a3-4700-ab3b-e86a28471f8e','子虛航重湖之險遠過山中輒次維心韻以謝  其三','沈與求','宋','宋诗','song-poetry','','[]','此客今那有，迎門喜氣浮。',48,'全唐诗/poet.song.96000.json','["此客今那有，迎門喜氣浮。", "心閑清似鵠，眼浄凛如鶖。", "塵榻開蓬室，風帆卷橘洲。", "襟期適相契，一笑發群憂。"]'),
('cfd79282-cde2-400e-b6e8-3e0e9a6fd758','子虛航重湖之險遠過山中輒次維心韻以謝  其四','沈與求','宋','宋诗','song-poetry','','[]','寶曆方重啟，英才必盡捜。',48,'全唐诗/poet.song.96000.json','["寶曆方重啟，英才必盡捜。", "題輿偶淹泊，牓道會營求。", "浪漫貧逾適，經綸老未酬。", "雲林得攜手，切勿志窮愁。"]'),
('500c2122-a094-413e-808d-d98afa9e00d8','子虛航重湖之險遠過山中輒次維心韻以謝  其五','沈與求','宋','宋诗','song-poetry','','[]','暮雲凝遠碧，覓句擬湯休。',48,'全唐诗/poet.song.96000.json','["暮雲凝遠碧，覓句擬湯休。", "不分千山隔，才爲十日留。", "高風誰繼者，清夢自驚不。", "聞說星躔動，何人識太丘。"]'),
('83d474ba-ea1b-4824-ad31-bd5bf9f9103b','次韻學士兄見一亭  其一','沈與求','宋','宋诗','song-poetry','','[]','自稱居士擬香山，隻影江湖得暫閑。',64,'全唐诗/poet.song.96000.json','["自稱居士擬香山，隻影江湖得暫閑。", "大隱可能追褦襶，小亭聊欲對孱顔。", "持盃有月同歌舞，策杖無人共往還。", "聞道修篁解新籜，密遮門逕不須刪。"]'),
('79bc9b9a-84b2-465d-b20a-b529bead4ebc','次韻學士兄見一亭  其二','沈與求','宋','宋诗','song-poetry','','[]','塵土敗名如敗敵，雲山招隱似招降。',64,'全唐诗/poet.song.96000.json','["塵土敗名如敗敵，雲山招隱似招降。", "漫傾魯酒醒猶獨，聊發吳謳調本雙。", "誰念佳人在空谷，自同漁父老清江。", "它年對榻分餘地，風雨蕭蕭夜打窗。"]'),
('1b0ec5f2-e464-405a-86d8-8af38cc5e2b0','次韻學士兄述懷  其一','沈與求','宋','宋诗','song-poetry','','[]','故國風烟素已諳，結茅端欲占重嵐。',64,'全唐诗/poet.song.96000.json','["故國風烟素已諳，結茅端欲占重嵐。", "聚蚊那肯追金谷，號虎真成賦石龕。", "阨運經過度陽九，幻生顛倒識朝三。", "它年自有鷄豚約，小阮新居卜道南。"]'),
('3f473d0a-82d3-4a45-8da7-6f4ef1a0e06c','次韻學士兄述懷  其二','沈與求','宋','宋诗','song-poetry','','[]','葱麥推還井大春，拂衣歸伴臥雲人。',64,'全唐诗/poet.song.96000.json','["葱麥推還井大春，拂衣歸伴臥雲人。", "胸中歷歷蟠三略，肘後時時校六淳。", "已作移文排俗士，更將要術混齊民。", "知閑聊復求閑地，歲晚功名恐逼身。"]'),
('531ce221-816a-4d70-90ce-305b04f0d139','次韻黄子虛所居隨緣堂','沈與求','宋','宋诗','song-poetry','','[]','應羨扁舟泛五湖，隨緣卜築伴樵蘇。',64,'全唐诗/poet.song.96000.json','["應羨扁舟泛五湖，隨緣卜築伴樵蘇。", "青山衮衮成嘉遯，華髪蕭蕭負壯圖。", "松檜鶱騰元自植，魚龍吟嘯巧相娱。", "清宵背立巖前月，大叫三高更疾呼。"]'),
('8324a5ce-d080-44cd-99a5-db14dcaa1893','次律兄餉魚魚不至而詩至頗類南海使君送酒輒成三絕一笑而已賜茗少分以報厚意  其一','沈與求','宋','宋诗','song-poetry','','[]','憑虛公子騎鯨後，烏有先生控鯉初。',32,'全唐诗/poet.song.96000.json','["憑虛公子騎鯨後，烏有先生控鯉初。", "可是凡魚亦仙去，空餘一紙腹中書。"]'),
('dda82405-ae04-4dac-a4a7-ddc7c932f6ec','次律兄餉魚魚不至而詩至頗類南海使君送酒輒成三絕一笑而已賜茗少分以報厚意  其二','沈與求','宋','宋诗','song-poetry','','[]','先生遠餉錦鱗鮮，剥啄扣門驚阿連。',32,'全唐诗/poet.song.96000.json','["先生遠餉錦鱗鮮，剥啄扣門驚阿連。", "只有珠璣落窗几，空教口角墮饞涎。"]'),
('ef777ad2-eb72-423c-baf9-31dee457ceb9','次律兄餉魚魚不至而詩至頗類南海使君送酒輒成三絕一笑而已賜茗少分以報厚意  其三','沈與求','宋','宋诗','song-poetry','','[]','尚方小鳳睗精芽，戲比瓊瑤報木瓜。',32,'全唐诗/poet.song.96000.json','["尚方小鳳睗精芽，戲比瓊瑤報木瓜。", "夢境紛紛非實相，往煩鈎起睡中蛇。"]'),
('c95c4dca-a516-4635-8622-bc31eebf667a','曉過鄰村','沈與求','宋','宋诗','song-poetry','','[]','推枕夢初斷，籃輿踏露行。',48,'全唐诗/poet.song.96000.json','["推枕夢初斷，籃輿踏露行。", "歲登人意樂，風急雁行驚。", "曲澗哀湍瀉，危橋獨木横。", "清霜莫欺客，雲日自晶明。"]'),
('fdfdcbb5-7331-45af-9a1a-85c7cb262152','即事  其一','沈與求','宋','宋诗','song-poetry','','[]','鵲噪空庭曉，霜明百尺樓。',48,'全唐诗/poet.song.96000.json','["鵲噪空庭曉，霜明百尺樓。", "連耞響晴日，遺穗落平疇。", "黄菊疏籬晚，丹楓別岸秋。", "怡情有底計，開甕玉蛆浮。"]'),
('7967f1f8-337d-493d-8e7c-74d53856fbde','即事  其二','沈與求','宋','宋诗','song-poetry','','[]','竹樹參差合，溪流半隱扉。',48,'全唐诗/poet.song.96000.json','["竹樹參差合，溪流半隱扉。", "雨昏鳩婦閙，風急雁奴歸。", "策杖循沙步，褰裳到石磯。", "游魚吾共樂，身世自依違。"]'),
('c3c7e915-f841-4fb2-a779-610bd369cdc6','過梅知宫東軒','沈與求','宋','宋诗','song-poetry','','[]','舍南舍北花無數，眼看游蜂上下狂。',32,'全唐诗/poet.song.96000.json','["舍南舍北花無數，眼看游蜂上下狂。", "風信晚來簾額動，黄庭相對一爐香。"]'),
('cfbc4336-6d77-4c76-9474-f3af4cb06209','允迪遣書問訊并寄示與子我唱酬佳句猥及微蹤輒用廬字韻爲二詩以報嘉惠  其一','沈與求','宋','宋诗','song-poetry','','[]','泛愛何人枉素書，銀鈎奕奕到田廬。',64,'全唐诗/poet.song.96000.json','["泛愛何人枉素書，銀鈎奕奕到田廬。", "朋游久許貧方耐，宦學空憐老更疏。", "回雁峰前應夢到，放龜池上也齋居。", "相期保社同香火，口禱功名乞與渠。"]'),
('57d3831b-7f99-4992-9ef8-b51ad7008f73','允迪遣書問訊并寄示與子我唱酬佳句猥及微蹤輒用廬字韻爲二詩以報嘉惠  其二','沈與求','宋','宋诗','song-poetry','','[]','不從吏議汙丹書，恩許懷章返故廬。',64,'全唐诗/poet.song.96000.json','["不從吏議汙丹書，恩許懷章返故廬。", "投老有緣知分溢，排姦無術愧才疏。", "勝流踴躍聞歸櫂，妙語吹嘘慰索居。", "懷望北轅心已折，忍將時事付軒渠。"]'),
('de34fb6c-b0ad-45ec-a1c5-4e291f5f94da','書懷三首  其一','沈與求','宋','宋诗','song-poetry','','[]','應俗由來嬾，謀身尚敢先。',48,'全唐诗/poet.song.96000.json','["應俗由來嬾，謀身尚敢先。", "栖栖從見嫉，僕僕豈能賢。", "駿馬常追日，方舟可濟川。", "人生各有趣，心目慎相憐。"]'),
('f5a7f2de-eb0c-440e-b308-4d9fa0cab476','書懷三首  其二','沈與求','宋','宋诗','song-poetry','','[]','暗中人易記，名下士非虛。',48,'全唐诗/poet.song.96000.json','["暗中人易記，名下士非虛。", "此道憑誰辦，它時或自如。", "真能食萬戶，定復愧三閭。", "富貴雖吾有，當令功可書。"]'),
('be939d3b-25a8-43d7-8ed7-db3e5bfd7582','書懷三首  其三','沈與求','宋','宋诗','song-poetry','','[]','事業貴不苟，聲名難預期。',48,'全唐诗/poet.song.96000.json','["事業貴不苟，聲名難預期。", "功非宜食肉，道豈忘羹藜。", "政恐儀無舌，那論緯有髭。", "漢庭今用少，覽鏡獨何爲。"]'),
('dd88e124-a1ea-4d97-9d51-7fa2c3c6b0d2','劉希顔提舉見過出示卞山居二詩次其韻  其一','沈與求','宋','宋诗','song-poetry','','[]','偪仄風塵際，分攜歲月賒。',48,'全唐诗/poet.song.96000.json','["偪仄風塵際，分攜歲月賒。", "向來聞避地，勝處偶爲家。", "對客談鋒鋭，憂時酒量加。", "中觴莫辭醉，回首又天涯。"]'),
('4786aa45-88af-487c-9895-37b6613abc2a','劉希顔提舉見過出示卞山居二詩次其韻  其二','沈與求','宋','宋诗','song-poetry','','[]','小別千山隔，相看一笑温。',48,'全唐诗/poet.song.96000.json','["小別千山隔，相看一笑温。", "丹心獵風斾，華髪粲霜根。", "鴨鴨争呼伴，鵶鵶自識村。", "更須判劇飲，落月倒窪尊。"]'),
('446edf84-0dd8-44ec-9f0b-ad71786cad4d','張仲宗有詩懷歸因次其韻勉之','沈與求','宋','宋诗','song-poetry','','[]','相逢無日不懷歸，又是春山聽子規。',64,'全唐诗/poet.song.96000.json','["相逢無日不懷歸，又是春山聽子規。", "休歎豺狼迷道路，似聞貔虎仆旍旗。", "那從薄俗求青眼，還向高堂念白眉。", "南望孤雲應目斷，殊方歲月易推移。"]'),
('23171eaa-250a-46cc-bffa-be527b34f05c','南北山探梅俱未花維心從家圃折數枝以餉坐客蓋半開矣會次律兄有詩輒次韻','沈與求','宋','宋诗','song-poetry','','[]','山北山南雪意忙，梅花未肯鬬寒芳。',64,'全唐诗/poet.song.96000.json','["山北山南雪意忙，梅花未肯鬬寒芳。", "懸知小圃争前發，爲折疏枝分外香。", "故國年華驚晼晚，老人心事伴摧藏。", "更看陌上傳春信，倚杖空懷遲暮傷。"]'),
('de150ca0-bccd-4a6c-97ac-6424d19f04d5','次韻鄭維心探梅未花  其一','沈與求','宋','宋诗','song-poetry','','[]','木落空山不著行，寒梅長是占年芳。',64,'全唐诗/poet.song.96000.json','["木落空山不著行，寒梅長是占年芳。", "未容霜女窺孤豔，定恐花神嗇舊香。", "竹杖穿林聊問訊，槿籬縈路巧遮藏。", "誰能折寄江南恨，北客相看摠可傷。"]'),
('e8c8bec8-2dd7-47fb-bfb8-ddd1699bdd1e','次韻鄭維心探梅未花  其二','沈與求','宋','宋诗','song-poetry','','[]','聞道年時醉一觴，野梅飄几薦餘芳。',64,'全唐诗/poet.song.96000.json','["聞道年時醉一觴，野梅飄几薦餘芳。", "兵塵不礙含生意，花骨猶存底死香。", "入夜從教月浮動，争春空被雪埋藏。", "憑君妙句先催發，調護高枝莫中傷。"]'),
('39277a8a-b527-49d2-aeac-4422f5d7db8c','復次韻呈維心拙澀不工當爲抵掌  其一','沈與求','宋','宋诗','song-poetry','','[]','岐亭幽夢墮微茫，百草先春自不芳。',64,'全唐诗/poet.song.96000.json','["岐亭幽夢墮微茫，百草先春自不芳。", "山雨壓低臨澗影，天風吹下滿林香。", "梨花少韻非儔匹，竹葉多情故斂藏。", "長記江橋閑立馬，落英誰掃重情傷。"]'),
('ec04d401-8019-4e13-a0d6-014fbafbc9cd','復次韻呈維心拙澀不工當爲抵掌  其二','沈與求','宋','宋诗','song-poetry','','[]','粲粲疏梅短短牆，騷人長恨失遺芳。',64,'全唐诗/poet.song.96000.json','["粲粲疏梅短短牆，騷人長恨失遺芳。", "低徊草棘精神透，彷彿關山魂夢香。", "月淡乍看清影亂，春深終恐綠陰藏。", "歲寒爲爾添愁絕，倚樹微吟亦自傷。"]'),
('2eda731d-dd1e-4bad-ac33-9ffa7d621f7c','次韻維心憶梅','沈與求','宋','宋诗','song-poetry','','[]','野花飄盡江梅發，爲報先春一信芳。',64,'全唐诗/poet.song.96000.json','["野花飄盡江梅發，爲報先春一信芳。", "近水疏林風格老，故山歸路夢魂香。", "雪霜貿貿添愁絕，蜂蝶紛紛預屏藏。", "折寄憑君呼健步，生枝莫放手痕傷。"]'),
('cf90a435-4e8e-469a-adf5-dba94830a733','次韻行簡懷次律兄','沈與求','宋','宋诗','song-poetry','','[]','門對青山水繚牆，隔畦花卉盡流芳。',64,'全唐诗/poet.song.96000.json','["門對青山水繚牆，隔畦花卉盡流芳。", "澆胸快瀉鵝兒酒，襲鼻長聞柏子香。", "夜雨對牀成契闊，晚雲歸岫識行藏。", "抽身未試平戎略，空爲憂時倍感傷。"]'),
('40a624f5-4f8b-4336-baaa-75ed5a0fca69','邵子非謂予有天台之行見貽以詩次其韻','沈與求','宋','宋诗','song-poetry','','[]','巉巉老氣鬰青霞，過我依然醉帽斜。',64,'全唐诗/poet.song.96000.json','["巉巉老氣鬰青霞，過我依然醉帽斜。", "爲說驚魂招楚些，忍聞悲曲動胡笳。", "扁舟犯雪來何許，健筆凌雲語益嘉。", "莫笑海山風引去，要尋源上問桃花。"]'),
('98917e43-f791-4661-a35b-971272f43dcd','次韻劉希顔蠟梅二絕  其一','沈與求','宋','宋诗','song-poetry','','[]','仙衣曳紫練裙黄，天遣清臞勝國香。',32,'全唐诗/poet.song.96000.json','["仙衣曳紫練裙黄，天遣清臞勝國香。", "月上小窗寒影動，不禁風味惱剛腸。"]'),
('d45c9310-9437-4edd-bd37-7e93460cea94','次韻劉希顔蠟梅二絕  其二','沈與求','宋','宋诗','song-poetry','','[]','剪成香蜜綴疏枝，度臘争春已恨遲。',32,'全唐诗/poet.song.96000.json','["剪成香蜜綴疏枝，度臘争春已恨遲。", "清夜無人花睡去，小園風露更相宜。"]'),
('7c54a0d3-4654-4fee-809b-bb62cf437767','次韻雪','沈與求','宋','宋诗','song-poetry','','[]','紫簫吹斷玉梅魂，夢入江南幾處村。',32,'全唐诗/poet.song.96000.json','["紫簫吹斷玉梅魂，夢入江南幾處村。", "半夜落英飛不定，旋添清絕到柴門。"]'),
('5c2e715f-7714-41bb-a677-8f2374677775','月下獨步','沈與求','宋','宋诗','song-poetry','','[]','娟娟微月小庭西，月下幽人影自隨。',32,'全唐诗/poet.song.96000.json','["娟娟微月小庭西，月下幽人影自隨。", "賴有寒梅伴愁絕，一枝清艷耿疏籬。"]'),
('ca43b7b2-32c5-4a4d-9227-5395bd30ebdc','次韻次律兄除夜述懷  其一','沈與求','宋','宋诗','song-poetry','','[]','此身傳馬與時移，過盡三餘又一歸。',64,'全唐诗/poet.song.96000.json','["此身傳馬與時移，過盡三餘又一歸。", "野炬占風迷夜色，村肴宿歲待晨晞。", "鬢華老去能餘幾，心賞春來轉覺非。", "慚愧君恩許閑佚，食蔬那比首陽薇。"]'),
('07c80f62-875d-44e1-9563-eb793df22f79','次韻次律兄除夜述懷  其二','沈與求','宋','宋诗','song-poetry','','[]','餞歲鄰翁席屢移，拍歌猶聽夜深歸。',64,'全唐诗/poet.song.96000.json','["餞歲鄰翁席屢移，拍歌猶聽夜深歸。", "尊浮凍螘霜逾重，林噪寒鴉日未晞。", "剰歎飛騰憐杜老，過爲孤憤陋韓非。", "干戈滿眼傷時節，遣戍長聞賦采薇。"]'),
('36f35de0-1b07-4754-ae6a-75cf1bdfe4bc','次律兄以蘆菔見餉并有詩次其韻','沈與求','宋','宋诗','song-poetry','','[]','歲晚嘉蔬已向萎，獨餘蘆菔老霜畦。',64,'全唐诗/poet.song.96000.json','["歲晚嘉蔬已向萎，獨餘蘆菔老霜畦。", "收隨芧栗供山谷，贈比蘋蘩擷澗溪。", "葅亂金釵入珍饌，羹融玉糝脱汙泥。", "程春定覺人彊飯，功校蹲鴟自不齊。"]'),
('6abe4ff1-62d3-4c28-9b48-daa4601e3644','次律兄以鼠盜防風感而作詩命某同賦','沈與求','宋','宋诗','song-poetry','','[]','嘉蔬靈卉兩紛紛，小摘山花自出群。',64,'全唐诗/poet.song.96000.json','["嘉蔬靈卉兩紛紛，小摘山花自出群。", "芽茁短根紅玉卷，葉敷疏節翠旟分。", "細看藥譜鐫遺錄，終擬騷經補缺文。", "堪笑饑鼯穿敗篋，寧知野彘力跑雲。"]'),
('61a75f59-07c9-46cc-a98e-f4d4a35969a9','戲酬嘗草茶','沈與求','宋','宋诗','song-poetry','','[]','慣看留客費瓜茶，政羨多藏不示夸。',64,'全唐诗/poet.song.96000.json','["慣看留客費瓜茶，政羨多藏不示夸。", "要使睡魔能偃草，肯慚懽伯解迷花。", "一旗但覺烹殊品，雙鳳何須覓瑞芽。", "待摘家山供茗飲，與君盟約去驕奢。"]'),
('3cb56da1-0e87-4bc3-b6d0-d663308a4d7e','某蒙學士兄相要陪賞芍藥花多白者月色相射光彩映發殆玉盤盂之苗裔耶維心有詩輒次其韻','沈與求','宋','宋诗','song-poetry','','[]','悵望揚州千朵盛，數枝聊足慰淹留。',64,'全唐诗/poet.song.96000.json','["悵望揚州千朵盛，數枝聊足慰淹留。", "相逢月下陪真賞，一醉花前得勝遊。", "鑿落細斟金暈側，盤盂斜颭玉光浮。", "春衫並色渾無賴，映带霜毛笑隱侯。"]'),
('4ad855cc-3dce-4490-ac57-2a60f20d1ea2','溪亭夜坐','沈與求','宋','宋诗','song-poetry','','[]','波面搖風暑氣微，禿巾來坐釣魚磯。',32,'全唐诗/poet.song.96000.json','["波面搖風暑氣微，禿巾來坐釣魚磯。", "相看月墮行人盡，只有流螢上下飛。"]'),
('11eae73d-f8c7-4445-8e79-42d43925b5da','松架','沈與求','宋','宋诗','song-poetry','','[]','聯絡樛枝架短簷，蒼髯綠骨尚依然。',64,'全唐诗/poet.song.96000.json','["聯絡樛枝架短簷，蒼髯綠骨尚依然。", "袪除畏日心三伏，領略清風直四筵。", "好在老龍蟠夭矯，悞來孤鶴舞蹁躚。", "那堪側雨敲窗夜，貪聽颼颼自不眠。"]'),
('a4d55b36-9112-4975-acea-9faf761017bd','代人作壽詩  其一','沈與求','宋','宋诗','song-poetry','','[]','老人明處識斜河，曾占充閭爽氣多。',64,'全唐诗/poet.song.96000.json','["老人明處識斜河，曾占充閭爽氣多。", "蚤以才名凌屈宋，戲將詩律鬬陰何。", "丹臺舊綴神仙籍，黄屋仍垂將相科。", "禮絕座間公未晚，且提鴻筆上鑾坡。"]'),
('9f2146df-88d6-4e20-a0c0-1e4571d73654','代人作壽詩  其二','沈與求','宋','宋诗','song-poetry','','[]','英氣超超不可親，温然笑語便生春。',64,'全唐诗/poet.song.96000.json','["英氣超超不可親，温然笑語便生春。", "絳帷久屬宗師任，紫橐方參侍從臣。", "八面文章寧有敵，一門忠孝信無倫。", "山東出相公家事，只擬尊前詠大椿。"]'),
('ae8cbd6b-3709-499b-8517-806efd883877','張倅生日以詩爲壽','沈與求','宋','宋诗','song-poetry','','[]','宿歲雕盤供五辛，充閭佳氣已生春。',64,'全唐诗/poet.song.96000.json','["宿歲雕盤供五辛，充閭佳氣已生春。", "俊游自合陪金馬，英骨人猶記石麟。", "別乘重分千里政，五湖追數十年身。", "知公隱德宜難老，鳩杖看扶法從臣。"]'),
('e405f4fe-aeda-457b-9ee0-cbe1f16ab126','詩悼鄒仲容教授','沈與求','宋','宋诗','song-poetry','','[]','骨相自清臞，居然澹滿軀。',48,'全唐诗/poet.song.96000.json','["骨相自清臞，居然澹滿軀。", "高文凌鮑謝，勝略本孫吳。", "鸑鷟期千仞，驊騮殞半途。", "傷心九泉恨，那忍奠生芻。"]'),
('59199a98-4cff-4764-8751-dee51bd291de','徐縣丞挽章','沈與求','宋','宋诗','song-poetry','','[]','插架遺編滿，依然手自臨。',48,'全唐诗/poet.song.96000.json','["插架遺編滿，依然手自臨。", "瓌辭寧世用，高調罕知音。", "白髪浮湘意，青衫忌鵩吟。", "些招空往事，魂斷舊家林。"]'),
('90177ba7-8492-4245-a421-45d78984a39c','蔣司成挽詞  其一','沈與求','宋','宋诗','song-poetry','','[]','法駕天臨五學初，曾聞重席絕諸儒。',64,'全唐诗/poet.song.96000.json','["法駕天臨五學初，曾聞重席絕諸儒。", "雍容久載從臣橐，晼晚猶分刺史符。", "不使高材陪鼎鼐，卻收清節傲江湖。", "賤生無地從巾屨，獨對遺篇想步趨。"]'),
('9e56fb97-bda4-49b1-ad84-b487ac6b8771','蔣司成挽詞  其二','沈與求','宋','宋诗','song-poetry','','[]','召節西來屬老成，乞身終欲返巖扃。',64,'全唐诗/poet.song.96000.json','["召節西來屬老成，乞身終欲返巖扃。", "新書未奏三千牘，舊說曾繙十二經。", "漢室首推施氏易，衛人端識孔悝銘。", "儒宗學府今誰輩，空使諸生記典刑。"]'),
('50fd13ba-991f-4ee5-93a6-bc40cd42e771','曾逢原挽詞  其一','沈與求','宋','宋诗','song-poetry','','[]','落落江湖一偉人，當年玉立映簪紳。',64,'全唐诗/poet.song.96000.json','["落落江湖一偉人，當年玉立映簪紳。", "四朝耆舊推先達，三國英雄出後塵。", "金板袐謀空淟汨，土門奇禍足悲辛。", "懸知精爽猶堪畏，嚼齒傳聞不滿齦。"]'),
('85ac716f-d11f-4574-8024-0dc5369dbdf3','曾逢原挽詞  其二','沈與求','宋','宋诗','song-poetry','','[]','驚聞義骨殞狐狸，悵失中朝一吏師。',64,'全唐诗/poet.song.96000.json','["驚聞義骨殞狐狸，悵失中朝一吏師。", "廣漢威名由擿伏，寛饒直氣不容欺。", "丹心共憤時多難，白首相期論少卑。", "滿眼西風空濺淚，何心忍讀蔡邕碑。"]'),
('1ba20885-ec74-4ce7-b7f3-695c28a5f19d','安次山挽詞  其一','沈與求','宋','宋诗','song-poetry','','[]','都門惜別淚沾巾，回首孤城草木春。',64,'全唐诗/poet.song.96000.json','["都門惜別淚沾巾，回首孤城草木春。", "封豕遙聞食上國，疾風懸料識忠臣。", "程嬰已死終存趙，揚子雖生輒美新。", "青史高名知不朽，遺榮猶賁土中身。"]'),
('03366e18-3704-4e7e-896b-062f31119529','安次山挽詞  其二','沈與求','宋','宋诗','song-poetry','','[]','曉殿傳催玉筍班，東風小立照衰顔。',64,'全唐诗/poet.song.96000.json','["曉殿傳催玉筍班，東風小立照衰顔。", "臨分愧我江湖上，伏節悲君矢石間。", "往事凄凉千古恨，舊交零落幾人還。", "殊方更致生芻奠，目斷高丘涕淚潸。"]'),
('6abb44ca-7a2c-494b-8354-116334e491e5','劉資政挽詞  其一','沈與求','宋','宋诗','song-poetry','','[]','國恥忍言城下盟，忽驚河洛失清寜。',64,'全唐诗/poet.song.96000.json','["國恥忍言城下盟，忽驚河洛失清寜。", "心摧寶仗離宸極，血濺轅門落將星。", "請死自緣鳴越甲，乞師誰爲哭秦庭。", "高名會與丘山重，一誦遺箴一涕零。"]'),
('778f9796-041d-4a20-8360-43fc042105d1','劉資政挽詞  其二','沈與求','宋','宋诗','song-poetry','','[]','志士長悲處死難，唯公勇決一言間。',64,'全唐诗/poet.song.96000.json','["志士長悲處死難，唯公勇決一言間。", "結纓季路空遺跡，投閣揚雄亦厚顔。", "義烈峥嶸昭國史，忠魂寂寞閟家山。", "隻鷄已負它年約，下客傷心兩鬢斑。"]'),
('f26f6f99-b52c-4ba9-b3bc-9a33684f97e7','挽詞二首  其一','沈與求','宋','宋诗','song-poetry','','[]','職爲蘋蘩謹，門推黻冕華。',48,'全唐诗/poet.song.96000.json','["職爲蘋蘩謹，門推黻冕華。", "煢嫠初鞠幼，壽考竟肥家。", "玉暗傳經簡，金餘賜誥花。", "斑衣無復戲，遺恨徹天涯。"]'),
('da876ac2-8ba4-4a17-b1a6-e6c67f2f12c9','挽詞二首  其二','沈與求','宋','宋诗','song-poetry','','[]','耄期何所樂，有子使三吳。',48,'全唐诗/poet.song.96000.json','["耄期何所樂，有子使三吳。", "方享千鍾洎，俄成五鼎踰。", "搆堂遺素幔，祔域閟黄壚。", "欲拜臨終像，它年記結趺。"]'),
('6a569e56-7a99-490b-a947-b964c529ee26','吳宜人挽詞','沈與求','宋','宋诗','song-poetry','','[]','壽富居然五福先，簪纓況復世蟬聯。',64,'全唐诗/poet.song.96000.json','["壽富居然五福先，簪纓況復世蟬聯。", "斷機志節酬平日，舉案風流記昔年。", "上郡方蒙湯沐地，諸郎應廢蓼莪篇。", "送車千乘松門道，會有雙飛鶴戾天。"]'),
('79212e80-a845-4f59-bb7a-4336f4007798','天寧節致語口號','沈與求','宋','宋诗','song-poetry','','[]','欲識樞星紀誕彌，天人端命撫昌期。',64,'全唐诗/poet.song.96000.json','["欲識樞星紀誕彌，天人端命撫昌期。", "聲函萬歲騰歡頌，節應千秋舉慶儀。", "金篋賜齡輝碧簡，珠囊薦壽肅丹墀。", "何須更效南山祝，艮嶽連雲自不移。"]'),
('ac0f8904-515e-46c2-8cbc-cd2422aaa18d','館待高麗進奉使樂語口號','沈與求','宋','宋诗','song-poetry','','[]','仙槎渺渺出雞林，路指神京歲奉琛。',64,'全唐诗/poet.song.96000.json','["仙槎渺渺出雞林，路指神京歲奉琛。", "四海已同朝禹志，萬年宜罄祝堯心。", "儀參大客恩方茂，位亞群公澤更深。", "況有王人宣德義，經塗莫惜費登臨。"]'),
('099ef441-530a-478b-ae21-796991edd1e7','薛林二太尉特排樂語口號','沈與求','宋','宋诗','song-poetry','','[]','三吳分野直中台，一目驚傳二相來。',64,'全唐诗/poet.song.96000.json','["三吳分野直中台，一目驚傳二相來。", "桃李蹊間分組綬，湖山影裏炫尊罍。", "清談道舊真難繼，淺笑追歡許易陪。", "須爲故人成徑醉，已聞雙旌下銀臺。"]'),
('9480bfce-5d5b-4889-a3b9-612abac2b714','館待杭帥樂語口號','沈與求','宋','宋诗','song-poetry','','[]','熊羆千騎駐南州，謀帥來寬旰飯憂。',64,'全唐诗/poet.song.96000.json','["熊羆千騎駐南州，謀帥來寬旰飯憂。", "草木也應思潤澤，湖山正恐費遨遊。", "旌旗耀日催前導，樽俎浮春許暫留。", "劇飲不須辭徑醉，詔環聞已戒鳴騶。"]'),
('84d40b11-818e-4758-b0d0-0d3c3a461ff7','秀州館交代樂語口號','沈與求','宋','宋诗','song-poetry','','[]','一麾相望繼芳塵，召杜風流主與賓。',64,'全唐诗/poet.song.96000.json','["一麾相望繼芳塵，召杜風流主與賓。", "芸閣去方思就日，竹符來及趁班春。", "清談款密看論舊，善政從容許告新。", "早晚銀臺雙詔下，共期持橐侍嚴宸。"]'),
('25ba3546-0874-420b-8446-10637420ba14','草堂二首  其一','沈與求','宋','宋诗','song-poetry','','[]','全家高隱白雲關，事不縈懷夢亦閑。',32,'全唐诗/poet.song.96000.json','["全家高隱白雲關，事不縈懷夢亦閑。", "欸乃交歌漁市散，隔江城郭是人間。"]'),
('14d532ee-a41c-4f80-b4e2-428e3c990ac0','草堂二首  其二','沈與求','宋','宋诗','song-poetry','','[]','仙翁五十鬢猶青，高臥柴門晝亦扃。',64,'全唐诗/poet.song.96000.json','["仙翁五十鬢猶青，高臥柴門晝亦扃。", "茅舍已忘鐘鼎夢，蒲輪休過薜蘿亭。", "陰森門巷先生柳，寂寞江天處士星。", "晚歲田家農事了，閑抄寧戚相牛經。"]'),
('4029ef41-d0a3-4f93-8492-dc5d8000cfa4','歸鄉','沈與求','宋','宋诗','song-poetry','','[]','窮巷歸來已白頭，結茅何必榜休休。',64,'全唐诗/poet.song.96000.json','["窮巷歸來已白頭，結茅何必榜休休。", "好山當戶碧雲晚，明月滿溪寒葦秋。", "詩社縱添新句法，醉鄉難覓舊交遊。", "平生幸自無機械，一棹夷猶去狎鷗。"]'),
('e6e70c0f-88ac-4a14-a8a0-2284c89c71a9','臞庵','沈與求','宋','宋诗','song-poetry','','[]','地控三州界，池開十丈蓮。',48,'全唐诗/poet.song.96000.json','["地控三州界，池開十丈蓮。", "桑麻無杜曲，松菊有斜川。", "別浦歸帆遠，他山晚照妍。", "江湖春水闊，容與白鷗前。"]'),
('c7f8d8b4-645c-48f0-bac3-7fc0b1f0e2ee','南漪堂','沈與求','宋','宋诗','song-poetry','','[]','山遶湖塘寺遶山，平生願向此中閑。',64,'全唐诗/poet.song.96000.json','["山遶湖塘寺遶山，平生願向此中閑。", "青雲白水相浮蕩，野客高僧獨往還。", "少壯無嫌軒冕累，因循將恐鬢鬚斑。", "南漪最是逍遙地，且挹清波濯愧顔。"]'),
('f59eb3f4-8e91-460e-ac3c-ac536d3b8152','偶訪吉甫畫三蠅壁間吉甫有詩次韻','倪濤','宋','宋诗','song-poetry','','[]','何人刻獼猴，老眼覷荆棘。',72,'全唐诗/poet.song.96000.json','["何人刻獼猴，老眼覷荆棘。", "不如丹青手，快意風雨疾。", "我窮坐詩豪，九鼎扛筆力。", "偶然一點污，著紙生羽翼。", "千言走蚍蜉，寧爲寸紙逼。", "還當寫君詩，什襲同藏羃。"]'),
('5aed8818-d555-4288-9dbb-050a240e8bbd','次韻毛達可給事秋懷念歸','倪濤','宋','宋诗','song-poetry','','[]','結茅遠人村，破屋水半扉。',84,'全唐诗/poet.song.96000.json','["結茅遠人村，破屋水半扉。", "涼葉墮清響，空山轉斜暉。", "微官臥江汊，素心久依依。", "十年天涯秋，搖落月芳菲。", "馬蹄歲月去，夢蝶東南飛。", "平生丘壑志，有言輒乖違。", "不如孤征鴻，春風自知歸。"]'),
('f309598d-a07c-40e9-88c2-a388f293ed54','七夕','倪濤','宋','宋诗','song-poetry','','[]','玉殿凭肩共語時，風清月墜有誰知。',32,'全唐诗/poet.song.96000.json','["玉殿凭肩共語時，風清月墜有誰知。", "梧桐秋雨三山遠，始信生前有別離。"]'),
('c87d9899-a374-4203-9629-c77eb2818937','句','倪濤','宋','宋诗','song-poetry','','[]','舊韻無儀字，蒼髯有恨聲。',12,'全唐诗/poet.song.96000.json','["舊韻無儀字，蒼髯有恨聲。"]'),
('1b806fbf-6a65-4da4-bff4-5631527fde4e','金瀨弔貞女歌','楊邦乂','宋','宋诗','song-poetry','','[]','溧山兮蒼蒼，瀨水兮湯湯。',135,'全唐诗/poet.song.96000.json','["溧山兮蒼蒼，瀨水兮湯湯。", "中有貞女，飲冰茹霜。", "於焉擊漂，維瀨之陽。", "遭壯士兮苦絕糧，賑窮不惜傾壺漿。", "所處既以義，安能計存亡。", "幡然捐珮人不測，下遊九土從英皇。", "耿幽光兮貫白日，澟正氣兮摩穹蒼。", "嗚呼！世無李太白，此女終弗揚。", "遺風奕奕，山高水長。", "可以敦薄俗，激忠良，千古萬古誰頡頏。"]'),
('4a9495d2-9048-4b64-bef8-49d65cad1875','寄從弟鱣堂  其一','楊邦乂','宋','宋诗','song-poetry','','[]','從前我亦慕耕桑，世故驅人起北窗。',32,'全唐诗/poet.song.96000.json','["從前我亦慕耕桑，世故驅人起北窗。", "昨夜夢歸驚邂逅，羊裘和雪釣洞江。"]'),
('dea3ab64-c1e2-4d04-b418-1f638c6a1aec','寄從弟鱣堂  其二','楊邦乂','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一片長江滾滾流，此生何日遂歸休。',32,'全唐诗/poet.song.96000.json','["一片長江滾滾流，此生何日遂歸休。", "秋風準擬搔人耳，可待霜寒始索裘。"]'),
('5b2fe5e5-f24e-4c48-8cd3-46d4b6c7478b','句','楊邦乂','宋','宋诗','song-poetry','','[]','寧作趙氏鬼，不爲它邦臣。',12,'全唐诗/poet.song.96000.json','["寧作趙氏鬼，不爲它邦臣。"]'),
('3958ff8b-1b51-4b08-afca-403f0f4e7851','滴水巖','連南夫','宋','宋诗','song-poetry','','[]','滴水巖高路欲窮，佩環聲響玉玲瓏。',64,'全唐诗/poet.song.96000.json','["滴水巖高路欲窮，佩環聲響玉玲瓏。", "一天星斗墮青漢，萬斛珠璣瀉碧空。", "滄海逕歸朝夕會，曹溪不隔本源通。", "何妨凝竚龕巖下，更沐如來灌頂功。"]'),
('93cbc07c-1dde-4689-8fa9-9bc4ca5d69ac','在京思故園見鄉人問','王闐','宋','宋诗','song-poetry','','[]','旅泊多年歲，這去不知迴。',144,'全唐诗/poet.song.96000.json','["旅泊多年歲，這去不知迴。", "忽逢門外客，道發故鄉來。", "斂眉俱握手，破涕共銜杯。", "殷勤訪朋舊，屈曲問童孩。", "衰宗多弟侄，若個賞池臺。", "舊園今在否，新樹也應栽。", "柳行疏密布，茅齋寬窄裁。", "經移何處竹，別種幾株梅。", "渠當無絕水，石計總生苔。", "院果誰先熟，林花那復開。", "羈心祇欲問，爲報不須猜。", "行當驅下澤，去剪故園萊。"]'),
('7e694b41-6cbb-4226-849e-0371f47f3aa9','建炎丞相成國呂忠穆公退老堂','秦梓','宋','宋诗','song-poetry','','[]','釣璜大老舊家聲，崧嶽儲精甫再生。',64,'全唐诗/poet.song.96000.json','["釣璜大老舊家聲，崧嶽儲精甫再生。", "樂道有心安畎畝，逢時無計避功名。", "已扶皦日歸黄道，欲養丹砂隱赤城。", "十里梅花千箇竹，北窗高臥有餘清。"]'),
('56862445-963b-47ed-9aef-998d02247c25','貞義女詠','秦梓','宋','宋诗','song-poetry','','[]','史氏之女生寒門，白璧粲粲貞義存。',160,'全唐诗/poet.song.96000.json','["史氏之女生寒門，白璧粲粲貞義存。", "上無所天漂爲業，春風三十報母恩。", "斬奢芟尚白日昏，子胥脫身間道奔。", "遠來困窮乞於此，漂母進食哀王孫。", "子胥還吳雪讎恥，貞女可憐身已死。", "一飯之德古必償，遺以百金投瀨沚。", "謫仙高才起幽沈，奕奕穹碑照江水。", "有客停舟臨古祠，涼飈動水興遐思。", "蕉黄荔丹幾千古，焄蒿悽愴若見之。", "更憐抉目人已去，姑蘇臺上草萋萋。"]'),
('031b97c3-a3a5-4667-ade9-44506badadef','過烏江','趙奉','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','曉望泰山雲，暮飲烏江水。',24,'全唐诗/poet.song.96000.json','["曉望泰山雲，暮飲烏江水。", "雲水寄萍蹤，何日歸根處。"]'),
('1ed7d808-9433-496a-b7d0-4196e20690c0','乘舟中述懷','趙奉','宋','宋诗','song-poetry','','[]','醉中忽忽到吳頭，懷見金陵卻倦遊。',32,'全唐诗/poet.song.96000.json','["醉中忽忽到吳頭，懷見金陵卻倦遊。", "不逐波流赴滄海，挽茲神水上中洲。"]'),
('149ecb49-8e9f-44ff-9e81-ad08535027c0','初秋喜雨  其一','趙奉','宋','宋诗','song-poetry','','[]','長風吹出萬山雲，釀作甘霖四野均。',32,'全唐诗/poet.song.96000.json','["長風吹出萬山雲，釀作甘霖四野均。", "畦背蓑衣牛背笛，津津喜色洽吾民。"]'),
('f6e5b2c1-b818-4e5b-ae60-b621fd883bfc','初秋喜雨  其二','趙奉','宋','宋诗','song-poetry','','[]','柴門過雨稻花香，一抹輕煙鎖綠楊。',32,'全唐诗/poet.song.96000.json','["柴門過雨稻花香，一抹輕煙鎖綠楊。", "四句吟成誰與和，懷人日日九迴腸。"]'),
('0228759f-c9a6-4c1a-ab60-6a9300154726','蟹浦','錢時敏','宋','宋诗','song-poetry','','[]','層閣面滄江，夜色上東嶺。',48,'全唐诗/poet.song.96000.json','["層閣面滄江，夜色上東嶺。", "風浦多遠聲，月巖見清影。", "棲柯鳥夢恬，依葦漁榔靜。", "招提落寒鐘，寂然絕人境。"]'),
('5986165b-34f5-446e-a5f0-d30918df27b2','句','張俊','宋','宋诗','song-poetry','','[]','嵩嶺便從雲外見，峴山應向雪中看。',16,'全唐诗/poet.song.96000.json','["嵩嶺便從雲外見，峴山應向雪中看。"]'),
('f55e30f5-2338-41d2-bc34-64fa1cb4a90c','夢中賦白鷳','胡憲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','惟餘虛名在，長江與蒼山。',24,'全唐诗/poet.song.96000.json','["惟餘虛名在，長江與蒼山。", "不逢堯舜世，終此若鳥閑。"]'),
('4928f5ad-6c2e-4933-8dd0-9a07d9a659a3','句','胡憲','宋','宋诗','song-poetry','','[]','地勝千山會。',6,'全唐诗/poet.song.96000.json','["地勝千山會。"]'),
('51d547cc-f38c-406c-ac95-aa640bca7f12','留題少林寺  其一','李昌孺','宋','宋诗','song-poetry','','[]','少林來處豈無因，知有當年面壁人。',32,'全唐诗/poet.song.96000.json','["少林來處豈無因，知有當年面壁人。", "五葉一花元會得，莫將消息問殘春。"]'),
('12921586-47d6-4ee4-a934-8629b8d9dec5','留題少林寺  其二','李昌孺','宋','宋诗','song-poetry','','[]','五乳峰前達磨居，徘徊山崦竹疏疏。',32,'全唐诗/poet.song.96000.json','["五乳峰前達磨居，徘徊山崦竹疏疏。", "自從隻履西歸後，卓錫泉今問已無。"]'),
('afecc9c3-9c84-4190-8274-f9ff2ef7a4ea','留題少林寺  其三','李昌孺','宋','宋诗','song-poetry','','[]','曾已香山作隱居，雙泉風月自蕭疏。',32,'全唐诗/poet.song.96000.json','["曾已香山作隱居，雙泉風月自蕭疏。", "不知小鄧庵相近，餘地還能待我無。"]'),
('8d8da3e2-43e4-4652-a161-31e2add14334','示初公頌  其一','李昌孺','宋','宋诗','song-poetry','','[]','昔日曾聞師子音，清風匝地滿叢林。',32,'全唐诗/poet.song.96000.json','["昔日曾聞師子音，清風匝地滿叢林。", "不須更問西來意，曉月亭亭正露金。"]'),
('48363d91-d023-42e8-9792-f21497719252','示初公頌  其二','李昌孺','宋','宋诗','song-poetry','','[]','一見師來契此心，更於何處問知音。',32,'全唐诗/poet.song.96000.json','["一見師來契此心，更於何處問知音。", "要尋達磨當年事，只是如今舊少林。"]'),
('044c02bd-e479-4100-a84b-ef605d7f9c08','陳素齋席上','韓應','宋','宋诗','song-poetry','','[]','自得滄洲趣，門開接釣磯。',48,'全唐诗/poet.song.96000.json','["自得滄洲趣，門開接釣磯。", "江光翻夕照，嵐氣上秋衣。", "心苦一官冷，吟多萬事違。", "何如明月夜，有客扣林扉。"]'),
('9aa7129e-f2c8-4861-830a-991da617ac6c','李介山席上','韓應','宋','宋诗','song-poetry','','[]','野屋與僧鄰，蕭然隔市塵。',48,'全唐诗/poet.song.96000.json','["野屋與僧鄰，蕭然隔市塵。", "好山晴入戶，幽鳥晚依人。", "雨歇竹光潤，風生荷氣新。", "故人同此趣，來往日相親。"]'),
('54b55bfe-c3a4-46e2-9e6b-e94dbf153e0e','丁氏宅','韓應','宋','宋诗','song-poetry','','[]','接竹引山泉，菖陽滿石盆。',48,'全唐诗/poet.song.96000.json','["接竹引山泉，菖陽滿石盆。", "秋高松落子，歲久鶴生孫。", "古壁寒藤上，前人舊墨存。", "平生箕潁興，風度有誰尊。"]'),
('8f3be0e2-9024-4f7b-b94c-e702c2ebfedf','濺玉亭','詹友端','宋','宋诗','song-poetry','','[]','昔聞東坡老，險語壯廬阜。',96,'全唐诗/poet.song.96000.json','["昔聞東坡老，險語壯廬阜。", "向來詩潄玉，光焰不可覆。", "飛龍擘翠峽，絕響還許步。", "追觀秋霜岸，奔流作雷怒。", "春撞碎圭璧，雪濺入窻戶。", "頭眩怯初高，眼眈久反顧。", "恍疑塵埃蹤，誤落清凈土。", "永懷琴高生，控鯉得仙去。"]'),
('bc6a645c-d079-41dd-9c9c-ccf35fa813b8','留題驪山','謝彥','宋','宋诗','song-poetry','','[]','自愧塵容去復來，驪山頂上看崔嵬。',32,'全唐诗/poet.song.96000.json','["自愧塵容去復來，驪山頂上看崔嵬。", "誰人得向長安道，曾浴蓮湯十二回。"]'),
('b4131538-dfa1-4c80-a6a1-feccf36194aa','游靈巖寺','宋居卿','宋','宋诗','song-poetry','','[]','喬木森森結綠陰，翠峰深處隱禪林。',64,'全唐诗/poet.song.96000.json','["喬木森森結綠陰，翠峰深處隱禪林。", "高僧見鶴坐泉眼，群醜聞雞息盜心。", "春去野花開異品，曉來山鳥弄新音。", "勝遊休便生歸計，到此蓬瀛路好尋。"]'),
('f75c1650-8c0b-4d97-94c1-09d20e73cd60','贈李綱','釋宗本','宋','宋诗','song-poetry','','[]','青共立，米去皮。',16,'全唐诗/poet.song.96000.json','["青共立，米去皮。", "此時節，甚光輝。"]'),
('1e27553f-01e5-470a-80a0-c2cd787738da','臨終偈  其一','釋宗本','宋','宋诗','song-poetry','','[]','百骸潰散尋常事，一物長靈識者稀。',32,'全唐诗/poet.song.96000.json','["百骸潰散尋常事，一物長靈識者稀。", "爭似大梅知底意，無聲三昧證緣知。"]'),
('fc2fa077-1aab-416b-8f21-92191686eb79','臨終偈  其二','釋宗本','宋','宋诗','song-poetry','','[]','兩年脾疾苦相攻，瘦骨崚嶒鶴足同。',32,'全唐诗/poet.song.96000.json','["兩年脾疾苦相攻，瘦骨崚嶒鶴足同。", "賴有真常無病者，湛然常在寂光中。"]'),
('f898b044-b3fe-44da-858d-693c47620491','秀溪','羅𡸅','宋','宋诗','song-poetry','','[]','秀溪充塞重堪嗟，誰與通流且種花。',32,'全唐诗/poet.song.96000.json','["秀溪充塞重堪嗟，誰與通流且種花。", "東里先生連古意，欲分餘潤散儒家。"]'),
('d981e847-a7e4-4e22-b9a0-db197a1a286a','蟠龍山','羅𡸅','宋','宋诗','song-poetry','','[]','蟠龍山名何所因，爲言山作蟠龍形。',352,'全唐诗/poet.song.96000.json','["蟠龍山名何所因，爲言山作蟠龍形。", "欲尋地志質諸古，適遇野老傳於今。", "偉哉造化巧經始，斵以斧鑿初無痕。", "四傍坦夷渺原隰，一徑窈窕森松筠。", "回旋屈曲隱頭角，蓊鬰葱翠含精神。", "若蹲若踞玩清隱，不起不蟄司芳辰。", "遙空水面素澄澈，縈若珠顆尤鮮明。", "政當頷下不易奪，況復鱗逆誰敢攖。", "我疑此龍蟠亦久，一日得志當求伸。", "轟雷掣電掀碧漢，驤首曳尾凌青雲。", "會從古穴起靈霓，用作霖雨蘇蒼生。", "豈惟厚澤沛寰宇，兼有餘潤清邊塵。", "乃知神物終變化，肯容玩肆甘沉淪。", "嗟予避寇偶居此，坐見牙璋爭起兵。", "張皇旗幟亘長道，考擊鐘鼓辭嚴城。", "共期元惡心膽破，不待迎敵神魂驚。", "何知鼠輩怙同惡，相與蠶食徒經旬。", "傾囊竭篋極侈欲，戢戈橐矢尋歸程。", "遂令強賊愈猖獗，絕流肆毒屈生靈。", "未聞改轍事更舉，但得飲氣潛悲辛。", "龍乎龍乎速奔逸，吾將與爾俱飛騰。", "直上天池最幽處，噓風吸浪陪鵾鵬。"]'),
('353df0e5-3819-4026-bbab-787cb8619d67','快閣','羅𡸅','宋','宋诗','song-poetry','','[]','一閣巍巍映此心，水餘疊疊翠峰橫。',32,'全唐诗/poet.song.96000.json','["一閣巍巍映此心，水餘疊疊翠峰橫。", "凭欄四顧無纖翳，只有漁歌向晚聲。"]'),
('e83bbe64-d9f8-4e66-855c-50defc6c71dd','龍雲寺','羅竦','宋','宋诗','song-poetry','','[]','倥傯無因懷抱舒，橋邊紆路款幽居。',64,'全唐诗/poet.song.96000.json','["倥傯無因懷抱舒，橋邊紆路款幽居。", "佛龕香火高峰頂，仙洞林坳小雨餘。", "拭目已觀春草句，澄心還味內葉書。", "好風恰似知人意，吹散浮雲現太虛。"]'),
('a473d6f9-bf54-4533-93a2-d9d8239b1223','句','華山道人','宋','宋诗','song-poetry','','[]','北蕃群犬窺籬落，驚起南朝老大蟲。',16,'全唐诗/poet.song.96000.json','["北蕃群犬窺籬落，驚起南朝老大蟲。"]'),
('6749d957-86dd-4de9-b03d-e14f370eb660','臨終偈','婁和尚','宋','宋诗','song-poetry','','[]','有生有死尋常事，無去無來誰不然。',32,'全唐诗/poet.song.96000.json','["有生有死尋常事，無去無來誰不然。", "我今去也何時節，風在松梢月在天。"]'),
('246de9d6-8783-48d0-84b9-9d871b6df0ed','次韻呈天台宰','左緯','宋','宋诗','song-poetry','','[]','僕也不自知，愛詩已成癖。',288,'全唐诗/poet.song.96000.json','["僕也不自知，愛詩已成癖。", "有作盈一囊，無人爲攟摭。", "將求識者觀，千里事行役。", "揚舲入武林，禰刺久未釋。", "一日謁尚書，尚書爲虛席。", "號僕以詩人，聲名從此得。", "日上尚書堂，見公於侍側。", "公時訪天台，頗恨未嘗識。", "洎僕將告歸，贈言羨好色。", "歲月不我留，八年如頃刻。", "俄聞綰銅符，無乃慰平昔。", "自古神仙才，多居隱吏職。", "豈不見王喬，葉縣飛雙舄。", "又不見葛洪，句漏流丹石。", "付公以天台，人事有中的。", "茲山八百里，窈窕多奇跡。", "桐柏古洞天，金庭在其域。", "三災不能侵，歷數無終極。", "景命今始興，吾君壽千億。", "公名亦俱傳，何啻登仙籍。", "僕雖生此邦，仙果未得食。", "今日返問公，何處桃花碧。", "公疑我骨凡，未肯言消息。", "骨凡安敢辭，此桃亦終覓。"]'),
('e3509ad0-3866-4d45-8c60-d3fbba465ec4','大觀戊子秋七月大雨洪水薄城幾至奔決太守李公出禱城上即刻雨止水勢爲殺而民獲免焉因敘其所見爲古體詩五十韻且言台之城不可不修也','左緯','宋','宋诗','song-poetry','','[]','立秋亦云久，涼飈何參差。',288,'全唐诗/poet.song.96000.json','["立秋亦云久，涼飈何參差。", "蓐收氣力弱，炎帝從見欺。", "赤雲熱如火，反甚盛夏時。", "陰陽互擊薄，變動不可期。", "颶風欻卷地，急雨如崩犂。", "屋瓦逗飛鳥，雲柟棼亂絲。", "暗恐江漢覆，又疑山岳隳。", "百川肆橫流，倏忽潄城陲。", "居民類燒蟻，惶恐不自持。", "爲魚在頃刻，呼叫聲何悲。", "我公初不動，徐問其所爲。", "以謂吾在是，水其爲民疵。", "駕言徑往視，朝服來登陴。", "狂瀾吼而至，公亦爲興咨。", "端物叩頭立，逡巡以致辭。", "公辭殆未畢，水還疾如馳。", "回首望黑雲，忽然見明曦。", "雨師不得逞，風伯無所施。", "少皞獨行令，昊天青四垂。", "吁哉是可駭，神速至於斯。", "蒼蒼其天乎，所聽信已卑。", "公言我不聞，豈謂天聞其。", "古人稱至信，水火蹈不疑。", "天人雖限絕，吻合無由私。"]'),
('d5e93d34-c8b8-472a-b6a7-0ef0d4a1074e','避賊書事十三首  其一','左緯','宋','宋诗','song-poetry','','[]','凶賊意何慘，殺人焚其廬。',48,'全唐诗/poet.song.96000.json','["凶賊意何慘，殺人焚其廬。", "我命雖僅免，我家已爲墟。", "譬如巢南鳥，巢破不得居。", "朔風吹黄草，飛去將何如。"]'),
('461ef029-1e1b-4d9e-a161-b80370ee76b1','避賊書事十三首  其二','左緯','宋','宋诗','song-poetry','','[]','生長城市間，吾其患驅逐。',48,'全唐诗/poet.song.96000.json','["生長城市間，吾其患驅逐。", "賊人俄漲天，舉家如奔鹿。", "入山恐不深，但冀免殺戮。", "賊平無所歸，獨倚青松哭。"]'),
('0af3c904-28cc-45ff-a469-d0c31de28350','避賊書事十三首  其三','左緯','宋','宋诗','song-poetry','','[]','懷寶恐吾累，蔽形何可遺。',48,'全唐诗/poet.song.96000.json','["懷寶恐吾累，蔽形何可遺。", "囊衣入山谷，勢急還棄之。", "及至出山日，秋風吹樹枝。", "免爲刀兵鬼，凍死宜無辭。"]'),
('d44bf524-8466-499d-bfbc-e84ca1ccdd5a','避賊書事十三首  其四','左緯','宋','宋诗','song-poetry','','[]','賊來屬初夏，逃去窮幽荒。',48,'全唐诗/poet.song.96000.json','["賊來屬初夏，逃去窮幽荒。", "山深松蘿密，野曠草木長。", "蟒蛇大如樹，見我不忍傷。", "賊固不如蟒，害人無善良。"]'),
('77223f3a-2cdb-4b7b-b873-661074313859','避賊書事十三首  其五','左緯','宋','宋诗','song-poetry','','[]','搜山輒縱火，躡跡皆操刀。',48,'全唐诗/poet.song.96000.json','["搜山輒縱火，躡跡皆操刀。", "小兒饑火逼，掩口俾勿號。", "勿號可禁止，饑火彌煎熬。", "吾人古有命，困仆猶能逃。"]'),
('90547c75-f501-4e46-a9f7-1aa60ca8a808','避賊書事十三首  其六','左緯','宋','宋诗','song-poetry','','[]','十遷昧南北，終歲在路歧。',48,'全唐诗/poet.song.96000.json','["十遷昧南北，終歲在路歧。", "霜堅齧我足，風冽剝我肌。", "艱難固其分，衰老難支持。", "白骨亂荒草，百遷亦不辭。"]'),
('42d4ecd9-2f7f-4ee4-8f90-a7971b67c328','避賊書事十三首  其七','左緯','宋','宋诗','song-poetry','','[]','東鄰有老人，金玉富無敵。',48,'全唐诗/poet.song.96000.json','["東鄰有老人，金玉富無敵。", "惡賊一朝來，棄之如瓦礫。", "性命雖尚存，見人無顔色。", "老人自不思，本爲大盜積。"]'),
('0be702f2-ecac-4249-9949-75f6b38d652e','避賊書事十三首  其八','左緯','宋','宋诗','song-poetry','','[]','保城恃義兵，誤事真可惜。',48,'全唐诗/poet.song.96000.json','["保城恃義兵，誤事真可惜。", "國家久昇平，誰復睹鋒鏑。", "一旦驅市人，紛然冒矢石。", "逢敵先棄戈，罪之不可得。"]'),
('78623894-0db2-4da9-8860-368c37f263c6','避賊書事十三首  其九','左緯','宋','宋诗','song-poetry','','[]','妻兒共一區，日夜謹相守。',48,'全唐诗/poet.song.96000.json','["妻兒共一區，日夜謹相守。", "遙驚白旗來，不覺四散走。", "汝死吾不知，吾亡汝何咎。", "隔林聞哭聲，相見真成偶。"]'),
('c699a42b-602e-4e1b-bdcf-ab499c3316f3','避賊書事十三首  其一○','左緯','宋','宋诗','song-poetry','','[]','今我有三子，欲謀分置之。',48,'全唐诗/poet.song.96000.json','["今我有三子，欲謀分置之。", "庶幾一子在，可以收我尸。", "老妻已咽絕，三子皆號悲。", "生離過死別，不如還相隨。"]'),
('5f050349-4ffc-4844-9a27-5a4a91d6d3bb','避賊書事十三首  其一一','左緯','宋','宋诗','song-poetry','','[]','妖賊本蒸民，忽爾爲豬豚。',48,'全唐诗/poet.song.96000.json','["妖賊本蒸民，忽爾爲豬豚。", "王師一日下，割剝恣啗吞。", "食盡固其所，恐傷仁聖君。", "招安俾復業，亦既不是人。"]'),
('87206c94-8b22-444c-80b6-397c618eb573','避賊書事十三首  其一二','左緯','宋','宋诗','song-poetry','','[]','有女衣已穿，顔色猶自好。',48,'全唐诗/poet.song.96000.json','["有女衣已穿，顔色猶自好。", "無食未幾時，呦呦哭荒草。", "問之誰家女，低頭未忍道。", "前山欲黄昏，吾行不暇考。"]'),
('380f3d46-3927-41fe-94de-92142b4f6fbf','避賊書事十三首  其一三','左緯','宋','宋诗','song-poetry','','[]','嗟爾遊宦人，彌年住京闕。',48,'全唐诗/poet.song.96000.json','["嗟爾遊宦人，彌年住京闕。", "盡室寄東南，一朝聞賊發。", "道路已不通，音書多斷絕。", "朔風滿長安，日夜成華髪。"]'),
('4455e277-bcbc-4ccb-9bc8-42a26bc2fcbb','會侄書','左緯','宋','宋诗','song-poetry','','[]','憶昨宣和末，群凶聚韋羌。',288,'全唐诗/poet.song.96000.json','["憶昨宣和末，群凶聚韋羌。", "一朝邏巡尉，州縣皆皇皇。", "居民棄家走，元稚紛搶攘。", "我時遭劫逐，與子空相望。", "及茲建炎始，叛卒起錢塘。", "初聞殺長吏，尋亦及冠裳。", "死者不爲怪，生者反異常。", "子在賊圍中，不知存與亡。", "出處雖異域，阽危多備嘗。", "骨肉非不親，患難各自當。", "回思見賊日，豈謂免殺傷。", "安知出深壁，猶得還故鄉。", "爭言不死狀，失聲驚四旁。", "餘生偶然遂，萬事皆可忘。", "會我試新秫，放懷坐中堂。", "庭梧露踳碧，砌菊風催黄。", "年華意未晚，蟋蟀已近床。", "對此復何待，五觴至十觴。", "歌聲咽寒月，舞袖破夜霜。", "豈無少年態，一醉乃爾狂。", "此徒爲酒使，酒力安得長。", "燈影照鬢髪，百憂在中腸。", "干戈時未息，盜賊勢益張。", "與子歸何處，相看兩茫茫。"]'),
('e182ee23-e06b-4406-92de-584ada03cc1e','送僧歸天台','左緯','宋','宋诗','song-poetry','','[]','還尋流水去，水極到天台。',48,'全唐诗/poet.song.96000.json','["還尋流水去，水極到天台。", "時把碧雲句，寄將黄葉來。", "石門高賺雪，溪塢曲藏梅。", "貪看故山色，不知春已迴。"]'),
('fca7acde-7df1-4047-8690-66f641d7be93','送齊上人遊方','左緯','宋','宋诗','song-poetry','','[]','往究一乘去，期明諸祖燈。',48,'全唐诗/poet.song.96000.json','["往究一乘去，期明諸祖燈。", "遠山銜落日，空谷響殘冰。", "離物心無染，談經義有憑。", "世人多頂禮，爲是右橋僧。"]'),
('f1cb0a4d-2698-4dbd-8372-d895c3155285','崇教寺','左緯','宋','宋诗','song-poetry','','[]','只把山爲界，紅塵自此分。',48,'全唐诗/poet.song.96000.json','["只把山爲界，紅塵自此分。", "竹窗吟聽雪，苔石坐看雲。", "意靜詩先到，心清道自聞。", "深慚王許輩，猿鶴舊同群。"]'),
('38589a81-2bdb-4473-9615-9b3ec881e5e3','交翠亭','左緯','宋','宋诗','song-poetry','','[]','地勝多喬木，亭幽闞古墉。',48,'全唐诗/poet.song.96000.json','["地勝多喬木，亭幽闞古墉。", "春梢經雨合，晚色過煙濃。", "影落琴書徧，聲穿戶牖重。", "鸞棲應不久，枳棘若爲容。"]'),
('157b6f90-e87a-43fc-8531-8eaa03b9092c','半山庵','左緯','宋','宋诗','song-poetry','','[]','入山須判宿，不宿漫區區。',48,'全唐诗/poet.song.96000.json','["入山須判宿，不宿漫區區。", "泉脈尋還有，蘭香嗅卻無。", "杉高方見直，石怪不成粗。", "若到三潭頂，歸時路更迂。"]'),
('d9901431-ec7c-4766-830b-cded3ecb8c17','天台石橋','左緯','宋','宋诗','song-poetry','','[]','咄哉橋畔客，何不向前行。',48,'全唐诗/poet.song.96000.json','["咄哉橋畔客，何不向前行。", "自是君心險，無從此地平。", "銀河千尺到，金劍一稜傾。", "故我諸緣斷，唯聞流水聲。"]'),
('f2ec9aa9-568b-4b7f-80c7-25866964e151','避寇即事十二首  其一','左緯','宋','宋诗','song-poetry','','[]','凶賊起何暴，數州俄見殘。',48,'全唐诗/poet.song.96000.json','["凶賊起何暴，數州俄見殘。", "殺人空骨亂，聞者爲心寒。", "世治官軍怯，城孤守吏難。", "天兵何日到，淚眼望長安。"]'),
('cb8b17dd-4b5c-43be-a8bd-2008cf48dc5e','避寇即事十二首  其二','左緯','宋','宋诗','song-poetry','','[]','遙聞烏合輩，數十破錢塘。',48,'全唐诗/poet.song.96000.json','["遙聞烏合輩，數十破錢塘。", "故是昇平久，胡爲守備亡。", "天誅初不暴，賊勢尚云張。", "作過古來有，未宜憂我皇。"]'),
('e14d9b89-740e-4015-9812-2023e2dc0368','避寇即事十二首  其三','左緯','宋','宋诗','song-poetry','','[]','避地遶天涯，艱難兩鬢華。',48,'全唐诗/poet.song.96000.json','["避地遶天涯，艱難兩鬢華。", "逢人唯問賊，有夢只還家。", "幾處看楓葉，今朝見菊花。", "客衣寒更薄，日暮在平沙。"]'),
('4af90674-5626-47fe-a02f-3f2304141b64','避寇即事十二首  其四','左緯','宋','宋诗','song-poetry','','[]','消息苦無定，轉移難預言。',48,'全唐诗/poet.song.96000.json','["消息苦無定，轉移難預言。", "起看殘月色，行遶亂雲根。", "餓久百骸劣，啼多雙眼昏。", "天涯迷去路，誰爲我招魂。"]'),
('db7631fe-3026-484a-98f0-5cf054803bb9','避寇即事十二首  其五','左緯','宋','宋诗','song-poetry','','[]','草暗迷人迹，山空答履聲。',48,'全唐诗/poet.song.96000.json','["草暗迷人迹，山空答履聲。", "夜眠溫石去，朝爨束薪行。", "骨肉長嬉笑，交朋每送迎。", "回思無事日，已恐是前生。"]'),
('14ec1bf8-660e-46f5-8aa1-5e5e5fe5b978','避寇即事十二首  其六','左緯','宋','宋诗','song-poetry','','[]','失所尚遷次，江湖信足行。',48,'全唐诗/poet.song.96000.json','["失所尚遷次，江湖信足行。", "朝廷自多土，天地只孤生。", "已是無歸處，何須問去程。", "甘心委溝壑，回首戀昇平。"]'),
('c97f8d97-3f0e-43a8-9b13-78eb61212dd3','避寇即事十二首  其七','左緯','宋','宋诗','song-poetry','','[]','移家入空谷，十口墮荆榛。',48,'全唐诗/poet.song.96000.json','["移家入空谷，十口墮荆榛。", "猛虎欲當路，怪禽如喚人。", "死生吾有命，幽獨自傷神。", "泉石非無意，終身愧隱淪。"]'),
('3f6c7fb1-331f-4c4c-a215-c3e39c68293b','避寇即事十二首  其八','左緯','宋','宋诗','song-poetry','','[]','轉徙不知處，亂山逢掩扃。',48,'全唐诗/poet.song.96000.json','["轉徙不知處，亂山逢掩扃。", "斷崖飛虺蟄，枯木亂鴉腥。", "莽蒼人煙滅，黄昏鬼火青。", "夜寒長飲泣，安得壯夫聽。"]'),
('afe717dd-60be-4219-baf5-b215f451c621','避寇即事十二首  其九','左緯','宋','宋诗','song-poetry','','[]','寂寞空山裏，黄昏百怪新。',48,'全唐诗/poet.song.96000.json','["寂寞空山裏，黄昏百怪新。", "鬼沿深澗哭，狐出壞牆頻。", "小雨俄成霰，孤燈不及晨。", "開門謝魑魅，我是太平人。"]'),
('4fc7c858-6360-45eb-a36d-a85211279442','避寇即事十二首  其一○','左緯','宋','宋诗','song-poetry','','[]','借問今何所，空山號白龍。',48,'全唐诗/poet.song.96000.json','["借問今何所，空山號白龍。", "秋聲悽萬竅，雪意黯千峰。", "俯首燒殘葉，披衣聽斷鐘。", "生涯都付賊，只有一萍蹤。"]'),
('2280db9c-8e31-4e7b-8f62-1b0983228a55','避寇即事十二首  其一一','左緯','宋','宋诗','song-poetry','','[]','無路掃妖氛，掀髯倚碧雲。',48,'全唐诗/poet.song.96000.json','["無路掃妖氛，掀髯倚碧雲。", "草茅難報國，畎畝敢忘君。", "民業稍云復，賊巢猶未焚。", "老臣筋力盡，灑淚對三軍。"]'),
('a4565615-3b47-4fee-ab82-336933d79dda','避寇即事十二首  其一二','左緯','宋','宋诗','song-poetry','','[]','太平無可議，妖孽欲何求。',48,'全唐诗/poet.song.96000.json','["太平無可議，妖孽欲何求。", "未足煩天討，然猶假廟謀。", "鷹揚誰敢抗，鳥散類難收。", "首惡聞猶在，王師願小留。"]'),
('468d9880-11d9-41c2-9433-6574c5d24707','聞角','左緯','宋','宋诗','song-poetry','','[]','頻催白日盡，爲爾一歔欷。',48,'全唐诗/poet.song.96000.json','["頻催白日盡，爲爾一歔欷。", "壯士軍中老，流人嶺外歸。", "秋生邊樹暗，月在隴沙微。", "燈火孤城閉，蕭蕭黄葉飛。"]'),
('5422126e-7737-4eca-8227-0514b6ba28b5','香遠堂','左緯','宋','宋诗','song-poetry','','[]','試捲珠簾看，青山有幾重。',48,'全唐诗/poet.song.96000.json','["試捲珠簾看，青山有幾重。", "崢嶸秋色老，蒼莽暮煙濃。", "未辨清猿處，遙知白鳥蹤。", "藍田無此景，痛掃只雙松。"]'),
('9d2526c7-3f5c-4033-a399-e0f973045ca1','題摘星嶺','左緯','宋','宋诗','song-poetry','','[]','已知星可摘，須信路皆通。',48,'全唐诗/poet.song.96000.json','["已知星可摘，須信路皆通。", "日影穿雲薄，天形入水空。", "遙看梁苑雪，獨挹楚臺風。", "指點中華地，山河萬國雄。"]'),
('c1798f80-e9df-4b9c-9775-303b958d2072','送許左丞至白沙爲舟人所誤','左緯','宋','宋诗','song-poetry','','[]','短棹無尋處，嚴城欲閉門。',48,'全唐诗/poet.song.96000.json','["短棹無尋處，嚴城欲閉門。", "水邊人獨自，沙上月黄昏。", "老別難禁淚，空歸易斷魂。", "豈知今夜夢，先過白沙村。"]'),
('abf53b47-3250-4725-b336-d399f16ae2c2','春晚','左緯','宋','宋诗','song-poetry','','["\u4eba\u751f", "\u6625\u5929", "\u611f\u4f24", "\u5199\u666f"]','池上柳依依，柳邊人掩扉。',48,'全唐诗/poet.song.96000.json','["池上柳依依，柳邊人掩扉。", "蝶隨花片落，燕拂水紋飛。", "試數交游看，方驚笑語稀。", "一年春又盡，倚杖對斜暉。"]'),
('6f734c3b-669f-49a5-9386-ca9e30c5790f','梅花','左緯','宋','宋诗','song-poetry','','[]','幾度尋春信，空歸及暮鴉。',48,'全唐诗/poet.song.96000.json','["幾度尋春信，空歸及暮鴉。", "試搖枝上雪，恐有夜來花。", "望月穿深塢，迎風立淺沙。", "若同桃李發，誰肯到山家。"]'),
('e5535974-75af-4a91-9ebf-a72c5655a12c','九峰','左緯','宋','宋诗','song-poetry','','[]','路人溪聲壯，秋深樹影稀。',48,'全唐诗/poet.song.96000.json','["路人溪聲壯，秋深樹影稀。", "岫雲藏鳥語，松露滴人衣。", "詩戰蜂腰怯，茶分粥面微。", "勝遊殊未厭，肯爲夜寒歸。"]'),
('143be8c7-685d-4455-bd7c-98477a95e453','雁山','左緯','宋','宋诗','song-poetry','','[]','亂山無限好，幽徑有時迷。',48,'全唐诗/poet.song.96000.json','["亂山無限好，幽徑有時迷。", "石骨秋偏瘦，松梢老卻低。", "天寒聞雁過，月白見烏棲。", "海上知名地，無人識馬蹄。"]'),
('83ef9999-a7e1-4610-a78d-e750d3731065','次韻王似之過天台','左緯','宋','宋诗','song-poetry','','[]','彩旆搖霜宿鳥驚，旋將疾苦問民情。',64,'全唐诗/poet.song.96000.json','["彩旆搖霜宿鳥驚，旋將疾苦問民情。", "從容會歷三臺遍，謦欬先看數路清。", "紅日盡頭思玉闕，赤霞深處見瑤京。", "信知子晉真苗裔，仙籍還居第幾名。"]'),
('e30050ea-aabc-4b31-a8fb-ed51826d08c1','次韻朱承事題丹邱','左緯','宋','宋诗','song-poetry','','[]','白雲城郭照通衢，未怕雲煙屬五湖。',64,'全唐诗/poet.song.96000.json','["白雲城郭照通衢，未怕雲煙屬五湖。", "萬疊暮山屏自展，一江春水練初鋪。", "輸他夫子供吟筆，沒箇閑人與畫圖。", "子晉玉簫聲已斷，不知笙鶴更來無。"]'),
('0b7e45a8-9063-4f2d-b796-976d8ae42203','尋委羽洞','左緯','宋','宋诗','song-poetry','','[]','委羽不知何處是，倩人扶上木蘭橈。',64,'全唐诗/poet.song.96000.json','["委羽不知何處是，倩人扶上木蘭橈。", "欲尋去路花梢密，爭認行雲酒浪搖。", "流水忽隨山腳轉，洞天疑把杖頭挑。", "逡巡不覺東風晚，殆有仙人弄玉簫。"]'),
('cebecf2c-15d3-4997-9e4a-6efaab4e325f','趨石橋初登山嶺','左緯','宋','宋诗','song-poetry','','[]','天梯欲上使人愁，身御長風不自由。',64,'全唐诗/poet.song.96000.json','["天梯欲上使人愁，身御長風不自由。", "下視白雲生澗底，仰看紅日在山頭。", "共傳此處迷劉阮，自恐今朝犯斗牛。", "歸路似從雲漢墮，卻來塵世待羈囚。"]'),
('1c7d5351-2e8d-493c-92a5-2c0b7f896030','次韻贈段德公','左緯','宋','宋诗','song-poetry','','[]','宦游初謂江南好，不道淹留十載餘。',64,'全唐诗/poet.song.96000.json','["宦游初謂江南好，不道淹留十載餘。", "官職任卑終傲世，俸錢雖少尚收書。", "天台舊俗思重借，于浦同官忍獨疏。", "縱使北歸猶識路，滏陽三徑近使如。"]'),
('92733464-dd3c-46c3-baec-38f526bd2b32','送方尉還任','左緯','宋','宋诗','song-poetry','','[]','平安耿耿念庭闈，乞假言旋謝式微。',64,'全唐诗/poet.song.96000.json','["平安耿耿念庭闈，乞假言旋謝式微。", "應向門前留彩棒，卻來堂下舞斑衣。", "流花洞口春將近，蓋竹山頭雪已晞。", "聞說後年官始滿，不知重到幾時歸。"]'),
('5c4d65bd-5d29-41f1-b76d-ff7942eaa1cb','過友人居','左緯','宋','宋诗','song-poetry','','[]','試問春蠶第幾眠，柳條如線雨如煙。',64,'全唐诗/poet.song.96000.json','["試問春蠶第幾眠，柳條如線雨如煙。", "池蛙相應昏昏月，海燕初歸漠漠天。", "卒歲未妨資橘柚，餘生應只付林泉。", "他時卜宅如相近，且種壕頭十畝蓮。"]'),
('d463cc79-7a62-46e2-b48d-c3c7358e9e7c','春日','左緯','宋','宋诗','song-poetry','','[]','嫩紅相逐上枝頭，多少東風索我酬。',64,'全唐诗/poet.song.96000.json','["嫩紅相逐上枝頭，多少東風索我酬。", "春色似人看易老，年華如客去難留。", "長因好景翻成恨，只恐香醪壓得愁。", "深放黄金爲酒盞，一城飛絮已悠悠。"]'),
('3c0f2742-64e8-4fe0-88ce-e31d8550e20b','招友人飲','左緯','宋','宋诗','song-poetry','','[]','入門相見喜還悲，不免樽前細問之。',64,'全唐诗/poet.song.96000.json','["入門相見喜還悲，不免樽前細問之。", "一別又經無數日，百年能得幾多時。", "後生袞袞皆成事，吾輩栖栖亦可疑。", "日暮東風吹鬢髪，拍牀嗔道酒行遲。"]'),
('d0222f13-31f0-4381-80e8-da360e5cc0a1','次盛元敘遊九峰韻','左緯','宋','宋诗','song-poetry','','[]','恰恰鶯啼欲曉天，喚人擔酒入林泉。',64,'全唐诗/poet.song.96000.json','["恰恰鶯啼欲曉天，喚人擔酒入林泉。", "沿崖覓路僧先引，選勝看山席屢遷。", "心靜掉頭嫌鼓吹，酒狂揮手弄雲煙。", "日斜數點殘紅下，芳草菲菲索醉眠。"]'),
('f0c62492-f364-47f9-8fb7-d690ac0cdcd8','桃源洞  其一','左緯','宋','宋诗','song-poetry','','[]','劉郎何用憶塵寰，舊路重尋事已難。',32,'全唐诗/poet.song.96000.json','["劉郎何用憶塵寰，舊路重尋事已難。", "古意飄零無處覓，藤縈溪色上闌干。"]'),
('74f39c3f-2be5-4876-a617-214529a00dcc','桃源洞  其二','左緯','宋','宋诗','song-poetry','','[]','浮杯石上坐多時，手弄滄浪客思遲。',32,'全唐诗/poet.song.96000.json','["浮杯石上坐多時，手弄滄浪客思遲。", "片片落花收拾看，洞中疑有舊題詩。"]'),
('f16ae1a3-f569-4c6e-9c21-0f3ea0a2c29d','桃源洞  其三','左緯','宋','宋诗','song-poetry','','[]','青山簇簇水灣灣，洞戶應將玉鎖關。',32,'全唐诗/poet.song.96000.json','["青山簇簇水灣灣，洞戶應將玉鎖關。", "飲罷出來紅日晚，一聲雞犬悟人間。"]'),
('04e3d5b6-b04b-4ad3-a376-875ed107c4c1','天台道中','左緯','宋','宋诗','song-poetry','','[]','亂山深處是仙家，海變桑田日未斜。',32,'全唐诗/poet.song.96000.json','["亂山深處是仙家，海變桑田日未斜。", "爲有慈親倚門望，卻愁溪上見桃花。"]'),
('340a99ee-8e82-4b9e-940f-5b6f23aad13d','石新婦','左緯','宋','宋诗','song-poetry','','[]','煙蘿爲髻霧爲巾，獨立江邊經月春。',32,'全唐诗/poet.song.96000.json','["煙蘿爲髻霧爲巾，獨立江邊經月春。", "無故被人呼作婦，不知誰是畫眉人。"]'),
('c5ee6fcd-b1be-44a8-9f9e-2ab03fe0c799','題正等院竹軒','左緯','宋','宋诗','song-poetry','','[]','山色重重鎖碧蘿，更栽修竹在山阿。',32,'全唐诗/poet.song.96000.json','["山色重重鎖碧蘿，更栽修竹在山阿。", "老僧不識春頭面，但見階前新筍多。"]'),
('e3c045c2-0199-4820-8da9-43da36bfb57a','送別','左緯','宋','宋诗','song-poetry','','[]','騎馬出門三月暮，楊花無賴雪漫天。',32,'全唐诗/poet.song.96000.json','["騎馬出門三月暮，楊花無賴雪漫天。", "客情惟有夜難過，宿處先尋無杜鵑。"]'),
('f4356b07-9f8b-43cb-b7e9-a4d337ab0bba','春日曉望','左緯','宋','宋诗','song-poetry','','[]','屋角風微煙霧霏，柳絲無力杏花肥。',32,'全唐诗/poet.song.96000.json','["屋角風微煙霧霏，柳絲無力杏花肥。", "朦朧數點斜陽裏，應是呢喃燕子飛。"]'),
('6a509ec4-cb0f-403b-9bdf-cf68e9f97a71','句  其一','左緯','宋','宋诗','song-poetry','','[]','祗把清風占得公。',8,'全唐诗/poet.song.96000.json','["祗把清風占得公。"]'),
('753fcdc9-82f8-4569-a57a-3a8cae3b8b78','句  其二','左緯','宋','宋诗','song-poetry','','[]','怪巖摩足力，空谷答人聲。',12,'全唐诗/poet.song.96000.json','["怪巖摩足力，空谷答人聲。"]'),
('5a734fd9-9c9b-417d-a3aa-0d1178d28ab4','句  其三','左緯','宋','宋诗','song-poetry','','[]','禽巢先覺曉，蟻穴未知霜。',12,'全唐诗/poet.song.96000.json','["禽巢先覺曉，蟻穴未知霜。"]'),
('cec5b7f8-c5c1-48f8-8b5d-fbfba21dddca','句  其四','左緯','宋','宋诗','song-poetry','','[]','歲華搖落盡。',6,'全唐诗/poet.song.96000.json','["歲華搖落盡。"]'),
('b404dcc3-da69-490d-bbc5-f0d1125c1470','飛龍引','劉才邵','宋','宋诗','song-poetry','','[]','憶昔遊洛川，投宿龍門中。',168,'全唐诗/poet.song.96000.json','["憶昔遊洛川，投宿龍門中。", "遠意託清夢，緱山訪遺蹤。", "道逢王子晉，瓊輪駕飛龍。", "幢盖紛颯沓，導從千玉童。", "行行躡清塵，遂到紫翠峰。", "整冠叩仙閽，獲禮冰雪容。", "瓊觴酌霞醴，勞苦問所從。", "授以龜臺書，玉笈啟靈封。", "勸我勤修煉，他時會方蓬。", "再拜領真訣，永永藏丹衷。", "俯仰十載餘，光景如飄風。", "常恐年歲晏，難收梨棗功。", "願言堅此心，真緣儻潛通。", "相與乘飛霞，謁帝青琳宫。"]'),
('3476fa68-a57d-47c6-a33b-4cfb6b8dd1c8','登景德寺塔','劉才邵','宋','宋诗','song-poetry','','[]','耽耽梵釋宫，憑高剏靈址。',228,'全唐诗/poet.song.96000.json','["耽耽梵釋宫，憑高剏靈址。", "中有窣堵波，排突青冥裏。", "梯磴眩回轉，蟠屈龍蛇尾。", "飛步出紫氛，眼界浄如洗。", "望極天南端，沓若孤烟起。", "何當結蜃樓，亭亭聊對峙。", "雲生空山頂，飛過朱闌底。", "憑欄瞰重城，樓堞雜雲水。", "市人何憧憧，閙若穿垤蟻。", "壯觀自何年，五季運初圯。", "干戈暗淮海，裒斂到骨髓。", "誰知黑雲都，金帛浩填委。", "聊復推其餘，辦此咄嗟爾。", "因知破慳法，驍悍亦風靡。", "百年能幾時，兩曜無停晷。", "弔古悲陵谷，山荒樹如薺。", "雙江雖依舊，去浪何曾止。", "從來曠達士，遐想塵外軌。", "安得凌風翰，一舉九萬里。"]'),
('5eb62493-eb7d-4ca0-90be-9c32fd31942b','次韻陳久道秋雨書事二首  其一','劉才邵','宋','宋诗','song-poetry','','[]','尋常秋色高，風力未遽惡。',120,'全唐诗/poet.song.96000.json','["尋常秋色高，風力未遽惡。", "應緣殺氣盛，惨淡連沙漠。", "林枯日向疏，溪斷水初落。", "閑雲亦何心，釀雨添寂寞。", "賴有金蘭契，新詩慰蕭索。", "盛意難虛辱，終愧筆鋒弱。", "元知鸞鶴音，異彼藩籬雀。", "欲泛東籬英，聊慶西疇穫。", "區區戀闕心，對酒翻不樂。", "天禍有時悔，妖氛會清廓。"]'),
('f34fa4e2-b245-4645-829f-67db8b97f275','次韻陳久道秋雨書事二首  其二','劉才邵','宋','宋诗','song-poetry','','[]','蕭蕭凉氣增，發興殊不惡。',120,'全唐诗/poet.song.96000.json','["蕭蕭凉氣增，發興殊不惡。", "長煙拂秋暈，小雨滑溪涸。", "夜長蟲語乏，池冷蓮衣落。", "崇蘭媚深靜，晚菊甘寂寞。", "寒姿曉更鮮，芳氣初不索。", "譬彼幽閑女，靜飾保纖弱。", "又如耿介士，逸志卑燕雀。", "無心競紛華，何處生隕穫。", "知君深悟此，高歌寫真樂。", "悠然脱塵鞅，寸田本恢廓。"]'),
('ffac06e4-be3c-4f7e-9e23-e5cecdbe5f63','子夜四時歌  其一','劉才邵','宋','宋诗','song-poetry','','[]','柳煙晨氣釅，花露春容濕。',48,'全唐诗/poet.song.96000.json','["柳煙晨氣釅，花露春容濕。", "翠幕捲宫羅，翩翩雙燕入。", "無心補粟眉，閑對粧臺立。", "誰調紫鸞笙，晴響散空碧。"]'),
('b3741659-d064-43c6-81eb-acef6d16bd12','子夜四時歌  其二','劉才邵','宋','宋诗','song-poetry','','[]','湘簟湧雙紋，冰山象群玉。',48,'全唐诗/poet.song.96000.json','["湘簟湧雙紋，冰山象群玉。", "神飈送荷香，冉冉度圓綠。", "雪腕蕩蘭舟，齊唱横塘曲。", "暗憶採蓮侣，横翠長眉蹙。"]'),
('7b6c9a14-62be-469a-ac92-bd6198e7a277','子夜四時歌  其三','劉才邵','宋','宋诗','song-poetry','','[]','月痕抹宫簾，凉風滿仙腋。',48,'全唐诗/poet.song.96000.json','["月痕抹宫簾，凉風滿仙腋。", "金閨歌吹深，不覺東方白。", "誰知長門宫，偏怪蟾漏澁。", "脉脉對曉蘭，風中抱香泣。"]'),
('3fd31750-bdac-4aff-a7e4-eeb4f9ed6349','子夜四時歌  其四','劉才邵','宋','宋诗','song-poetry','','[]','冰花生曲池，雲葉暗高閣。',48,'全唐诗/poet.song.96000.json','["冰花生曲池，雲葉暗高閣。", "初筵動雲韶，寒氣不待卻。", "翠茵承妙舞，拂衣燕低掠。", "翻愁回雪妬，不遣褰珠箔。"]'),
('513a280b-7591-4b13-bd79-9fc6ef87895e','次韻王文成謝人惠蓴菜','劉才邵','宋','宋诗','song-poetry','','[]','頗聞富鮭菜，徑欲作不速。',96,'全唐诗/poet.song.96000.json','["頗聞富鮭菜，徑欲作不速。", "忍以辛甘故，而煩主人肅。", "蒙分紫虯髯，芳滑鹽豉足。", "中原困苦旱，乾死食藿蠋。", "何從覓嘉蔬，得以供口腹。", "幸益殷孚羹，一解炎蒸毒。", "物隨人意重，爲惠同鼎餗。", "荒哉膏粱子，豐饌誇填谷。"]'),
('6d1948e7-fcfe-438f-8f00-b0dd392fec47','謝王君寶惠菊花','劉才邵','宋','宋诗','song-poetry','','[]','常憐避俗翁，寄傲謝簪紱。',204,'全唐诗/poet.song.96000.json','["常憐避俗翁，寄傲謝簪紱。", "三徑竹雖存，苦乏盃中物。", "采采黄金英，籬邉空竚立。", "賴有好事人，陶然得酣適。", "吾家頗種秫，壓滓夜槽泣。", "其如移菊晚，青蘂不堪摘。", "念誰分秋香，泛此花瓷白。", "高情歘相投，遣送勞一力。", "風期宛然同，未易分今昔。", "兩株千萬朵，冷艷光相射。", "銀盤何爛爛，承露带青碧。", "月下更奇絕，碎影寒氣逼。", "桃紅吐鮮妍，醉暈不容拭。", "嘉名配黄花，姚魏真匹敵。", "開窗對二妙，清意爭先入。", "卻思陪語笑，坐歎溪山隔。", "幸有真契存，滿目共秋色。"]'),
('e0577980-7806-4159-9127-95961ffb253e','青原臺次前人韻','劉才邵','宋','宋诗','song-poetry','','[]','伯仲聯華萼，登臨擁旌幢。',288,'全唐诗/poet.song.96000.json','["伯仲聯華萼，登臨擁旌幢。", "從行真鳳雛，不數襄陽龐。", "聖人念遠民，暫輟臨此邦。", "共驚后夔手，胡爲調衆腔。", "公獨體上意，勤民起膏肓。", "餘閑養詩勇，萬鈞一指扛。", "謝家內集盛，文彩今可雙。", "江白曳縞練，山青逼軒窗。", "緬懷風幡語，聞者拱手降。", "獨此雙泉老，機鋒暗相撞。", "曹溪一滴水，傾出白玉缸。", "至今正脉通，洪流咽三江。", "遠水注江腹，浮雲盪山胸。", "悠悠動遐想，矗矗標奇峰。", "祖意透今古，風期協霜鐘。", "詩中無礙辨，未信景能供。", "黄堂正多暇，森戟閑衛兵。", "月波復蕩漾，遥接銀河傾。", "天高萬物肅，星潤三階平。", "使君樂歲豐，高臺延客登。", "從來中秋夕，難得滿意晴。", "江山自高下，歌管搖空明。", "参差桂影動，清濕露華凝。", "新詩出妙思，心境還雙清。"]'),
('b4963980-94a2-4926-8079-960d329a52bf','次韻傅安道同陳元功諸公遊石獅巖','劉才邵','宋','宋诗','song-poetry','','[]','中書英烈氣，凛然照人寒。',288,'全唐诗/poet.song.96000.json','["中書英烈氣，凛然照人寒。", "濟美世有人，盛德啟其原。", "幸逢賢别乘，論文得交歡。", "逸辯傾遠海，潮波歘飛奔。", "燭理無滯碍，白日破幽昏。", "誰云前輩遠，豈獨文采存。", "新詩引人目，當食不暇餐。", "爲說遊巖樂，飛步恣騰鶱。", "卻立視萬象，森如列庭間。", "飄然乘風興，星榆不難攀。", "聊復陳大概，彼美難盡言。", "少年陳將軍，奮迹起江村。", "共知宰社手，美好豈常貧。", "深懷恩未報，竭誠奉至尊。", "驅兵獵餘寇，烈火焚蜂屯。", "亦復事招納，投弓憫窮猿。", "坐令歸業民，井竈羅丘樊。", "是日出近郊，旌旗鬰幡幡。", "同遊不知倦，落照横松門。", "士卒共甘苦，無人譏華元。", "老守懶出遊，何從滌塵煩。", "况阻陪歸騎，幽尋款禅關。", "鈴齋但兀坐，有酒空盈樽。", "常能歌妙句，爲激壯士肝。"]'),
('8783a3e2-231d-4446-974f-46b545927a1c','次韻劉克強寄劉齊莊并見寄','劉才邵','宋','宋诗','song-poetry','','[]','吾宗富清製，學海無滣湄。',288,'全唐诗/poet.song.96000.json','["吾宗富清製，學海無滣湄。", "洪濤駕三山，逸興不可羈。", "抱此未獲騁，造化真小兒。", "邇來二十年，姦諛取世資。", "梟鳶志氣滿，鸞翮戢固宜。", "皎皎空谷姿，誰復詠來思。", "上天既悔禍，威命方飈馳。", "遠裔復干紀，危塗動噫嘻。", "我生落世紛，備嘗憂與疑。", "敵帳如鬼國，漂墮驚渺瀰。", "蒼蒼安可問，泯然空自知。", "脱身垂涎口，生死争一釐。", "事機如電轉，由來難逆推。", "况當艱危際，志願常參差。", "小已安足念，身世久已遺。", "但有區區心，痛憤難伸眉。", "知公愛我厚，恠我色不移。", "新詩沃煩襟，勝彼白玉巵。", "天葩輕組繡，清芬吐鮮奇。", "復如遊玄圃，紫鸞雜文螭。", "雲煙忽中斷，宛虹露長鬐。", "驚嘆方未已，復歌清遠詞。", "南溟雄絕境，句中得潛窺。", "想當白日晝，微風皺琉璃。"]'),
('b6f9c238-0aba-48ef-b2c5-d6d9a512a7c5','次韻周秀實贈王自然','劉才邵','宋','宋诗','song-poetry','','[]','隱者逃世網，遂欲安一枝。',132,'全唐诗/poet.song.96000.json','["隱者逃世網，遂欲安一枝。", "不能負猿鶴，山林無返時。", "吾人富道義，詞華振芳蕤。", "共疑斂逸步，不願黄金羈。", "然於論議間，憂國不顧私。", "豈從隱者徒，耦耕抽棘茨。", "顧難同群碎，輕屈邁往姿。", "何當副仄席，執簡上玉墀。", "一薦危苦語，自結明主知。", "良藥起民瘼，神膏除國疵。", "不同鄭子真，虛名動京師。"]'),
('6c3a3c10-64e1-47f0-9cf1-2201b8db4a27','次韻張寶文贈王自然','劉才邵','宋','宋诗','song-poetry','','[]','成山對三山，殘夜動海色。',96,'全唐诗/poet.song.96000.json','["成山對三山，殘夜動海色。", "英靈鍾此翁，倜儻舊無敵。", "高標駕空濶，勁氣摧劍戟。", "危言髪衝冠，憂國淚横臆。", "當隨赴隴書，聊挂遊山屐。", "從容冕旒前，指摘治亂實。", "况聞群策用，佇待妖氛息。", "名與年俱高，機會不容失。"]'),
('508fce4d-0587-42e0-bd0c-f59460a8c254','次韻贈劉晞揚','劉才邵','宋','宋诗','song-poetry','','[]','旱氣徹坤輿，井水幾欲沸。',180,'全唐诗/poet.song.96000.json','["旱氣徹坤輿，井水幾欲沸。", "鄉邦正嗷嗷，度日長於歲。", "肯來款柴門，高義警衰替。", "時方遊郡城，塵駕未及税。", "逢迎闕主禮，走報乏候吏。", "空憐意頻繁，宗契敦魯衛。", "久聞吾子賢，不恥鶉衣敝。", "大璞固已奇，或就資良器。", "袖有瀘溪詩，價敵千金字。", "霜餘秋日嚴，春到江山麗。", "勤勤欲相勉，句句有深味。", "要當窮益堅，固豈患無位。", "田園雖已空，甑堕從脱棄。", "立賢本無方，數路今不廢。", "方觀群策用，坐使昆夷喙。"]'),
('39655a02-67b3-4f95-949f-69b711bfeb7d','贈王至道','劉才邵','宋','宋诗','song-poetry','','[]','乾坤萍宅水，日月蟻旋磨。',180,'全唐诗/poet.song.96000.json','["乾坤萍宅水，日月蟻旋磨。", "百年能幾何，經眼飛隼過。", "志士多苦心，共惜分陰趖。", "功名上竹帛，千百中幾箇。", "豈堪懷宴坐，偪仄就庸懦。", "王郎荆楚秀，俊氣傾四坐。", "屹如飽霜鷹，遠意不受挫。", "公家老先生，才高膽力大。", "生平持正論，終不懲寡和。", "延留住江閣，屢見月鏡破。", "不將恩奪義，朝夕勤磨磋。", "已見器識全，致遠誰能奈。", "正如舟楫具，風便即轉柂。", "要當度帆力，勢緊須少挅。", "行收利涉功，舉酒輙先賀。"]'),
('06fd4f93-4595-4726-8797-0cb8747bf2fb','贈劉升卿','劉才邵','宋','宋诗','song-poetry','','[]','五季詞格卑，一往遂不轉。',288,'全唐诗/poet.song.96000.json','["五季詞格卑，一往遂不轉。", "勢如屋將摧，難用一木撁。", "國家復古初，出力賴諸彦。", "探元測天心，擷秀空芳甸。", "氣質既雄渾，采章復葱蒨。", "炳焉同三代，風雅追未變。", "旁收稗官說，笑䐑時一薦。", "豈將鰕蜆盤，盡易鼎俎膳。", "後來失其源，多以恠相眩。", "觀濤遺巨浸，愛此一漚漩。", "芝蘭向蕪没，蕭艾方蔓延。", "顧豈無可觀，致遠恐非便。", "方今從雅道，英俊爭就選。", "當有紫鸞音，一洗時禽囀。", "吾宗富清製，金璞飽鎔鍊。", "高軒肯見臨，大軸獲初見。", "盈前森欲動，貪讀不知倦。", "吳歈鬭妍媚，楚些發哀怨。", "暗芳啼曉露，白月垂秋練。", "肅肅天廟儀，遲遲洞宫宴。", "建標凌倒景，勝氣來酣戰。", "古人用意處，窺闖應已徧。", "不然新詩中，安得衆體見。", "從來絕妙處，經眼不容眴。"]'),
('b1248217-5c26-468a-a3a3-29fd9995f8e6','次韻李彦淵送春','劉才邵','宋','宋诗','song-poetry','','[]','殘花啼宿露，惜與芳春辭。',48,'全唐诗/poet.song.96000.json','["殘花啼宿露，惜與芳春辭。", "多情被花惱，寫入柳枝詞。", "落絮惹芳草，新荷點清池。", "去意不可挽，酹以碧玉巵。"]'),
('6e8b3993-c99c-4046-9b09-169192ec4881','鄭守宣化齋前雙蓮','劉才邵','宋','宋诗','song-poetry','','[]','使君致遠器，清塗久飛轍。',132,'全唐诗/poet.song.96000.json','["使君致遠器，清塗久飛轍。", "聖朝念遠民，分符暫還輟。", "名齋以宣化，立意豈虛設。", "勤勤布德意，宿弊除根穴。", "坐令千里間，歌頌自填噎。", "聲聞聽卑耳，祥應爲之發。", "歘從齋前池，共蔕丹葩結。", "雙娥殊勝姿，同駐凌波韈。", "皎如寒鑑中，清影兩奇絕。", "方知報政速，顧豈待期月。", "行觀拜褒詔，飛纓覲丹闕。"]'),
('ef2a453b-eb1f-4ec1-87a2-cc17636acd87','題碧玉軒詩','劉才邵','宋','宋诗','song-poetry','','[]','燕石乏良質，謬當十襲貯。',108,'全唐诗/poet.song.96000.json','["燕石乏良質，謬當十襲貯。", "鼠璞本腐材，笑殺千金賈。", "取名非其實，縱美徒自許。", "惟有冰雪姿，堪與瓊瑤伍。", "幽軒清有餘，直幹森可數。", "抱節保堅剛，凝陰貫寒暑。", "圓虛律琯匀，蕭瑟鳴球舉。", "比德兩相宜，此君衆所與。", "揭名警浮躁，用意非小補。"]'),
('fafb625e-e380-49c5-aed0-ad9da3f48408','題歐陽炳文真止亭','劉才邵','宋','宋诗','song-poetry','','[]','前浪與後浪，推引不自休。',132,'全唐诗/poet.song.96000.json','["前浪與後浪，推引不自休。", "誰知橋下水，終古何曾流。", "喧寂兩俱遣，已自非良謀。", "避喧趨寂者，豈免一處收。", "吾人識真際，不向中邉求。", "聊復起小亭，對此竹檜幽。", "雲煙互明滅，草木自春秋。", "諸法如露電，乾坤一浮漚。", "試看究竟處，還有起滅不。", "想當隱几時，蕭然任天遊。", "不同習枯禅，兀兀守一丘。"]'),
('0c591dce-58d5-4819-9205-a98026393481','觀瀾閣爲羅長卿題','劉才邵','宋','宋诗','song-poetry','','[]','贛水出而激，交流虎城背。',288,'全唐诗/poet.song.96000.json','["贛水出而激，交流虎城背。", "崎嶇三百里，方脱灘石礙。", "滔滔遂北之，遠與西江會。", "揚瀾在其北，抝怒兩崖隘。", "春天雲氣裂，拍岸山石碎。", "老蛟千丈強，擘水見光怪。", "水初無定形，因勢生萬態。", "出石未入江，其間幸平快。", "公家起高閣，下瞰鋪練带。", "天光迷上下，山影分向背。", "魚行吹細浪，鷺下點晴黛。", "氣象日夕佳，無一可揀汰。", "獨憐風動地，萬竅雜號噫。", "雖微江濤壯，波山亦高大。", "取名遂以此，用意知有在。", "西江天設險，雄絕難摹繢。", "賴有醉翁詞，卓偉盖當代。", "神清鸞鶴遠，故里江山在。", "後來揮翰手，顧豈易追配。", "因公索題詩，愧汗若方頮。", "盛意難虛辱，輕作恐終悔。", "以茲進退間，捉筆久不黴。", "牢辭既不獲，聊復書梗概。", "聖言如大川，到海無邉界。"]'),
('aa71d27e-e3e3-48c8-9f0a-571d3a805ae8','題競秀亭','劉才邵','宋','宋诗','song-poetry','','[]','遠水恨微茫，近山露巖壑。',180,'全唐诗/poet.song.96000.json','["遠水恨微茫，近山露巖壑。", "是中有佳處，遠近理自各。", "危亭枕江干，江外群峰泊。", "森然青玉圭，穿空勢如削。", "沙湍與松籟，逼耳笙磬作。", "勿言山宜遠，近亦殊不惡。", "雲烟半有無，月霧带清薄。", "凝嵐與空翠，不受曉雨濯。", "是時崖窽藏，秀氣森盤礴。", "方知寸碧岑，信美恐難博。", "主人喜賓至，宴豆日參錯。", "况有賢弟兄，超然解禪縛。", "拄笏望西山，心境兩脱略。", "想當觴詠時，險語恣嘲謔。", "何當遊其間，時聽穿林雹。"]'),
('05e1e525-a3c6-4670-aa6d-d01c8a8ff3a8','哀劉志明','劉才邵','宋','宋诗','song-poetry','','[]','滋蘭事修潔，佩服何陸離。',48,'全唐诗/poet.song.96000.json','["滋蘭事修潔，佩服何陸離。", "誰爲風霜慘，輕同蕭艾萎。", "芸窗螢罷照，蕙帳鶴猶疑。", "有子能傳業，皇天還有知。"]'),
('05ee58b3-ecb0-45a2-86e5-8fd3a48f761b','遊天竺靈隱寺詩','劉才邵','宋','宋诗','song-poetry','','[]','清晨出城西，車馬紛颯沓。',252,'全唐诗/poet.song.96000.json','["清晨出城西，車馬紛颯沓。", "行行巖壑深，漠漠霧雨雜。", "雲陰忽披豁，海色共蕭颯。", "幽尋浩莫窮，空響時相答。", "地籟笙竽真，材纈丹青合。", "潦收猿澗浄，寺遶鷲峰匝。", "簷牙向空啄，殿腳依山插。", "空翠撲軒窗，乳洞敞閨閤。", "泄雲無定姿，欹石半相磕。", "珠燈吐光焰，香龍振鱗甲。", "啼煙禽念佛，掇蘂蜂供蠟。", "丹井漲靈泉，嵒松披艾衲。", "蘿徑勞躋攀，風扉自開闔。", "龍天想奔凑，飛走亦馴狎。", "同遊今淵雲，馳聲久鞺鞳。", "逸驥誰能追，流風不受閘。", "家山富岷峨，水驛經夔峽。", "不應得未曾，猶若濟所乏。", "欲去還停騶，就石屢移榻。", "共笑香積供，未脱腐儒糲。", "重來當一洗，尋盟忽忘歃。"]'),
('006343e8-a6a5-4754-8669-916e42238c70','次韻劉寛夫題進此庵','劉才邵','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','使君機鑒高，圓妙等空有。',156,'全唐诗/poet.song.96000.json','["使君機鑒高，圓妙等空有。", "一超到真際，論古全無友。", "豈更向鴻濛，勤勤問何叟。", "以茲了喧靜，三三元一九。", "佳哉府中園，松竹當花柳。", "於中結圓廬，風月供戶牖。", "從來廊廟具，朝野注望久。", "難從容膝安，廣袤横數肘。", "定煩帷幄籌，爲指逐獸狗。", "氣吞西江水，吸盡才一口。", "坐令世間人，仰之如北斗。", "第功高汗馬，許復更稱首。", "方知庵中人，元是經綸手。"]'),
('8941b04b-8f4e-4585-b13c-afdad39ea7c6','題李知監野思亭','劉才邵','宋','宋诗','song-poetry','','[]','秋風挾殘暑，秋日垂清光。',132,'全唐诗/poet.song.96000.json','["秋風挾殘暑，秋日垂清光。", "行行向城西，夾路紅蕖香。", "松岡西北轉，中間水雲鄉。", "小亭信佳哉，叢篁供晚凉。", "月溪響環珮，古來隱城隍。", "斜影分徑柳，依依已成行。", "蕭然清思動，濶遠無邊傍。", "公云方經始，從今闢幽荒。", "豈惜草木富，簷宇日舒長。", "此興不退轉，來效未易量。", "更欲堅公意，留詩冀勿忘。"]'),
('d8b78759-314c-4a2f-84fd-7fa7b07cb595','書翠波亭','劉才邵','宋','宋诗','song-poetry','','[]','雲谿瀉寒液，活碧瑠璃軟。',60,'全唐诗/poet.song.96000.json','["雲谿瀉寒液，活碧瑠璃軟。", "山如物外人，排空勢偃蹇。", "溪山兩奇絕，倒影蘸清淺。", "驚風起蘋末，萬竅助號喘。", "誰鋪翠織成，一展不容卷。"]'),
('a3bb1b4c-09a0-4b7a-99c2-a6856261acfe','醉經堂爲段成之作','劉才邵','宋','宋诗','song-poetry','','[]','醉者全於酒，憂患雖暫捐。',84,'全唐诗/poet.song.96000.json','["醉者全於酒，憂患雖暫捐。", "豈若醉經人，因以全於天。", "六經藴妙理，深醇道之源。", "是中儻知趣，真成中聖賢。", "賢哉段夫子，奥學窺古先。", "虛堂得真適，心神自陶然。", "不同嗜糟粕，釋鑿煩輪扁。"]'),
('cfc2029b-5cbb-46e4-a32a-510d548d8b2c','次韻朱新仲省宿十首  其一','劉才邵','宋','宋诗','song-poetry','','[]','天運若循環，火中暑方徂。',48,'全唐诗/poet.song.96000.json','["天運若循環，火中暑方徂。", "中庭月霧薄，映空凝有無。", "曉色上丹闕，回光射平湖。", "殿門觀劍集，櫑具裝鹿盧。"]'),
('40722729-df42-42ef-bf9e-248df76e7ba7','次韻朱新仲省宿十首  其二','劉才邵','宋','宋诗','song-poetry','','[]','新詩神物護，在處謹誰何。',48,'全唐诗/poet.song.96000.json','["新詩神物護，在處謹誰何。", "讀罷清風來，簾旌搖翠波。", "最憐超詣處，高標鬰嵯峨。", "欲學空有心，恐似龜茲驘。"]'),
('f4693de0-5302-4f58-9173-1ec112a42ace','次韻朱新仲省宿十首  其三','劉才邵','宋','宋诗','song-poetry','','[]','紅塵倦奔馳，流汗緣衣縷。',48,'全唐诗/poet.song.96000.json','["紅塵倦奔馳，流汗緣衣縷。", "深堂儘岑寂，寢卧殊得所。", "春去能幾時，還復見徂暑。", "悠悠天壤間，俯仰成今古。"]'),
('08deda57-b1dc-4f68-87de-6886c0271b8c','次韻朱新仲省宿十首  其四','劉才邵','宋','宋诗','song-poetry','','[]','夕陽淡遥岑，晚烟横萬井。',48,'全唐诗/poet.song.96000.json','["夕陽淡遥岑，晚烟横萬井。", "清風入修竹，真契不待請。", "無人共杯杓，何許發嘲哂。", "空餘江梅興，蒼波千萬頃。"]'),
('47f7113c-e860-4d30-95d5-8bf039a4d027','次韻朱新仲省宿十首  其五','劉才邵','宋','宋诗','song-poetry','','[]','古井貯寒泉，清深不見底。',48,'全唐诗/poet.song.96000.json','["古井貯寒泉，清深不見底。", "銅瓶下纖綆，輒輟斗升水。", "取用亦不乏，餘冷冰頰齒。", "人生消底物，悟此貴知止。"]'),
('a951c4d3-9cde-4488-9550-fb39685d93dc','次韻朱新仲省宿十首  其六','劉才邵','宋','宋诗','song-poetry','','[]','閏餘先占秋，秋至熱難久。',48,'全唐诗/poet.song.96000.json','["閏餘先占秋，秋至熱難久。", "不知更旬日，燈火可親不。", "書告腕欲脱，正藉解勞酒。", "誰知比舍郎，新釀復烏有。"]'),
('84cebaaf-8175-484e-8065-241e0bff5b69','次韻朱新仲省宿十首  其七','劉才邵','宋','宋诗','song-poetry','','[]','老火鑠稚金，已滿庚伏節。',48,'全唐诗/poet.song.96000.json','["老火鑠稚金，已滿庚伏節。", "江湖氣候偏，殘暑尚屯結。", "頗欲學僧軒，灑粉作竹雪。", "蕭然寒意生，儻可滌煩熱。"]'),
('6620a6a8-8146-496f-88c7-082420c35cc1','次韻朱新仲省宿十首  其八','劉才邵','宋','宋诗','song-poetry','','[]','誰云艱難際，儒冠愧兜鍪。',48,'全唐诗/poet.song.96000.json','["誰云艱難際，儒冠愧兜鍪。", "勝算運帷幄，殺氣凛先秋。", "偏師掃狂寇，千里行不留。", "捷書送喜頻，行聞甲兵休。"]'),
('d82b2d46-a20a-4807-8d06-696b45ac8124','次韻朱新仲省宿十首  其九','劉才邵','宋','宋诗','song-poetry','','[]','與作先秋蒲，豈若經霜竹。',48,'全唐诗/poet.song.96000.json','["與作先秋蒲，豈若經霜竹。", "堅脆随所養，古人戒多欲。", "年來鉛汞鼎，丹火猶未伏。", "更須形中神，各各司其局。"]'),
('74965208-a541-4060-9c8a-222a39581f90','次韻朱新仲省宿十首  其一○','劉才邵','宋','宋诗','song-poetry','','[]','神飈轉闕角，龍旗振瓊鑾。',48,'全唐诗/poet.song.96000.json','["神飈轉闕角，龍旗振瓊鑾。", "是時天宇凈，極望青漫漫。", "更長海月上，高出修竹竿。", "遥知露如珠，的皪在仙盤。"]'),
('da4d3758-a0ae-4d0d-b98f-cba1051b4695','題霧豹齋','劉才邵','宋','宋诗','song-poetry','','[]','幽人樂安閑，雜世不復顧。',144,'全唐诗/poet.song.96000.json','["幽人樂安閑，雜世不復顧。", "可憐有爲身，輕被山林錮。", "豈知曠達士，用捨隨所寓。", "聊從隱約中，養就扶世具。", "如彼南山豹，深藏十日霧。", "一朝文采成，蔚然駭狐兔。", "偉哉王夫子，術業久饒裕。", "今猶事韜晦，盖亦以此故。", "獨於議論間，時肯一斑露。", "使得效所長，英躔可平步。", "方今正急賢，延納非一路。", "願早隨鶴書，勿久山間住。"]'),
('93fe9b06-fa80-4ee9-aba5-2366260b85b9','登高丘而望遠海','劉才邵','宋','宋诗','song-poetry','','[]','登高丘，望遠海，銀臺芝闕排空煙，青童羽駕今安在。',88,'全唐诗/poet.song.96000.json','["登高丘，望遠海，銀臺芝闕排空煙，青童羽駕今安在。", "炎涼相續如循環，堂堂白日欺紅顔。", "誰能混迹塵埃間，當驅風馭凌三山。", "問天暫借斬鯨劍，長鬐中斷蒼波閑。", "卻憑海若檄北極，員嶠岱輿宜見還。"]'),
('845ab1d1-f687-429f-9352-627a015f6ae6','湘夫人歌','劉才邵','宋','宋诗','song-poetry','','[]','湘山影落重湖中，中有菌閣臨珠宫。',80,'全唐诗/poet.song.96000.json','["湘山影落重湖中，中有菌閣臨珠宫。", "霞衣蘭佩雜香風，蓮旂閃閃拖晴紅。", "朱弦凄怨指法鬆，綠煙洗盡山重重。", "湘雲遠與蒼梧通，騰空宛轉如遊龍。", "雲中帝子謁重瞳，寶車倐忽穿遥空。"]'),
('2c877296-b4a0-4d67-b074-71553596e1c8','昭君出塞行','劉才邵','宋','宋诗','song-poetry','','[]','曉鐘傳箭金門開，翠裘玉几高崔嵬。',144,'全唐诗/poet.song.96000.json','["曉鐘傳箭金門開，翠裘玉几高崔嵬。", "蕃官膜拜領天語，玉顔忍涙青娥摧。", "塵昏金翠風鬟亂，琵琶難寫重重怨。", "回望秦關煙霧深，心魂暗逐么絃斷。", "大閹當國國勢卑，坐致匈奴輒輕漢。", "請婚薦女不自慚，畫師微罪翻深按。", "雖然責賂變真質，卻爲宫中去尤物。", "正似渠成秦利厚，反間之辜宜特宥。", "漢皇儻有帝王資，盡戮姦諛賞延壽。"]'),
('62ed4e7e-4b1b-4156-bec7-07652fa49e2e','塞下曲二首  其一','劉才邵','宋','宋诗','song-poetry','','[]','北落光搖霜海空，邊烽飛入甘泉宫。',96,'全唐诗/poet.song.96000.json','["北落光搖霜海空，邊烽飛入甘泉宫。", "天家下詔發精銳，健馬騰驤衝朔風。", "羽書四出如飛電，路指蕭關旗影轉。", "壯士爭酬未報恩，青樓淚臉空垂線。", "匣中劍作饑龍鳴，流星正墜單于營。", "將軍玉帳曉初起，卧看邊風吹漢旌。"]'),
('8e8bc623-e498-4b7a-88b0-293758d8a306','塞下曲二首  其二','劉才邵','宋','宋诗','song-poetry','','[]','燕支山頭秋葉脫，白龍堆下沙如雪。',160,'全唐诗/poet.song.96000.json','["燕支山頭秋葉脫，白龍堆下沙如雪。", "膠筋漆力胡馬肥，驃騎提兵辭玉闕。", "萬甲光寒若流水，殺氣高隨鼓聲超。", "琱弓一發落欃槍，連天氛祲清如洗。", "金節牙旗入漢關，捷書曉奏天開顔。", "玉麟噴香滿瑤殿，黄麾仗裏排千官。", "小臣拜舞彤庭下，一寸丹心願攄寫。", "安邊上策古豈無，戒在窮兵事戎馬。", "但敷文德懷百蠻，邊塵不動弓刀閑。", "漢人耕種胡人獵，陛下聖壽齊南山。"]'),
('94f2c93d-2653-4e0e-87aa-846d047c7dfe','勒兵行','劉才邵','宋','宋诗','song-poetry','','[]','高臺曉色明雙旌，來看將軍親閱兵。',128,'全唐诗/poet.song.96000.json','["高臺曉色明雙旌，來看將軍親閱兵。", "甲光熒熒照秋水，陣行屢變隨縱横。", "將軍勇銳無堅敵，馳心已向伊吾北。", "好同諸将擁琱戈，浄掃邊塵早開國。", "重收京邑翠華西，卻歸宿衛聽朝雞。", "蓬萊宫深花柳暗，曖風輕動龍蛇旗。", "監丞健筆文中虎，須臾作歌繼常武。", "是時劍佩共趨朝，何似勒兵誇練組。"]'),
('048e6f9c-ec86-42c2-8032-f448f3cb616c','相思曲','劉才邵','宋','宋诗','song-poetry','','[]','長相思，懷百憂，誰憐方寸間，常貯一掬愁。',118,'全唐诗/poet.song.96000.json','["長相思，懷百憂，誰憐方寸間，常貯一掬愁。", "年華過眼如川流，君亦何心長遠遊。", "菱花炯炯垂鸞結，懶學宫梅勻膩雪。", "風吹涼鬢影蕭蕭，一抹疏雲對斜月。", "紅樓曲檻凌高寒，秋色滿空風更酸。", "問征鴻兮倩爾傳素書，歲将闌兮君早還。", "何時失喜聽嘶馬，相迎小立珠簾下。"]'),
('af97be13-a111-4409-874e-489610f0d2a7','清夜曲','劉才邵','宋','宋诗','song-poetry','','[]','紅藍衫薄香玉春，翠鬟䰀鬌盤鬆雲。',64,'全唐诗/poet.song.96000.json','["紅藍衫薄香玉春，翠鬟䰀鬌盤鬆雲。", "門前溪水空粼粼，鯉素不傳嬌翠顰。", "窗紗濾月寒光薄，冉冉暮愁無處著。", "龜屏掩恨玉痕垂，井桐葉墮青鸞啼。"]'),
('e8d47de7-1e3b-4afa-a5c1-1d39b8d8b069','書翠波亭','劉才邵','宋','宋诗','song-poetry','','[]','人言止水燭鬢眉，便向靜處淘真機。',80,'全唐诗/poet.song.96000.json','["人言止水燭鬢眉，便向靜處淘真機。", "那知怒濤恣澎湃，中有未嘗搖動時。", "虛亭恰當隱貼處，不愁景物驕莫隨。", "晴嵐迷空香霧重，不論朝暮都相宜。", "直須會取箇中意，閑看溪邊鷗鷺飛。"]'),
('c0b01d26-584c-4e44-8763-160c20668e85','遊風穴','劉才邵','宋','宋诗','song-poetry','','[]','清曉意不愜，驅車向城東。',176,'全唐诗/poet.song.96000.json','["清曉意不愜，驅車向城東。", "行行歷谿谷，遂到青蓮宫。", "古塔跨虛碧，長橋卧晴虹。", "水落見谿骨，雲開露秋容。", "疏竹搖晚翠，寒花綴幽叢。", "訪古但丘壑，令人氣填胸。", "登覽未覺久，山遮半輪紅。", "白煙生汝水，横空正濛濛。", "緬懷道化盛，山高水無窮。", "坐令千萬世，矯首希高蹤。", "浙江黄面子，應纖開禪宗。", "妙哉鐵牛機，誰敢當其鋒。", "杖林山下竹依舊，金沙灘頭人已空。", "可憐高坐寂寥久，蕭蕭古木號悲風。"]'),
('e7d43a47-15d2-4f89-929e-932f92cb8bc7','慈寧壽慶曲','劉才邵','宋','宋诗','song-poetry','','[]','鳳凰山下瑞煙濃，湖海凝光秋正中。',384,'全唐诗/poet.song.96000.json','["鳳凰山下瑞煙濃，湖海凝光秋正中。", "流星驛騎如飛電，來奏吉語聞天聰。", "龍舟移棹渡淮水，金車歸來長樂宫。", "詔書即日嚴法駕，出迎不憚勞清躬。", "曉鐘傳箭金門開，翠華赫弈從天來。", "繡旗拂雲勢偃蹇，綵仗照日光徘徊。", "漢宫威儀重烜赫，天宇披豁無氛埃。", "里閭縱觀萬人喜，秋城一變成春臺。", "高檣影轉龍負舟，平河清淺乘安流。", "臨平山色映雕輦，草木光榮佳氣浮。", "龍輿照耀金開鱗，御幄對起高連雲。", "歡聲喜氣傳萬里，盛事創見超前聞。", "煌煌儀衛迴丹闕，萬騎千艘乘曉發。", "道傍觀者皆鼓舞，帝力難名但欣悅。", "由來孝弟能通神，聖主成功在得人。", "誰云高高難感格，一德協謀天所因。", "皇帝盛德動天地，丞相嘉謀無比倫。", "昭然獨斷納遠策，重見元愷承華勛。", "聖情孜孜天不倦，宫中預建慈寧殿。", "繡栱雲楣藏盛儀，廣庭層陛宜清宴。", "寶盛珍匣龍蟠拏，冊寫鴻猷金煥爛。", "臣民觀聽盡傾聳，文物聲明信葱蒨。", "共知睿意已潛達，行見天心從宿願。", "果然悔禍答清衷，信使交馳鄰好通。"]'),
('c87e2c15-37cc-4021-b482-b8c22a67deea','暮春苦雨','劉才邵','宋','宋诗','song-poetry','','[]','鳴鳩逐婦蟻移窠，衆山戴帽垂雲幕。',192,'全唐诗/poet.song.96000.json','["鳴鳩逐婦蟻移窠，衆山戴帽垂雲幕。", "雨從中夜猛如傾，春晚東風真作惡。", "竹響偏能䀨睡餘，曉寒無奈侵衣薄。", "可惜殘花飛欲盡，賴有蒼苔襯初落。", "瓦溝散水作疏簾，蟲網綴珠挂瓔珞。", "波穿石罅泛瀧瀧，烟接水光低漠漠。", "秧抽翠毯競穿泥，蠶戀遲眠未登箔。", "求桑操耒田家急，久雨欲晴人意各。", "稍見天邊嵐翠收，已覺林間鳥聲樂。", "心懷莫悦厭蒸濕，眼界方期便開拓。", "但得高風恣性吹，不怕歸雲無處著。", "明朝準擬看溪山，已辦瘦笻與芒屩。"]'),
('e863d352-c5f2-4a3b-a35e-a4e4f632a9f3','中秋夜館中會飲','劉才邵','宋','宋诗','song-poetry','','[]','世情共惜隔年期，豈堪四野陰雲垂。',176,'全唐诗/poet.song.96000.json','["世情共惜隔年期，豈堪四野陰雲垂。", "幾處紅樓歌吹起，窺簷初訝寒光遲。", "那知細雨復侵夜，燈外蟾影還微微。", "是時冊府陪諸彥，聊復杯酒相追隨。", "地嚴更覺秋氣凈，雨過還有涼風吹。", "忘懷自得觴詠趣，真賞不爲陰晴移。", "月豈無光忌全露，雲亦有意藏餘輝。", "雲輕影薄自清絕，不減永夜天河詩。", "人言蚌胎因吸月，隨月明暗占盈虧。", "詔詞丁寧斥金翠，豈更漉海求珠璣。", "月光不露乃天意，正是君王崇儉時。"]'),
('b060e710-e120-4b8e-a916-83af6bc2963d','次韻寛夫題王自然參議江閣','劉才邵','宋','宋诗','song-poetry','','[]','橘州部曲奴千頭，倚檻應猶憶故丘。',64,'全唐诗/poet.song.96000.json','["橘州部曲奴千頭，倚檻應猶憶故丘。", "胸中耿耿挂秋月，坐閱世故如星流。", "誰能令公還饜事，且脫荷衣藏篋笥。", "定将奇策收桑榆，不似書魚老文字。"]'),
('05292e46-42a8-4d73-912c-d493c3c5270d','燈下見梅花','劉才邵','宋','宋诗','song-poetry','','[]','沉沉永夜成清聚，翠箔護寒風力住。',176,'全唐诗/poet.song.96000.json','["沉沉永夜成清聚，翠箔護寒風力住。", "疏響遥傳玉漏聲，華燈屢續蘭膏炷。", "瓊枝亭亭浸清泚，浮香漠漠輕來去。", "晴虹神彩正超絕，素練肌膚無點污。", "體輕難便有行雲，光透只應緣飲露。", "珠宫宴罷恰歸時，瑤臺月下相逢處。", "斜輝耿耿照冰姿，清影重重雜香霧。", "除著參差仙子似，謾矜淡竚人間誤。", "但令綺席借餘光，誰管玉顔生暗妬。", "竹外斜枝太幽獨，溪邊寒影饒高趣。", "何當盡取貢玉堂，免使空傷碧雲暮。"]'),
('bace17e2-5ac4-4e02-b7a6-7d6c4b3b1974','波光亭','劉才邵','宋','宋诗','song-poetry','','[]','方塘溶溶貯清泚，中有高亭兀然起。',208,'全唐诗/poet.song.96000.json','["方塘溶溶貯清泚，中有高亭兀然起。", "問公名亭意若何，公笑不言搖麈尾。", "知公直是我輩人，此意不凡端有以。", "亭本無風水亦靜，風落波生偶然爾。", "山搖宿靄迷粉黛，鶯啼晚柳明金翠。", "涔涔涼氣侵語笑，漠漠飛嵐到襟袂。", "冰痕搖度簾痕曲，曉日初升窗影碎。", "幾箇沙鷗亂夕陽，一段餘霞浴晴綺。", "可憐巽坎固多態，轉續無窮難僂指。", "憑欄若隨根境轉，目不暇瞬亦勞矣。", "誰知主人心湛然，道骨嶔嶔照雲水。", "本來非靜亦非搖，坐觀物態聊爾爾。", "更須說似登臨人，認取鬧中真自己。"]'),
('2f4ec5db-619e-4315-98fc-f677b94f2252','題容安閣','劉才邵','宋','宋诗','song-poetry','','[]','湧地千楹排鏤磶，朱樓跨空半天赤。',64,'全唐诗/poet.song.96000.json','["湧地千楹排鏤磶，朱樓跨空半天赤。", "鬼神下瞰防禍機，坐使心猿困跳躑。", "豈知高人心獨遠，不覓贏餘但容膝。", "寄傲南窗一事無，時見歸雲度晴碧。"]'),
('0fd62498-9eb5-4047-832a-5aa1701c6a04','代簡謝載仲弟惠黄雀牛尾狸柑子','劉才邵','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','南昌珍品誇牛尾，肥膩截肪玉堪比。',80,'全唐诗/poet.song.96000.json','["南昌珍品誇牛尾，肥膩截肪玉堪比。", "臨川甘實敵洞庭，光照霜林香染指。", "黄雀披綿亦同到，厚意不凡端有以。", "雪晴晚日懸清光，爲君設席傾瑤觴。", "醺然隱几結清夢，坐覺春風生池塘。"]'),
('b0e9ffa6-6a38-478d-8bc7-ca7427e76686','題從兄和仲國香軒','劉才邵','宋','宋诗','song-poetry','','[]','靈均志與日爭光，收拾香草供篇章。',128,'全唐诗/poet.song.96000.json','["靈均志與日爭光，收拾香草供篇章。", "高冠奇服事修潔，辛夷爲楣葯爲房。", "滋蘭九畹多不厭，似更有意憐幽香。", "當時楚俗寶蕭艾，誰知紉佩芙蓉裳。", "高情如兄能有幾，封植靈根當砌傍。", "芝英玉樹宜相映，清芬宛轉隨風長。", "結根得所異晚菊，不向籬邊混衆芳。", "早晚知音垂採摘，玉盤霞綺升中堂。"]'),
('b8cba60b-9f20-4231-b2d0-1d3564d165d8','玉笥山超然堂','劉才邵','宋','宋诗','song-poetry','','[]','三山遠在虛無間，還有勝境居人寰。',224,'全唐诗/poet.song.96000.json','["三山遠在虛無間，還有勝境居人寰。", "瓊樓貝闕知何許，統領分治皆仙官。", "名稱等級已素定，載在玉書垂不刊。", "能兼洞天與福地，唯有玉笥餘難攀。", "憶昔扁舟中夜過，白月滿空星斗寒。", "起登船背聊一望，攙天但見青孱顔。", "重巖衆壑眇難辨，福庭想像依層巒。", "那知虛堂宅幽邃，蕭爽不容塵滓干。", "超然物外亦不惡，要當心境俱清閑。", "真機還向靜中起，不礙默朝窺九關。", "我生本來世味薄，欲養鉛汞成金丹。", "也知上界足官府，人間遊覽堪盤桓。", "如聞方平持玉節，似欲歷按諸名山。", "相逢不問蓬萊事，試與乘風去共看。"]'),
('8a41ab89-fe71-4521-9ee2-2ed6e0458b28','題清軒','劉才邵','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','大江之源發乎岷山，蓄餘怒於瞿塘。',201,'全唐诗/poet.song.96000.json','["大江之源發乎岷山，蓄餘怒於瞿塘。", "混衆流以東下，渺翻空而湯湯。", "天風下兮蹵縞練，白浪如山衝馬當。", "邈不知其所止，接雲海之茫茫。", "魚龍並育細不遺，龍驤萬斛浮若飛。", "噴雪霓兮散霧雨，功利浩博難盡窺。", "眷彼溪谷流，夫豈不清泚。", "飛鷗墮影魚依空，水濺濺兮石齒齒。", "景趣信佳傷險狹，纔可濯纓兼洗耳。", "清乎清乎期及物，清不能容徒潔已。", "知公博覽眼不寒，築室雖小識量寛。", "聖朝撥亂收群策，難擅丘壑眈雲山。", "願公爲萬里之長江，勿作細流之驚湍。"]'),
('4aeed00a-c381-4766-894c-3d6c97b7bd5d','題琴風亭','劉才邵','宋','宋诗','song-poetry','','[]','絲桐能寫風入松，爭如種松挽天風。',64,'全唐诗/poet.song.96000.json','["絲桐能寫風入松，爭如種松挽天風。", "蒼髯玉骨已奇絕，清音激越還無窮。", "宫商一日古意淡，坐使瘦筝慚未工。", "快哉此景不可負，時邀佳客傾金鍾。"]'),
('3371b71d-da58-4b13-81ad-a9a95c3a4af4','題李仲孫佩軒','劉才邵','宋','宋诗','song-poetry','','[]','華堂壓雲排柱磶，堂背開軒看青璧。',160,'全唐诗/poet.song.96000.json','["華堂壓雲排柱磶，堂背開軒看青璧。", "鏤螭石斗貯芳根，綠葉裁雲凈如拭。", "秋風吹空夜正涼，曲瓊掛簾放香入。", "小鞋踏月傍幽叢，霧氣籠寒髻鬟濕。", "主人才具超常流，竟體芳香非外襲。", "不應便爾學紉蘭，芰製荷衣向泉石。", "詔書屢下言路開，黼坐憂勤方仄席。", "綠章聞早叩天關，坐使青雲生咫尺。", "垂紳鳴玉近瑤墀，舊隱煙霞從寂寂。", "卻須爲續北山移，細說幽芳恨輕擲。"]'),
('cdc2ded9-7428-4f19-a221-e6f01da7d80a','題和仲兄碧鮮軒','劉才邵','宋','宋诗','song-poetry','','[]','竹軒居士全天真，胸中不著纖毫塵。',144,'全唐诗/poet.song.96000.json','["竹軒居士全天真，胸中不著纖毫塵。", "泠然孤照更洞徹，炯如月白垂秋旻。", "紛紛俗物不到眼，但延修竹爲佳賓。", "一談不交意且喻，真契豈復煩云云。", "清風高節自相許，爽氣曉接西山雲。", "一般奇絕靜中覺，細香風過時時聞。", "端能令人看不足，乘興數來還更新。", "欲掃寒梢掛高壁，不惜畫材無此人。", "嫦娥卻解窺窗戶，時與此君傳喜神。"]'),
('65b7044a-a4f2-412a-9946-bc166c1bf842','方景南出示館中諸公唱和分茶詩次韻','劉才邵','宋','宋诗','song-poetry','','[]','欲知奇品冠坤珍，須觀乳面齧甌脣。',176,'全唐诗/poet.song.96000.json','["欲知奇品冠坤珍，須觀乳面齧甌脣。", "湯深不散方驗真，側瓶飛瀑垂巖紳。", "色香味觸未離塵，清意元自超空輪。", "靈臺賡唱格力勻，皎如冰蘂夾霜筠。", "高詞險韻愁鬼神，雄辨逸藻回冬春。", "天教飛步出凡倫，窺闖天巧終不真。", "閩山蒼翠倚高旻，地靈氣淑儲芳津。", "從來霑溉浩無垠，修貢先期還更新。", "諸公才具足致身，況復感會方逢辰。", "邇英講讀優儒臣，玉甌珍賜從中宸。", "自憐衰鬢真陳人，欲覓漁舟向水濵。"]'),
('6e931bc0-0a33-4660-97a1-961053182d9d','題李平國義方堂','劉才邵','宋','宋诗','song-poetry','','[]','渥洼異産超駛騠，逸態崷崪精權奇。',160,'全唐诗/poet.song.96000.json','["渥洼異産超駛騠，逸態崷崪精權奇。", "軼埃蹶塊儻未免，欲駕鑾輅終難爲。", "迺知人家良子弟，亦或豪逸難羈縻。", "調柔折服就繩矩，他日致遠夫何疑。", "李侯灑落富清製，頃刻滿紙填珠璣。", "建堂教子意不淺，欲使行能無少虧。", "會須骨格早成就，不與凡足爭先馳。", "正如名駒已服習，使堪寶校金黄羈。", "周旋進退悉中節，追風逐電隨所施。", "朝燕暮越尋常事，還看弄影舞瑤池。"]'),
('b6845b27-4d98-41f5-8fe6-2ee571fdcb0c','題段成之粟庵','劉才邵','宋','宋诗','song-poetry','','[]','毗耶城中無垢師，丈室僅似蝸牛廬。',128,'全唐诗/poet.song.96000.json','["毗耶城中無垢師，丈室僅似蝸牛廬。", "三萬二千師子坐，同時容納無贏餘。", "圎通境界不思議，一顆玄入隨卷舒。", "先生從來道眼具，深入不二離圏模。", "粟庵宴坐觀萬法，不以誕幻驚群愚。", "炯如白月挂圎碧，千江分影冰輪孤。", "乃知芥子納須彌，妙用豈以常形拘。", "惜哉山人空索價，不悟心藏萬卷書。"]'),
('c1f51394-ecfd-4c46-ae12-6f6c64beb826','爲李邦臣題叢桂堂','劉才邵','宋','宋诗','song-poetry','','[]','君家外孫吾祖母，生長舅家曉圖史。',304,'全唐诗/poet.song.96000.json','["君家外孫吾祖母，生長舅家曉圖史。", "平時教誨子與孫，深念昔人立門戶。", "因言仙李傳芳遠，外氏且從中允數。", "天将善慶萃其門，盛事老人目親覩。", "七寶輪高風露清，丹枝翠葉紛旁午。", "玉階迢迢無路通，詩書爲作冲天羽。", "從子傳孫世已稀，兄弟同攀復如許。", "太守好賢爲出迎，冠蓋如雲沸簫鼓。", "名聲藉甚里閭傳，豈假老人爲重舉。", "區區此意豈有他，欲汝讀書轉勤苦。", "汝家先世不乏人，折桂里名因汝祖。", "一時聲價動場屋，相繼登科亦四五。", "才豐報嗇理難曉，在其子孫豈虛語。", "良農不爲旱輟耕，多稼終聞飽倉庾。", "親姻中外貴相輝，莫向明時守環堵。", "慈顔幽隔三十年，歲月堪驚如驟雨。", "追惟義方不敢墜，到今婚友情相與。", "還喜君家世益昌，芝玉煌煌照庭宇。", "月娥賸與長孫枝，不厭頻頻來折取。"]'),
('413a5020-6bc0-4f5f-9666-a76c63e6d25d','爲劉端禮題翠微堂','劉才邵','宋','宋诗','song-poetry','','[]','春陰涔涔透方礎，春雲濛濛閣殘雨。',368,'全唐诗/poet.song.96000.json','["春陰涔涔透方礎，春雲濛濛閣殘雨。", "烟中梅子未傳黄，坐使名園清興阻。", "誰料天公亦會事，報晴逼曉聞街鼓。", "來遲不見碧桃開，滿洞翠陰籠牖戶。", "杖藜徐步穿芳徑，芝术丰茸雜蘭杜。", "含笑無心迷下蔡，酴醾分清從月宇。", "共占餘春動地香，香地滿園無處貯。", "步芳橋長清浸闊，花影波光媚欄柱。", "漫天柳絮爛不收，點水荷錢疏可數。", "行行直到翠微堂，簾幕風輕雙燕舞。", "梢雲何啻千竿竹，鑠石空傳三伏暑。", "遠碧巖巖太超絕，高標凜凜如相許。", "堂陰路轉經古城，茅屋數間營别墅。", "白石清溪自瀟灑，閑花野草無行伍。", "歸來還復坐達軒，石鼎酪奴煩旋煮。", "因君指似壁間詩，知是昔人觴詠所。", "駕麟跨空窺理窟，搜抉幽奇呈脉縷。", "當時景物怯劖鐫，造化小兒遽相苦。", "海山茫茫風馭遠，人世空驚如插羽。", "幸哉有子續奇芬，新編還見驚人語。", "才大終嬰珪組累，身閑好作林塘主。", "高情隨處即逍遥，豈向明時分出處。", "早晚乘風肆遠圖，九萬雲程看一舉。"]'),
('40dc0771-54fd-4c7e-9256-47114ee48bee','堆勝樓運幹許永之修','劉才邵','宋','宋诗','song-poetry','','[]','高城倚江憑峻址，層樓卻憶高城裏。',272,'全唐诗/poet.song.96000.json','["高城倚江憑峻址，層樓卻憶高城裏。", "迢迢飛磴出塵氛，繡栱朱欄照江水。", "四面雲山千萬疊，清原卻與黄原接。", "碧螺宛轉峰最奇，透色連雲俱岌嶪。", "樓前正對白鷺洲，翠虯夭矯横中流。", "回看井邑亦華盛，碧瓦鱗鱗光氣浮。", "崛起凌空何壮哉，歲久剥蝕霾風埃。", "高情一見爲嘆息，因循恐致奇標摧。", "才刃由來有餘地，葺舊扶傾真復易。", "坐令風月爲清新，還使江山增勝氣。", "公家列屋人如玉，清唱不須吹管逐。", "沉沉清夜繡筵開，垂下珠簾隔銀燭。", "放教簾外水仙聽，傳作仙家步虛曲。", "識高器遠追前人，不獨文采風流存。", "憑欄縱目莫厭數，即去飛騰登要津。", "老來自覺詩思慳，況此清絕形容難。", "恐公他時懷舊賞，猶堪展作畫圖看。"]'),
('30526ab2-d89d-48f2-b8af-d72a53eba1b1','德元盛暑中觀刈稻憩于茂林間愛其繁密因加芟治名曰綠陰軒以詩相示戱爲作此','劉才邵','宋','宋诗','song-poetry','','[]','焦先但作蝸牛廬，真與蝸牛殻相似。',320,'全唐诗/poet.song.96000.json','["焦先但作蝸牛廬，真與蝸牛殻相似。", "當時雖省營築勞，把茅蓋頭已多事。", "珏溪樵客意高遠，幾欲巢居如上古。", "茂林深處即幽居，樹作簷楹根作礎。", "經始全資木居士，竹夫人來共胥宇。", "刪繁聊藉刈禾鐮，補罅不須修月斧。", "山中熊館作比鄰，夢裏蟻城真别墅。", "葱帳不容逋客歸，葯房閑詠騷人語。", "月鈎斜挂褰雲箔，霞綺高長當朱戶。", "瑤砌無塵透曉霜，珠簾隔霧連天雨。", "洞門雖開亦非開，當空鑿出高崔嵬。", "憑虛公子見之喜，便約亡是公同來。", "更容明月作不速，賓主談辯聲如雷。", "畫空題詩記真賞，要與幽人作牓様。", "是中無欠亦無餘，一任傍人說半藏。", "莫言基址真牢固，夜半負之人莫悟。", "玉川膽怯不須論，覷著地皮捲不去。", "須防毗耶無垢師，擎向手中便進步。", "要當石頭具道眼，本自無來今不住。", "饒他百倍有神通，到此一籌無用處。"]'),
('16c9c850-d960-4c74-899b-17e5935610e5','陪同舍登望越亭觀潮','劉才邵','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','吳越中分江一派，兩岸溪山掃濃黛。',304,'全唐诗/poet.song.96000.json','["吳越中分江一派，兩岸溪山掃濃黛。", "茫茫雲海迷烟空，方諸宫外天爲界。", "潮波吐納誰使然，欲到先衝海門隘。", "江淺洲長礙奔放，勢益洶洶怒而噫。", "方看隱起玉堤横，忽復飛騰雪花碎。", "高浪翻空雷吼怒，黑沙崛起雲崩壊。", "山岳傾頹驚炫轉，鯨鵬摩戛舞幽怪。", "大聲吹地恣淙淙，餘響振天轟磕磕。", "恍如白帝盛羽衛，風攪旌幢紛斾斾。", "從以百萬虎與貔，組練精明呼聲大。", "世間奇觀獨雄絕，坐令耳目俱鬆快。", "津亭晚靄動遐想，樽酒相歡信良會。", "木落山空秋氣高，情多思遠人寰外。", "杜老扶桑有遺恨，韓子鯨魚思飽膾。", "豪氣英風終不泯，海色天容自相對。", "同來俱是蓬山侣，蘂簡玉書名姓在。", "東遊不用浮海航，仙驥追風雲作蓋。", "卻須從此排閶闔，叢鈴響雜飛霞佩。", "通明殿裏綴仙班，官府縱多君莫悔。"]'),
('1e70340e-d824-4d9d-b06e-4dc0ad114eed','贈夏侯子美養心居士','劉才邵','宋','宋诗','song-poetry','','[]','漢家恢儒成治功，獨與三代同高風。',192,'全唐诗/poet.song.96000.json','["漢家恢儒成治功，獨與三代同高風。", "當時經術傳家者，大小夏侯名譽崇。", "鄴都雄圖方鼎峙，英俊乘時盡風靡。", "坐使當途基業成，才如伏波能有幾。", "公家先世不乏人，詩書韜略傳清芬。", "文取賢科武分閫，爽氣英姿今尚存。", "前人清白今人繼，方得家聲終不墜。", "脩身大要在養心，公以自名深有意。", "世人但知縱多欲，盈壑填溪不知足。", "盡取豪華供目前，幾人更戒前車覆。", "如公此意具真識，不似世人長荆棘。", "寸田盡著子孫耕，會見慶餘由善積。"]'),
('8b0f458e-a6c8-4db0-b6c7-b7e5ba19920c','贈劉道正','劉才邵','宋','宋诗','song-poetry','','[]','紅輪曉上扶桑東，五雲正繞丹琳宫。',224,'全唐诗/poet.song.96000.json','["紅輪曉上扶桑東，五雲正繞丹琳宫。", "臨芳閣外霜筠合，碧桃溪邊香露濃。", "是時初喜識公面，小閣清香飛大篆。", "整冠共讀御書碑，翠琰填金光炫轉。", "朝野歡娛氣清淑，宫中聖人親授籙。", "雲軿白晝臨瑤壇，來聽新翻步虛曲。", "誰知世故多盈缺，況復年華如電掣。", "相逢不擬說前事，北望傷心墮清血。", "憶從弱歲遊都城，相知滿眼如繁星。", "今來寥落似将曉，知有幾點懸青冥。", "公如長松出霜林，童顔不受歲月侵。", "我亦從來世味薄，三宫鉛汞曾留心。", "知公鍊骨骨已輕，知公養丹丹已成。", "要看恢復見清平，且作人間白石生。"]'),
('34dd68e7-6fb7-480e-9e4d-2671e9e49e71','贈吾彦逸','劉才邵','宋','宋诗','song-poetry','','[]','山上龍泓標水府，方欲往遊逢雨阻。',304,'全唐诗/poet.song.96000.json','["山上龍泓標水府，方欲往遊逢雨阻。", "多謝山人會人意，約束群仙住朝雨。", "遊氛洗盡天宇空，山色湖光相媚嫵。", "就龍覓水酌清耳，雪山醍醐異凡乳。", "是中冷煖已自知，豈更将心求佛祖。", "流連清境不知晚，歸來已踏鼕鼕鼓。", "年兄笑我太清生，旋掃風軒置樽俎。", "欲将歌管聊相温，爲出紅粧唱金縷。", "不信人言竹勝絲，昵昵朱絃将手語。", "更長語笑益諠譁，快飲不勞觴插羽。", "因思同榜七百人，翠琰鏤名藏梵宇。", "邇來知有幾人在，相遇百中無四五。", "與君是時俱少年，快馬輕衫冒塵土。", "豈知重上君子堂，歲月驚人不堪數。", "相看斑鬢點秋霜，況復中間多齟齬。", "但餘契義敵杉松，青青不受冰霜侮。", "自憐憂患落窮山，冊府不應重接武。", "流離更覺主恩厚，獨慚未有涓埃補。", "因君感激歌此詩，滿酌玉巵須對舉。"]'),
('cbff2e36-6684-42c2-8882-c88742780537','和彭伯莊韻奉酬彭公達','劉才邵','宋','宋诗','song-poetry','','[]','龍媒昔是渥洼生，培塿無松陸無萍。',320,'全唐诗/poet.song.96000.json','["龍媒昔是渥洼生，培塿無松陸無萍。", "古人此語豈欺我，華胄非遥須細聽。", "奉常詞源隘三峽，倒流豈復論千瓶。", "句枝到手詩已就，四坐俯首甘罰觥。", "蒼苔虎跡雖善戲，諷戒曲盡詩人情。", "喜遇從事復超詣，重名不減平如衡。", "汝南人物亦云幾，高者難隨月旦更。", "到今公議牢不破，心雖不貪敵無勍。", "才高位下衆所惜，善慶源長流更清。", "風流文采終不泯，還復鍾此千人英。", "清言自可屈奉倩，賦力真能凌正平。", "干時直欲石投水，得位公不當慚卿。", "掃除群碎宅平坦，擺落浮僞存精誠。", "兼全衆美信如使，未許爰絲堪作兄。", "天遣名駒諳險隘，夫豈久困終能鳴。", "行當策足恣高步，徑取萬石寧躬耕。", "嗟予素懷丘壑趣，高情遠致誰服膺。", "隨流竊食聊復爾，取譽懶能工賦營。", "新詩有意相推激，第恐無實難叩榮。", "觀公豈是長貧者，便欲從此看超騰。"]'),
('a1e57875-29b6-4a6a-a437-16f7af973725','題仲兄和仲畫虎圖','劉才邵','宋','宋诗','song-poetry','','[]','寒雲韜日風搖山，鶻鵃鳴噪飛復還。',243,'全唐诗/poet.song.96000.json','["寒雲韜日風搖山，鶻鵃鳴噪飛復還。", "黄茅枯木轉蕭瑟，有虎引子來其間。", "一兒儘有食牛氣，跑空人立肩侵耳。", "一兒就乳方低身，只欲攙前不知跪。", "大虎垂頭蹲更促，吐舌宛如牛舐犢。", "豈知愛子物皆然，但教生獰貪獸肉。", "原注退之城南聯，句云心貪敵無勍。", "從來倚伏理難齊，一朝力盡還悲啼。", "攫頭銜尾遭熊豹，有眼誰云百步威。", "君家畫軸雖填委，難似此圖有深旨。", "欲令觀者知觀身，不在丹青畦徑裏。", "君不見漢家豪奪聚斂臣，乘時擊斷屠齊民。", "磨牙利吻事膏血，千載想見猶酸辛。", "深文厚斂雖同苦，以酷視貪不猶愈。", "可憐當路盡豺狼，獨使甯成名乳虎。"]'),
('c625be64-e9a8-4c01-8a19-f761840beeaa','夜夢一道人見訪相與語甚久頗及宗乘中事因戲之曰仙家亦學佛耶其人笑曰仙佛豈有二哉覺而異之作詩紀其事','劉才邵','宋','宋诗','song-poetry','','[]','北風吹雲肅天宇，蕙帳寒生月當戶。',208,'全唐诗/poet.song.96000.json','["北風吹雲肅天宇，蕙帳寒生月當戶。", "頹然就枕睡思濃，魂夢悠悠迷處所。", "仙宫勝士肯見臨，促席從容陪軟語。", "自言本事清虛君，學佛求仙兩無阻。", "雲軿白日降遥空，天衣飄飄袖輕舉。", "方諸宫深雲海闊，金碧禪房隔烟雨。", "與君粗有香火緣，聊復東來相勞苦。", "方遊崑閬還無期，君住世間須善爲。", "塵勞足厭不須厭，等是實相夫何疑。", "前身自是塵外人，端爲世緣縻此身。", "重聞妙語發深省，若更離塵佛亦塵。", "方平羽節何時來，道宫佛廟隨煙埃。", "未須苦說揚塵事，東海波聲正似雷。"]'),
('ab06032d-45b9-4680-b67c-8d500e78056b','霽虹亭','劉才邵','宋','宋诗','song-poetry','','[]','江流滚滚青於藍，山如陣馬方䟃𧽼。',256,'全唐诗/poet.song.96000.json','["江流滚滚青於藍，山如陣馬方䟃𧽼。", "景趣雖從開闢有，登覽正賴人謀參。", "濟川亭古傷險狹，石岸缺落呈嶔嵌。", "可憐眼界方冗雜，風月爲之久不堪。", "使君才高藴機鑒，妙思能發神所緘。", "異時一見已經意，施設先後難相攙。", "政成将去覲丹闕，一新棟宇何耽耽。", "就增亭閣跨空闊，徑從人境超塵凡。", "波光挾日動飛栱，簷影窺江凌過帆。", "欄危更覺明月近，浪湧正值秋風酣。", "螺峰晚靄助遥碧，鷺渚歸翼穿晴嵐。", "東望青原森欲動，祖意豈復勞窮探。", "夜深定有水仙集，霓裳練帨垂毿毿。", "雲烟態度日夕異，詞客賦詠勞彫劖。", "公歸指日登華要，雍容鳴玉横犀篸。", "湖山高會駐清賞，尚應回首江之南。"]'),
('0aa1dfdd-5278-441e-9945-261819feff70','貢士張智觀登禾山白雲峰絕頂愛其清曠乃結庵辟穀凡十年後遂落髮法名永元紹興三年夏訪予於城中具道所以出家及携詩東遊之意因作是詩以餞之','劉才邵','宋','宋诗','song-poetry','','[]','白雲山人機鑒高，了見萬法棲秋毫。',192,'全唐诗/poet.song.96000.json','["白雲山人機鑒高，了見萬法棲秋毫。", "龜腸蟬腹耐清苦，空山坐聽鼪鼯號。", "無心索價驚衆耳，尚恐名出終難逃。", "一朝解去薜蘿服，鬋剔須髮披方袍。", "黄龍宗旨人難湊，涓滴不容消息漏。", "一到禾山謁老方，全機不露三關透。", "城中軍馬正紛紛，紅塵漲空日色瘦。", "問師觸熱有底忙，云向疏山聊宿留。", "蒐奇獵怪窮端倪，詩胆大於身數圍。", "勿憂平淡少人愛，此去定逢韓退之。", "年來世味種種薄，文字習氣黏如黐。", "自信文通才未盡，猶堪重擬碧雲詩。"]'),
('6daf28db-d7f2-428c-a504-2578aafb9d97','次韻王民瞻贈覺梵二首  其一','劉才邵','宋','宋诗','song-poetry','','[]','腹稿欲成聊假卧，寒松疏磬仍相左。',112,'全唐诗/poet.song.96000.json','["腹稿欲成聊假卧，寒松疏磬仍相左。", "不容開府占清新，雲裏江梅萼初破。", "奇芬還似暗香浮，全勝光風泛蘭些。", "玉川昔訪長壽寺，石壁留題如此作。", "珊瑚炫轉光奪目，含曦一讀忘饑餓。", "便堪高躡詩将壇，紛紛誰可克參佐。", "韋莊豈免贈巾幗，格嫩更遭脂粉涴。"]'),
('cce322dc-2a48-4ae8-956d-2113845402d6','次韻王民瞻贈覺梵二首  其二','劉才邵','宋','宋诗','song-poetry','','[]','脩竹幽蘭伴高卧，新詩不待江山左。',112,'全唐诗/poet.song.96000.json','["脩竹幽蘭伴高卧，新詩不待江山左。", "開緘快讀耳目醒，睡魔奔迸愁城破。", "懸知大手千人英，且擬二招吟只些。", "暫時雖現宰官身，百事疏慵無所作。", "郊居未敢厭岑寂，且烹杞菊充朝餓。", "勸兄不須夢惠連，鄙句安能婉如佐。", "冰壺玉椀幸無瑕，莫使遊塵得輕涴。"]'),
('484be027-6c22-41e5-a75c-abb6cd13cf8b','靈壁石','劉才邵','宋','宋诗','song-poetry','','[]','堅脆殊形俱是幻，要當盡付空花觀。',128,'全唐诗/poet.song.96000.json','["堅脆殊形俱是幻，要當盡付空花觀。", "其餘空色兩非真，習氣從他不須斷。", "靈壁磬材如黑玉，歲久取多岸爲谷。", "問君何從得堅質，數尺嶔𡼭心賞足。", "新詩俊如霜鶻拳，攬取物象神機圎。", "援毫一揮不停手，巖壑意態何森然。", "如聞駛舟行日近，不得隨舟無少恨。", "夜敲清響哦新詩，定有水仙簾外聽。"]'),
('efaf966f-92c1-4c58-89d5-c00b5a38ad5a','次韻鄭守蠟梅二首  其一','劉才邵','宋','宋诗','song-poetry','','[]','靈根何年離衆香，色相全似金容黄。',128,'全唐诗/poet.song.96000.json','["靈根何年離衆香，色相全似金容黄。", "曉姿熒熒炫寒月，夜氣耿耿凌風霜。", "天真何曾資外飾，坐笑塗額誇宫粧。", "廣平當時應未見，獨爲梅花回鐵腸。", "賴有花仙覓奇句，東坡著意憐孤芳。", "詩中寫就無遺巧，安用學花熬蜜房。", "多情偏愛被花惱，聞香心醉難禁當。", "況復低垂深有意，欲教醉賞傾瑤觴。"]'),
('d2391a7f-214b-41d8-8c49-5a7e2492c50e','次韻鄭守蠟梅二首  其二','劉才邵','宋','宋诗','song-poetry','','[]','忍冷衝寒破霜萼，爲報春園行灼灼。',80,'全唐诗/poet.song.96000.json','["忍冷衝寒破霜萼，爲報春園行灼灼。", "黄輕正欲金波助，斜抹寒梢轉簷角。", "香隨風遠自析醼，豈待嗅芳方辟惡。", "不逐嫦娥向月奔，芳桂相望空斷魂。", "新詩清絕慰幽獨，勝似對月開綠樽。"]'),
('711d45df-f0cd-41c3-86e8-a53f004ee6ac','詠蠟梅呈李仲孫','劉才邵','宋','宋诗','song-poetry','','[]','霜鋪鴛瓦茸茸白，紅日破寒舒曉色。',176,'全唐诗/poet.song.96000.json','["霜鋪鴛瓦茸茸白，紅日破寒舒曉色。", "小枝斜傍碧闌干，光透香融嬌欲滴。", "緣何便證紫金容，勝妙從來衆香國。", "時世梳粧嫌不稱，豈假嫩黄拂宫額。", "清潤疑和玉髓膏，鮮妍似鍊鸞蜂液。", "團香掠蘂太辛勤，堪笑蜜房屯羽客。", "更有一般超絕處，畫史儘工描不得。", "漏板丁丁夜向闌，金波浸影寒光溢。", "賞奇自昔屬多情，況復南人多未識。", "恰及開時寄一枝，後時便恐香難拾。", "須藉高才與發揚，妙句收歸花萼集。"]'),
('3cf432d0-7b83-4fe8-9f44-0d8e32142519','謝蕭元隆賢良惠小團','劉才邵','宋','宋诗','song-poetry','','[]','紫鸞琢璧輕雲轉，幾年隔闊今重見。',68,'全唐诗/poet.song.96000.json','["紫鸞琢璧輕雲轉，幾年隔闊今重見。", "睡魔膽落不待降，氣壓月團三百片。", "飲罷清風生兩腋，三山去人疑咫尺。", "便欲携公封事叩玉扃，爲問蒼生幾時得蘇息。"]'),
('6bcc1144-8ead-4628-be97-b6b6898e31b9','聽寶月上人彈桃源春曉','劉才邵','宋','宋诗','song-poetry','','[]','桃源曉色春茫茫，花氣撲人和露香。',176,'全唐诗/poet.song.96000.json','["桃源曉色春茫茫，花氣撲人和露香。", "翠波溶溶泛晴陽，瓊樓半露非煙長。", "霓旌鸞佩雜花光，花光深處開琳房。", "金鯨夭矯寫霞漿，雲璈清響何琅琅。", "綠雲不動山蒼蒼，酒闌月影侵迴廊。", "千年過眼直尋常，蓬萊清淺海上桑。", "道人妙手能逢場，朱絃寫出水雲鄉。", "坐令遠意入八荒，泠然風馭隨雲翔。", "仙人迎笑從西廂，頗怪别來塵世忙。", "飛霞仙衣雲錦裳，朝真相與高頡頏。", "卻笑退之情未忘，生愁冰炭置我腸。"]'),
('189a2642-38e8-4cee-95fd-c55fc1ecd42f','詠白蓮花','劉才邵','宋','宋诗','song-poetry','','[]','長林翠乾因薰爍，池面水平風不落。',192,'全唐诗/poet.song.96000.json','["長林翠乾因薰爍，池面水平風不落。", "天公似亦厭煩溽，開就寒姿洗暄濁。", "龍宫想見送來時，靚粧無數褰珠箔。", "預愁風日會無情，翠蓋欹斜護纖弱。", "冰魂玉骨意自遠，凡花不是無心學。", "神人飲露骨偏清，仙子凌波塵不著。", "不隨時世事塗抹，徧得月娥憐綽約。", "雲軿隱隱欲降時，寒光清霧都情薄。", "勤勤問訊難留滯，欲去徘徊伸素約。", "待得秋高風露清，相将歸去朝珠閣。", "身家元是社中人，宿契非同謝康樂。", "更恐群仙苦相問，寄與短章資一噱。"]'),
('ecdcf72a-e83b-4a45-a7e7-8a1f39a6f206','神弦曲','劉才邵','宋','宋诗','song-poetry','','[]','古樹葉殘屯野煙，紅楹鏤磉蟠蝸涎。',80,'全唐诗/poet.song.96000.json','["古樹葉殘屯野煙，紅楹鏤磉蟠蝸涎。", "清燈暈淺不成圓，神妃靈女對瓊筵。", "翠衫籠玉眉連娟，泠泠古曲五十弦。", "啼雲弔月愁遠天，山鬼窺窗風颯然。", "絳節遥遥歸洞府，門前赤豹青貍舞。"]'),
('c2bfdc4f-ac87-4d9b-bcc3-80c1a2b483bb','瀘溪春日','劉才邵','宋','宋诗','song-poetry','','[]','風暖鶯離谷，花繁蝶倦飛。',48,'全唐诗/poet.song.96000.json','["風暖鶯離谷，花繁蝶倦飛。", "林塘供勝賞，雲日弄晴暉。", "古郡荒城在，芳郊遊騎歸。", "閑來推物理，痛飲未爲非。"]'),
('19b14b12-64f1-4008-b832-82e696910854','春日郊居四首  其一','劉才邵','宋','宋诗','song-poetry','','[]','地僻春還到，門閑性自便。',48,'全唐诗/poet.song.96000.json','["地僻春還到，門閑性自便。", "風回香縷轉，日透隙光圓。", "曲沼波初凸，繁花曉欲蔫。", "誰能學工部，直得爲春顛。"]'),
('a6ffc720-b8f5-43f7-86e5-d807081c8b86','春日郊居四首  其二','劉才邵','宋','宋诗','song-poetry','','[]','殘花啼曉露，落絮泊池荷。',48,'全唐诗/poet.song.96000.json','["殘花啼曉露，落絮泊池荷。", "带蘂蜂鬚重，窺簾燕語多。", "桑肥蠶趁暖，雨飽麥連坡。", "帝力知難報，閑聽擊壤歌。"]'),
('1efa0b55-96be-4081-a5cc-e1f1b3219a1b','春日郊居四首  其三','劉才邵','宋','宋诗','song-poetry','','[]','散策啟柴關，春光滿望間。',48,'全唐诗/poet.song.96000.json','["散策啟柴關，春光滿望間。", "長烟連遠碧，矮笋出新斑。", "倦蝶飛還歇，啼鶯意自閑。", "晚雲將小雨，容易暗前山。"]'),
('c9c6d06b-70b7-4a0a-a4ce-8b4b55b2a46e','春日郊居四首  其四','劉才邵','宋','宋诗','song-poetry','','[]','春事遽如許，登臨聊杖藜。',48,'全唐诗/poet.song.96000.json','["春事遽如許，登臨聊杖藜。", "遊絲斜带日，細草未霑泥。", "風軟花香熟，烟酣柳色迷。", "慇懃嘱鶗鴂，芳卉正萋萋。"]'),
('e00894da-67ce-4dbf-b221-f5f9811a761c','中秋','劉才邵','宋','宋诗','song-poetry','','[]','陰晴無遠近，獨有此宵看。',48,'全唐诗/poet.song.96000.json','["陰晴無遠近，獨有此宵看。", "寫盡山河影，想添蟾兔寒。", "清輝分玉露，斜漢泛冰盤。", "上到高圓處，亭亭輪更安。"]'),
('a5fbea29-55e3-4b0a-8853-81388c9a2e33','遊山寺詩','劉才邵','宋','宋诗','song-poetry','','[]','岡巒圍古刹，松桂發幽香。',48,'全唐诗/poet.song.96000.json','["岡巒圍古刹，松桂發幽香。", "斜日烟姿薄，空庭花影長。", "尋雲穿蘚徑，汲水動溪光。", "好就山房宿，閑聽鐘殷牀。"]'),
('fad4261b-1ab4-4bec-a9da-ded976807a31','次韻王民瞻題慧門院二首  其一','劉才邵','宋','宋诗','song-poetry','','[]','亂後身重到，醉中禪暫逃。',48,'全唐诗/poet.song.96000.json','["亂後身重到，醉中禪暫逃。", "蓮關無泣象，鷲嶺不傾鼇。", "井邑刼灰在，霜林秋氣高。", "更須資法雨，一爲洗弓刀。"]'),
('309e4ff6-aa4c-4ec2-8fe4-7692d99be61b','次韻王民瞻題慧門院二首  其二','劉才邵','宋','宋诗','song-poetry','','[]','亂兵如穴蟻，攘攘欲何逃。',48,'全唐诗/poet.song.96000.json','["亂兵如穴蟻，攘攘欲何逃。", "肆毒空搖蠆，支傾已斷鼇。", "上方塵不染，北極勢元高。", "佩犢知難久，紛紛已賣刀。"]'),
('7e786d8a-6ee9-4c82-b333-e4e25b666828','蘇文饒往昌國意頗憚之送以詩因勉之','劉才邵','宋','宋诗','song-poetry','','[]','已聞舟楫具，那得苦留君。',48,'全唐诗/poet.song.96000.json','["已聞舟楫具，那得苦留君。", "雨過霜風急，帆飛雪浪分。", "長途方策足，暇日正論文。", "功業他年事，風波豈足云。"]'),
('89b30ffe-d0b8-4a65-aa11-b362775fc80b','遊香山寶應寺恭覩仁宗皇帝御書發願文','劉才邵','宋','宋诗','song-poetry','','[]','龜洛隆周德，龍門賴禹功。',168,'全唐诗/poet.song.96000.json','["龜洛隆周德，龍門賴禹功。", "天開形勝地，雲捧法王宫。", "繡栱聯霞綺，虯簷壓霽虹。", "山河紛湊泊，星斗映穹崇。", "金界琅函秘，奎文筆勢雄。", "獨高今古外，何止帝王中。", "恭想重熙旦，追還太古風。", "開懷容直論，崇儉自清躬。", "俗厚刑幾措，時和歲屢豐。", "湛恩漸動植，大度納華戎。", "致治臻無事，持盈愈若冲。", "皇居多暇日，宸翰寫深衷。", "誓保基圖永，期躋壽域同。", "含生蒙願力，流澤浩無窮。"]'),
('ca3b7416-67b2-45e9-b23a-584db3cecfe4','賦得登瀛洲','劉才邵','宋','宋诗','song-poetry','','[]','天策開王府，仙才聚國英。',72,'全唐诗/poet.song.96000.json','["天策開王府，仙才聚國英。", "禮優初闢館，衆羡號登瀛。", "凡骨難飛步，神仙遂擬名。", "冠鼇堪比峻，馭鶴想同輕。", "銀闕誰云遠，金臺愧未清。", "收功歸正觀，文治播休聲。"]'),
('2f6df00a-2885-4f05-a227-7a191cb05bc9','賦得春色滿皇州','劉才邵','宋','宋诗','song-poetry','','[]','春光何處盛，先滿帝皇州。',72,'全唐诗/poet.song.96000.json','["春光何處盛，先滿帝皇州。", "日近恩輝動，天低淑氣浮。", "繁花迷綵仗，弱柳媚芳溝。", "風軟塵難動，烟酣翠欲流。", "驩聲連綺陌，仙吹咽瓊樓。", "願遂觀光志，曲江追勝遊。"]'),
('c92c1f7a-9a5f-42be-8b78-5bcae3f3f03d','賦得秋風生桂枝','劉才邵','宋','宋诗','song-poetry','','[]','金飈隨素律，丹桂吐幽姿。',72,'全唐诗/poet.song.96000.json','["金飈隨素律，丹桂吐幽姿。", "潛動驚秋意，生從傲雪枝。", "高應翻月窟，清已徹天涯。", "雖效紛披態，終無搖落悲。", "低嫌蘋末起，凉異棘心吹。", "幸有乘風興，高攀自不遲。"]'),
('7149b09e-b839-4385-a52a-4c3a6197dbdb','賦得鮮雲垂薄陰','劉才邵','宋','宋诗','song-poetry','','[]','輕雲初出岫，散漫本無心。',72,'全唐诗/poet.song.96000.json','["輕雲初出岫，散漫本無心。", "鄣日呈鮮彩，垂天結薄陰。", "浮空誠可玩，著地影非深。", "籠水難藏渚，依山豈暗林。", "誰言聊晻靄，遠勢已侵尋。", "不羡西郊密，終期爲作霖。"]'),
('a441311a-d0cb-4717-94da-14c9772eb46a','次韻朱希真送李仲輔使浙東','劉才邵','宋','宋诗','song-poetry','','[]','詔遣皇華使，恩殊白首郎。',72,'全唐诗/poet.song.96000.json','["詔遣皇華使，恩殊白首郎。", "越城膺重寄，雲路佇高翔。", "金節丹楓外，星軺碧海傍。", "溪山動詩興，藻火粲篇章。", "暫對青藜杖，徐驅白鳯凰。", "平反有餘暇，霜橘薦瑤觴。"]'),
('7de3ac27-bb02-4c66-9341-89664dbb5a91','賦得蛟龍得雲雨','劉才邵','宋','宋诗','song-poetry','','[]','賢能攄逸志，振迹比蛟龍。',72,'全唐诗/poet.song.96000.json','["賢能攄逸志，振迹比蛟龍。", "雲雨時方得，烟霄路自逢。", "濯鱗霑帝澤，擁足脫塵蹤。", "物外將輕矯，池中豈解容。", "依乘應有待，際會合相從。", "寄語懷才者，明時好奮庸。"]'),
('101ec0c6-10d1-428a-8ef6-e72a463ec248','贈端上人','劉才邵','宋','宋诗','song-poetry','','[]','傳得無聲曲，有時彈向人。',48,'全唐诗/poet.song.96000.json','["傳得無聲曲，有時彈向人。", "雪峰年老大，風穴語尖新。", "吼月泥牛困，抽條石笋春。", "衣珠猶不重，豈更覺身貧。"]'),
('7e485141-0094-487c-8cfe-90235bff138d','挽江司戶詞  其一','劉才邵','宋','宋诗','song-poetry','','[]','場屋聲名舊，林泉興味長。',48,'全唐诗/poet.song.96000.json','["場屋聲名舊，林泉興味長。", "青衫歸里閈，白首傲羲皇。", "鶴静終輕矯，蘭銷委暗芳。", "遥憐高遯處，庭宇日荒凉。"]'),
('0300256e-ab9b-4fde-9c45-79227e4fdff9','挽江司戶詞  其二','劉才邵','宋','宋诗','song-poetry','','[]','早歲識真際，前身疑浄名。',48,'全唐诗/poet.song.96000.json','["早歲識真際，前身疑浄名。", "窮通百年內，生死一銖輕。", "成佛無先後，同參有弟兄。", "悲傷隨世諦，益見在原情。"]'),
('c5b1daf6-ef9e-49de-a482-c4e2949aeb9d','挽戴彦誠通判三首  其一','劉才邵','宋','宋诗','song-poetry','','[]','初闢橋門日，英髦喜彙征。',48,'全唐诗/poet.song.96000.json','["初闢橋門日，英髦喜彙征。", "奇文逢藻鑒，時輩仰高名。", "仕路因騰踏，聲華久隱訇。", "方觀終遠業，埋玉恨難平。"]'),
('ade2cb2f-6171-432f-b91f-46a471330a95','挽戴彦誠通判三首  其二','劉才邵','宋','宋诗','song-poetry','','[]','庠序親餘論，京華獲並遊。',48,'全唐诗/poet.song.96000.json','["庠序親餘論，京華獲並遊。", "艱危心有託，感激義無酬。", "豈謂音容隔，頻驚歲月流。", "今來拜遺像，淚雨不能收。"]'),
('f4e6f29f-5816-48de-88ba-f629a5e6932f','挽戴彦誠通判三首  其三','劉才邵','宋','宋诗','song-poetry','','[]','賈鵩由來忌，應曾爲廢書。',48,'全唐诗/poet.song.96000.json','["賈鵩由來忌，應曾爲廢書。", "始終歸有數，善慶豈無餘。", "賢嗣真蘭玉，令名驚里閭。", "他年定通顯，躍馬從金輿。"]'),
('1a1521d2-8e2b-4261-b0e1-8c4315efe166','次韻元日會飲','劉才邵','宋','宋诗','song-poetry','','[]','不將簾幕挂簷脣，欲聽飛霙點繡茵。',64,'全唐诗/poet.song.96000.json','["不將簾幕挂簷脣，欲聽飛霙點繡茵。", "門外湖山元早白，醉中笑語不嫌真。", "爐烟盡日飄香霧，茗盌侵湯攪玉塵。", "莫怪更深寒力減，瑤墀今日布王春。"]'),
('edfe3d59-192e-48e4-b2f6-74517ae0effa','謝人惠花栽以龍涎及小團答之','劉才邵','宋','宋诗','song-poetry','','[]','應憐小圃少花看，分惠靈苗四五般。',64,'全唐诗/poet.song.96000.json','["應憐小圃少花看，分惠靈苗四五般。", "多謝高情無所吝，欲將俗物報應難。", "鯨波薦液香難比，龍焙先春玉作團。", "寄與文房助清興，詩魂莫怕月邊寒。"]'),
('6e1798e3-1f35-48ac-9596-e4ddaca0d203','江閣夜坐  其一','劉才邵','宋','宋诗','song-poetry','','[]','迢迢小閣倚雲端，高處懸知境界寛。',64,'全唐诗/poet.song.96000.json','["迢迢小閣倚雲端，高處懸知境界寛。", "共向城頭聊放目，卻驚沙觜減奔湍。", "蒼烟闕處江山遠，白月滿空星斗寒。", "炯炯此心誰會得，從公清坐到更闌。"]'),
('21e22daa-9c78-4744-bfe4-3d2a8b0b4e96','江閣夜坐  其二','劉才邵','宋','宋诗','song-poetry','','[]','閑雲收盡露乾端，垂地漫漫碧玉寛。',64,'全唐诗/poet.song.96000.json','["閑雲收盡露乾端，垂地漫漫碧玉寛。", "小海無人續遺唱，斜河挂影作飛湍。", "水仙環佩歸何處，天闕樓臺似更寒。", "知欲乘風叩閶闔，如公應入不爲闌。"]'),
('b673e23e-eebf-49a2-b798-622071df4535','愚堂爲歐陽炳文作','劉才邵','宋','宋诗','song-poetry','','[]','高懷從昔厭雄夸，宴坐虛堂玩物華。',64,'全唐诗/poet.song.96000.json','["高懷從昔厭雄夸，宴坐虛堂玩物華。", "清簟疏簾無俗客，澆花洗竹當生涯。", "風驚萬木誰家曲，雲擁千峰盡日衙。", "莫信韜光得深隱，鶴書終恐到君家。"]'),
('d3b2cd77-b66e-42a8-83dc-f0262669e06f','次韻李彦淵遊竹閣奉呈望之','劉才邵','宋','宋诗','song-poetry','','[]','春餘景物尚芳華，寫景詞工語不夸。',64,'全唐诗/poet.song.96000.json','["春餘景物尚芳華，寫景詞工語不夸。", "綺饌玉樽筵秩秩，碧梧翠竹影斜斜。", "湖山風月須頻賞，南北車書已一家。", "回首都人候清蹕，遥知紫禁繞烟花。"]'),
('a568ec3b-27aa-4a55-bae7-58b50b7621e1','同張敏叔登望闕臺','劉才邵','宋','宋诗','song-poetry','','[]','曉陟高臺望紫宸，愛君心切素忘身。',64,'全唐诗/poet.song.96000.json','["曉陟高臺望紫宸，愛君心切素忘身。", "堯天日遠迷西極，漢使星高拱北辰。", "賦雪才優宜視草，賜環恩重定隨春。", "剩須留下驚人句，長使江山氣象新。"]'),
('a3165ac9-a885-41b0-a5b7-50231456e69b','賀和仲移居  其一','劉才邵','宋','宋诗','song-poetry','','[]','狻猊群戲畫難工，木梢翬飛面勢雄。',64,'全唐诗/poet.song.96000.json','["狻猊群戲畫難工，木梢翬飛面勢雄。", "壯氣定知如杜固，鑿池肯復効燕公。", "好穿松竹躋雲磴，别敞簷楹看碧空。", "更願他年開北第，卻留蹤跡付隆中。"]'),
('fc8f29cc-6ffd-49d5-b16d-e9762f3d93a4','賀和仲移居  其二','劉才邵','宋','宋诗','song-poetry','','[]','蒼官湧翠千株直，石棧斜飛一徑通。',64,'全唐诗/poet.song.96000.json','["蒼官湧翠千株直，石棧斜飛一徑通。", "爽塏真能明遠目，囂塵不動但清風。", "卜鄰豈免煩王翰，相宅應兼出魏公。", "終使里名不虛設，先栽巖桂與分叢。"]'),
('aadcd37b-f598-43d9-8d7a-d954684bfbbd','次韻陶父雙蓮','劉才邵','宋','宋诗','song-poetry','','[]','和氣爲霖歲有涯，發祥宜自使君家。',64,'全唐诗/poet.song.96000.json','["和氣爲霖歲有涯，發祥宜自使君家。", "池開雙影同心瑞，氣敵三峰十丈花。", "嘯侣洛妃携翠袖，懼飛蛺蝶護新葩。", "天公似恐嫦娥妬，時把微雲隔素華。"]'),
('2a9f41bf-d4be-4ffd-b41d-8898ac1ee4be','鬰孤臺','劉才邵','宋','宋诗','song-poetry','','[]','風伯驅雲曉色開，使家清燕就高臺。',64,'全唐诗/poet.song.96000.json','["風伯驅雲曉色開，使家清燕就高臺。", "崆峒爽氣連天起，章貢寒聲遶檻來。", "譚屑霏霏隨玉麈，酒波灧灧溢金罍。", "還將崇政言詩手，一爲江城賦早梅。"]'),
('3730761e-3224-4e0b-900a-634eeefea752','次韻黄元授憫旱','劉才邵','宋','宋诗','song-poetry','','[]','旱氣爞爞似火炎，新來露亦不輕霑。',64,'全唐诗/poet.song.96000.json','["旱氣爞爞似火炎，新來露亦不輕霑。", "電光入夜空搖幟，雨響經時不到簷。", "獄吏誰憐寃死婦，農家空挂刈禾鐮。", "高天早副憂民意，雲漢無煩歎靡瞻。"]'),
('f90966b6-b849-4fe2-88ce-5bf16d32194c','次韻寛夫喜雨詩','劉才邵','宋','宋诗','song-poetry','','[]','檀龍致雨雨宵零，香氣如傳得薦馨。',64,'全唐诗/poet.song.96000.json','["檀龍致雨雨宵零，香氣如傳得薦馨。", "斷港已通無别浦，洪波遥想接重溟。", "門開甘露偏蘇槁，供設伊蒲異獻腥。", "清禁詞臣歌樂職，淵雲難獨掞天庭。"]'),
('ec27ddeb-d2c2-44a1-b6c7-88d9b605ccac','次韻黄元授喜雨詩','劉才邵','宋','宋诗','song-poetry','','[]','溝塍流水已源源，還有餘波及衆川。',64,'全唐诗/poet.song.96000.json','["溝塍流水已源源，還有餘波及衆川。", "焦稼頓蘇苗薿薿，涸池重見葉田田。", "休疑兩種分乾溼，且喜脩羅罷鎧鋋。", "平糴莫將同上熟，恐教閭井卻騷然。"]'),
('99a132ce-43f1-4c8a-bf94-1f52b76dde3b','次韻周秀實七夕','劉才邵','宋','宋诗','song-poetry','','[]','雲間素月若飛來，半鏡携歸共挂臺。',64,'全唐诗/poet.song.96000.json','["雲間素月若飛來，半鏡携歸共挂臺。", "星渚橋成仙步隱，玉簫聲斷曉風哀。", "曾向兹辰曝圖籍，還思延閣敵蓬萊。", "誰憐點鬢吳霜重，酒母分霑助把盃。"]'),
('a22aea2d-0436-4138-ba0e-0bbd7431d653','和彭德源秋開紫牡丹','劉才邵','宋','宋诗','song-poetry','','[]','暗覺小陽春氣回，卻從秋杪上樓臺。',64,'全唐诗/poet.song.96000.json','["暗覺小陽春氣回，卻從秋杪上樓臺。", "淺於潑墨輕勻露，小似齊頭只類杯。", "應是化工偏著意，便同仙骨免枯荄。", "笑他方士驚人眼，謾作空花頃刻開。"]'),
('a54e0c97-ff74-4b93-9377-932b65108f35','次韻温叔皮秋懷','劉才邵','宋','宋诗','song-poetry','','[]','海風截雨晚雲收，銀漢迢迢傍月流。',64,'全唐诗/poet.song.96000.json','["海風截雨晚雲收，銀漢迢迢傍月流。", "菊露自應知歲晏，砧聲今不起邊愁。", "尋常酒債何妨有，咫尺湖山未暇遊。", "欲跨青虯舒遠目，水仙真肯借人不。"]'),
('f751950d-85ce-4e59-907e-ca1456bee692','次韻李彦淵夜聞鶴唳','劉才邵','宋','宋诗','song-poetry','','[]','警露猶能動客情，淮淝况復雜風聲。',64,'全唐诗/poet.song.96000.json','["警露猶能動客情，淮淝况復雜風聲。", "語多真似留華表，意遠誰知在紫清。", "正值月寒秋夜永，更當風静海潮平。", "故山蕙帳空來久，想共曉猿相對鳴。"]'),
('90a1d125-c181-456a-937b-8f9f1cd37035','過唐興寺  其一','劉才邵','宋','宋诗','song-poetry','','[]','須應辭職效崔沂，豈合經時直紫微。',64,'全唐诗/poet.song.96000.json','["須應辭職效崔沂，豈合經時直紫微。", "領郡尚叨分竹箭，羡君不肯裂荷衣。", "高風久已勤山仰，妙語新從得指歸。", "更待春時稍暄暖，共尋烟塢與苔磯。"]'),
('8097d879-8018-43b2-8dfd-6e0d6dd11bb1','過唐興寺  其二','劉才邵','宋','宋诗','song-poetry','','[]','夜契從來耐歲寒，千株路盡見蒼官。',64,'全唐诗/poet.song.96000.json','["夜契從來耐歲寒，千株路盡見蒼官。", "舊遊還復尋金碧，清夢猶能記玉鑾。", "喜見雲烟生翰墨，隨時殽核簇杯盤。", "荷公高誼存真趣，不作尋常俗眼看。"]'),
('b5dae1c3-d8ec-4763-9f44-330c9b6df452','次韻劉仙卿臘日喜雪  其一','劉才邵','宋','宋诗','song-poetry','','[]','徹地寒威暖尚遥，豈同春日落還消。',64,'全唐诗/poet.song.96000.json','["徹地寒威暖尚遥，豈同春日落還消。", "醉翁不道鹽并絮，阿母難専池是瑤。", "素月交光千里共，豐年爲瑞四時調。", "臘中三白已堪賞，何况皚皚照此宵。"]'),
('fb6db8e4-072d-4360-b386-20094910fb3a','次韻劉仙卿臘日喜雪  其二','劉才邵','宋','宋诗','song-poetry','','[]','臘祀祁年瑞雪飄，共知帝力最難消。',64,'全唐诗/poet.song.96000.json','["臘祀祁年瑞雪飄，共知帝力最難消。", "無邊世界銀爲闕，不動根荄草變瑤。", "人悅自然天意得，時和豈待樂聲調。", "月娥似更憐鮮潔，清影亭亭徹永宵。"]'),
('79aa4a0e-e98a-4365-9d11-ce0a3c7ce277','早朝行宫奉呈諸同舍','劉才邵','宋','宋诗','song-poetry','','[]','龍山西轉浙江横，寶勢岧嶤切太清。',64,'全唐诗/poet.song.96000.json','["龍山西轉浙江横，寶勢岧嶤切太清。", "照海曉光來闕角，穿花宮漏带潮聲。", "風生劍佩班初上，霧歇旌旗色更明。", "共說中興似光武，南都賦合繼東京。"]'),
('cb80ca6a-67cb-4254-8552-3176d056ec37','祖廟殿生芝草  其一','劉才邵','宋','宋诗','song-poetry','','[]','由來天意眷明昌，偏向神宮發喜祥。',64,'全唐诗/poet.song.96000.json','["由來天意眷明昌，偏向神宮發喜祥。", "和氣潛蒸方蔓蔓，靈華託柱益煌煌。", "披圖正與端宸合，紀美還增原廟光。", "漢室但閑生禁宇，作歌空復詠齋房。"]'),
('ef762c0b-8596-46b2-a646-512c89023bad','祖廟殿生芝草  其二','劉才邵','宋','宋诗','song-poetry','','[]','聖孝神明已默通，皇猷德業更兼隆。',64,'全唐诗/poet.song.96000.json','["聖孝神明已默通，皇猷德業更兼隆。", "昌期適契千齡會，上瑞宜生九廟中。", "異彩光凝何煜爚，靈葩色正自昭融。", "天將福慶資宗佑，方至如川豈有窮。"]'),
('0c62859d-a56d-461c-a048-8f16229b8a24','次韻同舍道山堂宿直二首  其一','劉才邵','宋','宋诗','song-poetry','','[]','花影頻移夜向闌，重簷突兀倚雲端。',64,'全唐诗/poet.song.96000.json','["花影頻移夜向闌，重簷突兀倚雲端。", "木天西畔銀河響，陸海中間貝闕寒。", "風輭嚴更傳玉漏，月和清露滴金盤。", "不嫌上界多官府，請便乘風駕紫鸞。"]'),
('c3abb8d6-31b3-4604-9b83-fb28c4e61a70','次韻同舍道山堂宿直二首  其二','劉才邵','宋','宋诗','song-poetry','','[]','玉宇沉沉易覺秋，暮雲開盡夜悠悠。',64,'全唐诗/poet.song.96000.json','["玉宇沉沉易覺秋，暮雲開盡夜悠悠。", "天風斜轉蒼龍闕，宮月遥連紫桂樓。", "寶畫深嚴神物護，仙山縹緲瑞烟浮。", "慚無逸藻陪諸彦，歸興惟思理釣舟。"]'),
('d8d11dac-2f00-480a-8d89-e348e7b4f6cd','和李仲孫韻因以奉勉','劉才邵','宋','宋诗','song-poetry','','[]','詞格森嚴氣不寒，華星灼灼出雲間。',64,'全唐诗/poet.song.96000.json','["詞格森嚴氣不寒，華星灼灼出雲間。", "中興喜見天方啟，高議期追漢已還。", "正值朝家求切直，豈容奇逸戀雲山。", "願公淬筆參晁董，大對親瞻睟穆顔。"]'),
('f08a2b40-5d36-4c9b-843f-4ba15f9838b8','送李似之二首  其一','劉才邵','宋','宋诗','song-poetry','','[]','中興修政似周宣，共理聊煩命世賢。',64,'全唐诗/poet.song.96000.json','["中興修政似周宣，共理聊煩命世賢。", "凋瘵氣蘇真肉骨，豪強膽落怯冰淵。", "遠猷豈合淹千里，温詔俄頒自九天。", "解釋邦人去思恨，爲言行復入陶甄。"]'),
('054ac2bc-be5f-461e-b88f-bb975573bd66','送李似之二首  其二','劉才邵','宋','宋诗','song-poetry','','[]','晴虹詞彩冠群才，淡墨名高北斗魁。',64,'全唐诗/poet.song.96000.json','["晴虹詞彩冠群才，淡墨名高北斗魁。", "史筆繼聞登左省，廟謨今復贊中臺。", "方傳召命馳三節，頓使清風動九垓。", "想見君王偏注意，鳯池虛位待公來。"]'),
('a4ee3869-7f9a-4d41-ba06-eb8298215e09','次韻送盧汝舟','劉才邵','宋','宋诗','song-poetry','','[]','秋鴻社燕若爲情，歧路東西亦可驚。',64,'全唐诗/poet.song.96000.json','["秋鴻社燕若爲情，歧路東西亦可驚。", "入夜朔風搖畫角，滿空星斗罩高城。", "吳江浪濶兼天湧，楚塞山長盡日横。", "記取别筵看劍處，怕聽庭樹曉雞聲。"]'),
('0c2cb65e-a7a8-4093-8a9c-23bef2378d77','送江虞仲','劉才邵','宋','宋诗','song-poetry','','[]','烜赫家聲四海聞，材猷超絕出凡倫。',64,'全唐诗/poet.song.96000.json','["烜赫家聲四海聞，材猷超絕出凡倫。", "清規映物無塵隔，實德臨民蒙惠均。", "器遠自應當要路，政成還合覲嚴宸。", "禁途虛位須賢俊，佇慶登崇寵渥新。"]'),
('5e03f294-67a9-4e42-b0d6-905048a8cc7a','和丁浚明戲蕭濟夫  其一','劉才邵','宋','宋诗','song-poetry','','[]','生世纔如石火光，應憐不早見盧郎。',64,'全唐诗/poet.song.96000.json','["生世纔如石火光，應憐不早見盧郎。", "碧蟾自合來棲月，黄耳何緣得上床。", "但使知音同卓氏，何妨服猛似梁鴦。", "觀音妙相誰能測，暫化身爲無厭王。"]'),
('0d9f5c39-6376-40aa-9224-efb35e5b7f98','和丁浚明戲蕭濟夫  其二','劉才邵','宋','宋诗','song-poetry','','[]','庾婦休誇意智強，卻因詐魘喚江郎。',64,'全唐诗/poet.song.96000.json','["庾婦休誇意智強，卻因詐魘喚江郎。", "自從呼婢曾開口，不復連宵只對床。", "春晚燕狂捎蛺蝶，汀閑沙暖睡鴛鴦。", "鳯棲已協和鳴兆，誰記東家人姓王。"]'),
('ac6c0db1-763b-49b8-8dfa-389063ff9480','次韻蕭元隆見寄二首  其一','劉才邵','宋','宋诗','song-poetry','','[]','國朝制策得群賢，隆棟才高異衆椽。',64,'全唐诗/poet.song.96000.json','["國朝制策得群賢，隆棟才高異衆椽。", "温詔久頒崇舊典，英辭初喜見新編。", "竚登文陛三層峻，還寄家聲萬古傳。", "聖主憂民收遠策，欲令枕奠得安眠。"]'),
('6ba82313-f45f-4081-b65e-329280c5892e','次韻蕭元隆見寄二首  其二','劉才邵','宋','宋诗','song-poetry','','[]','麟閣岧嶤倚碧天，道山宿直燭如椽。',64,'全唐诗/poet.song.96000.json','["麟閣岧嶤倚碧天，道山宿直燭如椽。", "誰憐老眼今多病，喜讀危詞屢絕編。", "一鶚奮飛方遠舉，雙魚緘素肯輕傳。", "益思張膽論時事，未敢昏昏只醉眠。"]'),
('28128a92-c235-47ec-81a5-7576093b4209','次韻王民瞻','劉才邵','宋','宋诗','song-poetry','','[]','野外蕭條供給稀，愧煩車馬顧柴扉。',64,'全唐诗/poet.song.96000.json','["野外蕭條供給稀，愧煩車馬顧柴扉。", "正憐習懶成癡鈍，欲使乘時試奮飛。", "高義杉松度冰雪，好詩星斗轉璿璣。", "如公亦豈宜深隱，早晚光芒動少微。"]'),
('5c04d894-8f95-4d23-937b-d9595fcf9e2a','立春內中帖子詞  其一','劉才邵','宋','宋诗','song-poetry','','[]','蘭殿光風轉，椒塗淑氣濃。',24,'全唐诗/poet.song.96000.json','["蘭殿光風轉，椒塗淑氣濃。", "柳烟添曉翠，花露浥春容。"]'),
('0ed2caf5-27e6-4dbe-abae-ccffdcbe2399','立春內中帖子詞  其二','劉才邵','宋','宋诗','song-poetry','','[]','紫禁遲遲漏，瑤箱細細風。',24,'全唐诗/poet.song.96000.json','["紫禁遲遲漏，瑤箱細細風。", "君王問安早，紅燭照簾櫳。"]'),
('6a69dfda-0621-4b71-8821-b0bd68d4a032','立春內中帖子詞  其三','劉才邵','宋','宋诗','song-poetry','','[]','寶勝金書小，酥盤花様新。',24,'全唐诗/poet.song.96000.json','["寶勝金書小，酥盤花様新。", "六宮呈妙巧，清曉慶佳辰。"]'),
('85a19dd1-09e3-447e-b364-f2346c1d9e9e','立春內中帖子詞  其四','劉才邵','宋','宋诗','song-poetry','','[]','瑞氣籠春宮殿高，天官仙樂奏雲璈。',32,'全唐诗/poet.song.96000.json','["瑞氣籠春宮殿高，天官仙樂奏雲璈。", "欲知聖壽無疆處，王母千回獻碧桃。"]'),
('cb8d70ac-1f3b-4d19-9313-85d2973ec706','立春內中帖子詞  其五','劉才邵','宋','宋诗','song-poetry','','[]','君王聖母與天通，預建慈寧廣內中。',32,'全唐诗/poet.song.96000.json','["君王聖母與天通，預建慈寧廣內中。", "果慶回鑾功已就，纂修事實示無窮。"]'),
('6ca5cac6-9630-4c6b-95a2-c56685f84e3e','立春內中帖子詞  其六','劉才邵','宋','宋诗','song-poetry','','[]','春歸頓覺日華遲，樂事偏多屬聖時。',32,'全唐诗/poet.song.96000.json','["春歸頓覺日華遲，樂事偏多屬聖時。", "萬壽聲中觴酒滿，年年歲歲擁春祺。"]'),
('cb889f21-f2e4-4634-8a6b-3ad78c016a6d','又  其一','劉才邵','宋','宋诗','song-poetry','','[]','一氣回蒼陸，千祥集紫宸。',24,'全唐诗/poet.song.96000.json','["一氣回蒼陸，千祥集紫宸。", "天心存愛育，施惠發新春。"]'),
('6d81ed7c-f0db-4a7a-b6dc-4fd2a6ce8f28','又  其二','劉才邵','宋','宋诗','song-poetry','','[]','行仁隆治道，偃武爲生靈。',24,'全唐诗/poet.song.96000.json','["行仁隆治道，偃武爲生靈。", "恩施周遐邇，熙熙萬國寧。"]'),
('69ed6b21-e9f4-4fe3-b919-5f1c53d6157c','又  其三','劉才邵','宋','宋诗','song-poetry','','[]','盛德天垂覆，皇明日照臨。',24,'全唐诗/poet.song.96000.json','["盛德天垂覆，皇明日照臨。", "九重頒漢詔，四海識堯心。"]'),
('2b0d6bed-5c0e-4edb-b1a6-b0382af69346','又  其四','劉才邵','宋','宋诗','song-poetry','','[]','始和布政同天運，聖澤隨春下九霄。',32,'全唐诗/poet.song.96000.json','["始和布政同天運，聖澤隨春下九霄。", "垂法端闈萬人喜，典章盡復祖宗朝。"]'),
