('5de92447-c1e1-47fb-9f55-32533684388a','次韻德源道人水墨畫二絕句  其二','劉才邵','宋','宋诗','song-poetry','','[]','霜枯荷葉半欹斜，水落寒溪蹙浪花。',32,'全唐诗/poet.song.96000.json','["霜枯荷葉半欹斜，水落寒溪蹙浪花。", "雁足更須添繫帛，似傳遠信度龍沙。"]'),
('37b633fc-548d-407a-bbcb-4d28db6d321e','鑒上人通內外學徧遊訪方晚棲舊隱年來示疾遂不出山牡丹四窠見寄因成三絕句以謝  其一','劉才邵','宋','宋诗','song-poetry','','[]','聞說栽時正出家，春風四紀閲芳華。',32,'全唐诗/poet.song.96000.json','["聞說栽時正出家，春風四紀閲芳華。", "如今示疾空山裏，怕引諸天來散花。"]'),
('5d43e319-9523-48dd-8f99-fe35df990020','鑒上人通內外學徧遊訪方晚棲舊隱年來示疾遂不出山牡丹四窠見寄因成三絕句以謝  其二','劉才邵','宋','宋诗','song-poetry','','[]','遠寄靈根自梵家，小園景物頓增華。',32,'全唐诗/poet.song.96000.json','["遠寄靈根自梵家，小園景物頓增華。", "何當寫在屏幃上，一任高禪笑眼花。"]'),
('64177bf9-606c-4955-b2bb-3d67116f4bf0','鑒上人通內外學徧遊訪方晚棲舊隱年來示疾遂不出山牡丹四窠見寄因成三絕句以謝  其三','劉才邵','宋','宋诗','song-poetry','','[]','學道何妨只在家，謾栽花草記年華。',32,'全唐诗/poet.song.96000.json','["學道何妨只在家，謾栽花草記年華。", "箇中本自無榮悴，浮世何曾似落花。"]'),
('7c51225a-d3ef-4736-9ae9-2e17b992c152','贈段成之','劉才邵','宋','宋诗','song-poetry','','[]','粟菴宴坐正安禪，不踏城闉已十年。',32,'全唐诗/poet.song.96000.json','["粟菴宴坐正安禪，不踏城闉已十年。", "送别今朝不辭遠，信知高義薄雲天。"]'),
('ae189c84-d4ef-448b-b1c0-496b2aadd7f4','黄芍藥','劉才邵','宋','宋诗','song-poetry','','[]','遊沛曾聞漢帝魂，夢中名實未應分。',32,'全唐诗/poet.song.96000.json','["遊沛曾聞漢帝魂，夢中名實未應分。", "看花莫動枝頭蝶，驚覺徐州老使君。"]'),
('39a9cc6b-b580-47f7-b4a1-6f59e82ca957','瑪瑙數珠偈','劉才邵','宋','宋诗','song-poetry','','[]','一切有爲法，幻相有去來。',48,'全唐诗/poet.song.96000.json','["一切有爲法，幻相有去來。", "如來真實義，無去亦無住。", "我原寶珠光，徧照大千界。", "隨光所照處，見者悉成佛。"]'),
('78549ddc-7281-49ea-b04c-034f407afcc0','默齋偈','劉才邵','宋','宋诗','song-poetry','','[]','稽首金剛獅子座，紫金光聚妙色身。',208,'全唐诗/poet.song.96000.json','["稽首金剛獅子座，紫金光聚妙色身。", "微塵剎土轉法輪，演出無邊殊勝義。", "燃燈如來昔授記，初無一法可得者。", "云何種種方便門，多劫宣揚不能盡。", "觀音妙力不思議，元從耳門得昧。", "爍迦羅首八萬餘，隨處說法度衆生。", "云何現身蛤蜊中，不假語言法亦顯。", "當知是法本無法，語默兩塗俱解脫。", "二乘知見妄分別，偏執所見自纏縛。", "解縛不離縛處解，還從語默證圓湛。", "良哉居士具通眼，一切不隨根境轉。", "了知諸法不可礙，剎那真入三摩地。", "我願初沒這見聞者，悉悟真常成正覺。"]'),
('0d9178c7-6602-44ad-9ff0-297d539ab7cc','句','劉才邵','宋','宋诗','song-poetry','','[]','見說木天猶突兀，暫時金地亦清閑。',16,'全唐诗/poet.song.96000.json','["見說木天猶突兀，暫時金地亦清閑。"]'),
('9fbc5e30-574c-4c3c-8bc1-7ec763a26d85','句','丁浚明','宋','宋诗','song-poetry','','[]','從前謔浪今收拾，儘聽人呼張大王。',16,'全唐诗/poet.song.96000.json','["從前謔浪今收拾，儘聽人呼張大王。"]'),
('145e75b3-821d-4eee-aac8-a60316a95e69','隴口作','郭浩','宋','宋诗','song-poetry','','[]','隴口山深草木荒，行人到此斷肝腸。',32,'全唐诗/poet.song.96000.json','["隴口山深草木荒，行人到此斷肝腸。", "耳中不忍聽鸚鵡，猶在枝頭說上皇。"]'),
('f1b8f22b-2260-4a09-bb4b-57297239511e','觀音院德雲堂','胡松年','宋','宋诗','song-poetry','','[]','小舟乘風飛鳥過，萬頃雲濤縱掀簸。',192,'全唐诗/poet.song.96000.json','["小舟乘風飛鳥過，萬頃雲濤縱掀簸。", "此行要是快平生，無數青山笑迎我。", "山根隱約見人家，槿籬茅屋埋煙霞。", "宛似秦人種桃處，川原遠近紛香葩。", "杖藜徑踏華山去，試問蓮開今何許。", "路迷絕壑蔭松筠，身到半山聽魚鼓。", "道人爲我開雲堂，是中境界渾清涼。", "幽磬時和野鳥語，飛泉暗瀉巖花香。", "文書照眼本吾事，雁鶩著行敗人意。", "造物似憐厭世囂，挈置湖山煩一洗。", "何人夜呼隱去來，向來得喪真山崖。", "金庭玉柱永不改，人間劫火空飛灰。"]'),
('a7b36ea6-8d29-494b-90f4-48f1e1262658','顧亭林','胡松年','宋','宋诗','song-poetry','','[]','海山盪佳氣，千載傳古居。',48,'全唐诗/poet.song.96000.json','["海山盪佳氣，千載傳古居。", "平生讀書地，竹柏靜以疏。", "忠義貫白日，名不埋幽墟。", "苗裔今幾何，誰能補其餘。"]'),
('3394325f-e27d-493a-b6ac-1997a25b16a4','洞庭','胡松年','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','白蘋風靜碧波沉，畫舸來遊着意深。',64,'全唐诗/poet.song.96000.json','["白蘋風靜碧波沉，畫舸來遊着意深。", "願覓靈文窺祕鑰，更追遺範寫良金。", "姓名便合聯真隱，出處何妨擬醉吟。", "疇昔光陰費行樂，中原鼙鼓正傷心。"]'),
('4c0d1085-a61b-4185-ad3b-1e521843c48e','建炎丞相成國呂忠穆公退老堂  其一','趙思誠','宋','宋诗','song-poetry','','[]','抗章懇避公槐位，卜築千巖紫翠間。',64,'全唐诗/poet.song.96000.json','["抗章懇避公槐位，卜築千巖紫翠間。", "園鎖幽深似仙境，堂開華麗遠塵寰。", "貂冠虎騎榮新寵，雲閣瓊臺許暫閑。", "帷幄謀謨待元老，未容高蹈占東山。"]'),
('3b7bfe63-d275-4b83-8848-89e92686830e','建炎丞相成國呂忠穆公退老堂  其二','趙思誠','宋','宋诗','song-poetry','','[]','經濟奇謀有祖風，渭川卜獵舊非熊。',64,'全唐诗/poet.song.96000.json','["經濟奇謀有祖風，渭川卜獵舊非熊。", "風雲遇會千齡運，社稷扶傾萬世功。", "偃息郊園酬雅志，咨詢廟算簡清衷。", "更須整頓乾坤了，綠野歸來效晉公。"]'),
('6b3b8e5f-e8bc-4020-8fdf-cd7a504b93c5','偈二首  其一','釋道閑','宋','宋诗','song-poetry','','[]','全機敵勝，猶在半途。',50,'全唐诗/poet.song.96000.json','["全機敵勝，猶在半途。", "啐啄同時，白雲萬里。", "纔生朕兆，已落二三。", "不露鋒鋩，成何道理。", "誣人之罪，以罪加之。"]'),
('f712b9c4-5060-4abd-a402-e3b33508c5f6','偈二首  其二','釋道閑','宋','宋诗','song-poetry','','[]','蕩蕩無迂曲，明明透古今。',48,'全唐诗/poet.song.96000.json','["蕩蕩無迂曲，明明透古今。", "曉雲籠碧岫，殘葉落疏林。", "脫體全收放，當堂定淺深。", "饒君親薦得，未是我智音。"]'),
('95c353ed-0225-427c-a6c4-100bc4033c78','頌古二首  其一','釋道閑','宋','宋诗','song-poetry','','[]','雪壓怪松露，風高野渡橫。',24,'全唐诗/poet.song.96000.json','["雪壓怪松露，風高野渡橫。", "將謂衆生苦，更有苦衆生。"]'),
('0f9910e5-eae8-4e4b-bd30-7b51203b54b4','頌古二首  其二','釋道閑','宋','宋诗','song-poetry','','[]','相見不須嗔，君窮我亦貧。',24,'全唐诗/poet.song.96000.json','["相見不須嗔，君窮我亦貧。", "謂言侵早起，更有夜行人。"]'),
('23fb6ebc-cc11-428d-b27e-6d1452583070','頌古九首  其一','釋善悟','宋','宋诗','song-poetry','','[]','昨日與今日，說定說不定。',40,'全唐诗/poet.song.96000.json','["昨日與今日，說定說不定。", "寰中天子敕，塞外將軍令。", "外道當年入夢鄉，直至如今猶未省。"]'),
('1dc079a2-56f5-4aab-98b7-2dd0b07fc842','頌古九首  其二','釋善悟','宋','宋诗','song-poetry','','[]','祖師遠遠沒東土，面壁少林坐九年。',32,'全唐诗/poet.song.96000.json','["祖師遠遠沒東土，面壁少林坐九年。", "二祖傳心親得髓，算來早是已輪先。"]'),
('2681d389-309e-4bff-b200-3d4119a16415','頌古九首  其三','釋善悟','宋','宋诗','song-poetry','','[]','寶劍連飛急，透頂便通神。',24,'全唐诗/poet.song.96000.json','["寶劍連飛急，透頂便通神。", "有時輕按處，驚動五湖賓。"]'),
('cd19bbb8-2b7b-4612-b099-2ca9e818820d','頌古九首  其四','釋善悟','宋','宋诗','song-poetry','','[]','尋思去此地，清涼離煩暑。',48,'全唐诗/poet.song.96000.json','["尋思去此地，清涼離煩暑。", "暮雨朝雲樂太平，青山綠水人難睹。", "不難睹，深林有箇白額蟲，元來卻是玄沙虎。"]'),
('b39a2c3a-f63a-481f-aad0-88a9f54d2f48','頌古九首  其五','釋善悟','宋','宋诗','song-poetry','','[]','老清源，沒縫罅。',32,'全唐诗/poet.song.96000.json','["老清源，沒縫罅。", "問佛法，酬米價。", "衲僧一粒若沾唇，拄杖橫擔繞天下。"]'),
('0f373152-e173-43af-9d84-f2772229d304','頌古九首  其六','釋善悟','宋','宋诗','song-poetry','','[]','馬祖纔陞堂，百丈便卷席。',24,'全唐诗/poet.song.96000.json','["馬祖纔陞堂，百丈便卷席。", "春風一陣來，滿地花狼藉。"]'),
('6a0ec176-a0fa-4b0e-82ea-5a8d36e35b71','頌古九首  其七','釋善悟','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一口吸盡西江水，嶺上桃華香撲鼻。',32,'全唐诗/poet.song.96000.json','["一口吸盡西江水，嶺上桃華香撲鼻。", "枝枝葉葉盡含春，也是因我得禮你。"]'),
('8a80041f-5e20-4990-999a-3388d4c81972','頌古九首  其八','釋善悟','宋','宋诗','song-poetry','','[]','臺山路坦平，婆子苦商量。',24,'全唐诗/poet.song.96000.json','["臺山路坦平，婆子苦商量。", "趙州勘破了，清風滿大唐。"]'),
('d199e22a-af71-432b-ad82-d659dbf6ed2b','頌古九首  其九','釋善悟','宋','宋诗','song-poetry','','[]','因我得禮你，牽牛去飲水。',24,'全唐诗/poet.song.96000.json','["因我得禮你，牽牛去飲水。", "岸上蹄踏蹄，水中觜對觜。"]'),
('f5d33e02-88fe-49ec-974c-59bfdc060946','呈圓悟','釋祖覺','宋','宋诗','song-poetry','','[]','家住孤峰頂，長年半掩門。',24,'全唐诗/poet.song.96000.json','["家住孤峰頂，長年半掩門。", "自嗟身已老，活計付兒孫。"]'),
('30b64538-e24a-4ed4-8c8e-00c208c9356f','寄圓悟','釋祖覺','宋','宋诗','song-poetry','','[]','出林依舊入蓬蒿，天網恢恢不可逃。',32,'全唐诗/poet.song.96000.json','["出林依舊入蓬蒿，天網恢恢不可逃。", "誰信業緣無避處，歸來不怕語聲高。"]'),
('14a758a7-907e-4ae0-8c34-79a1e8592e61','偈','釋祖覺','宋','宋诗','song-poetry','','[]','一塵起，大地收。',36,'全唐诗/poet.song.96000.json','["一塵起，大地收。", "一葉落，天下秋。", "懸須彌於諸人鼻孔上，著大海於諸人眼睛中。"]'),
('2c0bb85a-64e9-4d30-a586-74c8b9cf1787','得仙亭','程瑀','宋','宋诗','song-poetry','','[]','危亭誰結據山椒，名第仙人不可招。',32,'全唐诗/poet.song.96000.json','["危亭誰結據山椒，名第仙人不可招。", "繞郭溪山敞圖畫，萬家樓閣插雲霄。"]'),
('86542c24-0209-4e76-8cc4-8b6c5c8d2f9b','拜程剛愍公墓','程瑀','宋','宋诗','song-poetry','','[]','早從賓客傅青扉，晚舉絲綸對紫微。',64,'全唐诗/poet.song.96000.json','["早從賓客傅青扉，晚舉絲綸對紫微。", "忠憤欲先同列死，塵沙驚繞屬車飛。", "墓間掛劍心猶在，帳下談經事已非。", "太學諸生皆白髮，汪汪老淚濕征衣。"]'),
('46b275f3-7a23-4001-a17f-fc7ed605a4c0','留隱軒','程瑀','宋','宋诗','song-poetry','','[]','先生骯髒與誰同，直道何妨竟不容。',64,'全唐诗/poet.song.96000.json','["先生骯髒與誰同，直道何妨竟不容。", "欲約故人酬素志，苦求晚節隱青松。", "圖開勝地詩篇重，客倦僧房野興濃。", "問舍求田端有日，從他百尺臥元龍。"]'),
('080c0037-4021-43cd-bdd1-dc285a34aaad','青峰山壯圖軒','程瑀','宋','宋诗','song-poetry','','[]','溪流洶涌激溪垠，土木頹移歲月新。',32,'全唐诗/poet.song.96000.json','["溪流洶涌激溪垠，土木頹移歲月新。", "爲問寺前圓也未，不應久負壯圖人。"]'),
('c171bd50-4da6-4650-b130-71d51e6fa1b5','句','程瑀','宋','宋诗','song-poetry','','[]','七年三破桃花浪。',8,'全唐诗/poet.song.96000.json','["七年三破桃花浪。"]'),
('157a9afa-0334-424d-8b0b-f8bf773cf393','忠節廟','劉岑','宋','宋诗','song-poetry','','[]','皇天祐宋生虎臣，奮身櫜鞬起西秦。',168,'全唐诗/poet.song.96000.json','["皇天祐宋生虎臣，奮身櫜鞬起西秦。", "勇義智略衛霍倫，西平云亡愬復興。", "疾首匈奴敢憑陵，恨不一舉空朔廷。", "鳴劍抵掌志幽幷，提兵北趨指神京。", "遇虜大點符離城，絳衣鐵冠目怒瞑。", "虜衆辟易屢竄奔，飛矢洞脇隕其身。", "帝心震悼詔廷紳，一旦失此飛將軍，作宮廟食妥其靈。", "生爲人雄死明神，雖歿不愧遠與巡。", "氣衝斗牛叩穹旻，臣魄尚能厲女真。", "鎮山之南勒堅珉，百世祀兮慰忠魂。"]'),
('429e99cd-47ee-4122-97ba-285267de0e98','貞女祠','劉岑','宋','宋诗','song-poetry','','[]','貞女已云遠，芳名聞至今。',48,'全唐诗/poet.song.96000.json','["貞女已云遠，芳名聞至今。", "煙波瀨江上，松柏古祠深。", "暮色留殘照，悲風動遠林。", "謫仙文不死，讀罷爲霑襟。"]'),
('c34852f2-687c-43d6-8816-80d5356951d5','留題寶相寺','陳堯臣','宋','宋诗','song-poetry','','[]','白雲樓殿翠林開，終日軒窗四面山。',32,'全唐诗/poet.song.96000.json','["白雲樓殿翠林開，終日軒窗四面山。", "卻愧勞生多事客，清涼分得片時閑。"]'),
('2156f546-f682-4aad-be10-3d7fc9a49493','贈妙靖鍊師','柯庭堅','宋','宋诗','song-poetry','','[]','絕粒棲神知幾年，閉關終日更翛然。',64,'全唐诗/poet.song.96000.json','["絕粒棲神知幾年，閉關終日更翛然。", "高風默與麻姑契，妙法親從嬰女傳。", "功行素超三界外，姓名清徹九重天。", "憑誰與問西王母，師是金華第幾仙。"]'),
('546efe4c-2762-4936-9285-5bde990f7427','游鶯脰湖','吳億','宋','宋诗','song-poetry','','[]','樹色煙光兩岸分，棹歌聲裏散鷗群。',64,'全唐诗/poet.song.96000.json','["樹色煙光兩岸分，棹歌聲裏散鷗群。", "船浮春水天疑近，人對春風酒易醺。", "翠袖不須花下舞，洞簫還待月中聞。", "仙游釣客今何在，湖上年年自白雲。"]'),
('d690e277-d672-42c6-bfc3-5f4e233742d7','磨崖中興頌','吳億','宋','宋诗','song-poetry','','[]','借問江頭人釣魚，爲言靈武事何如。',32,'全唐诗/poet.song.96000.json','["借問江頭人釣魚，爲言靈武事何如。", "磨崖豈是當時意，兩字噫嘻金鏡書。"]'),
('a81efb25-699a-4c5a-98a4-567d6de20ed7','讀邈上人翠微集','鄭億年','宋','宋诗','song-poetry','','[]','幾年祠館樂安閑，詩筆無聞老思慳。',64,'全唐诗/poet.song.96000.json','["幾年祠館樂安閑，詩筆無聞老思慳。", "謾把清篇遮病眼，每逢妙語解愁顔。", "定知道行超塵外，不使才名落世間。", "從此叢林推絕唱，未應後學便相班。"]'),
('f42f39a3-c111-44f2-b2b1-b842e7ee3140','和孫大夫贈開江沈察判','鄭億年','宋','宋诗','song-poetry','','[]','締構擁蒼岑，空林一徑深。',48,'全唐诗/poet.song.96000.json','["締構擁蒼岑，空林一徑深。", "嵐蒸四壁潤，雲鏁半窗陰。", "都寂世塵影，但清天籟音。", "若教支遁買，應倍沃洲金。"]'),
('c63db8d5-c879-4f18-a6e7-4dcfb7fc35ca','送知縣趙通直  其一','鄭億年','宋','宋诗','song-poetry','','[]','仁政三年有始終，陽關聲徹去匆匆。',64,'全唐诗/poet.song.96000.json','["仁政三年有始終，陽關聲徹去匆匆。", "森嚴治已冰霜比，慈愛臨民父母同。", "解印遠瞻京闕路，掛帆高颭楚天風。", "不須更問崑山事，已有歌謠達帝聰。"]'),
('0635bd92-3e38-442b-a71f-a408c10649e0','送知縣趙通直  其二','鄭億年','宋','宋诗','song-poetry','','[]','大門治邑歲年深，詒厥孫謀又到今。',64,'全唐诗/poet.song.96000.json','["大門治邑歲年深，詒厥孫謀又到今。", "遺愛聯綿民結戀，歸途迢遞柳垂陰。", "九莖芝草曾呈瑞，幷蔕荷花已賞心。", "或會朝廷求政績，何妨袖出野人吟。"]'),
('afcae53e-56ae-4fc8-914d-d15642d4b802','句','鄭億年','宋','宋诗','song-poetry','','[]','人逢歲稔家餘粟，地近嶺南冬不冰。',16,'全唐诗/poet.song.96000.json','["人逢歲稔家餘粟，地近嶺南冬不冰。"]'),
('ea5f6350-1765-40a7-986a-2b4c6aeb5950','金泉步虛臺','鄭庭芳','宋','宋诗','song-poetry','','[]','平生酷信退之詩，謝女仙蹤頗自疑。',32,'全唐诗/poet.song.96000.json','["平生酷信退之詩，謝女仙蹤頗自疑。", "不到步虛臺下看，瓊臺瑤佩有誰知。"]'),
('eb421f02-b69b-4324-b583-8ac161a25fcd','句','鄭庭芳','宋','宋诗','song-poetry','','[]','洗筆池頭煙淡淡，鳴琴臺畔水悠悠。',16,'全唐诗/poet.song.96000.json','["洗筆池頭煙淡淡，鳴琴臺畔水悠悠。"]'),
('2469217a-85b3-4949-8e7b-6e4f99b6549b','春日','趙𪛌之','宋','宋诗','song-poetry','','[]','拂牀欹枕晝初長，好夢驚回燕語忙。',32,'全唐诗/poet.song.96000.json','["拂牀欹枕晝初長，好夢驚回燕語忙。", "深竹有花人不見，直應風轉得幽香。"]'),
('799bd2d9-5124-4ba3-a781-cc1193bb1301','句','趙𪛌之','宋','宋诗','song-poetry','','[]','風生閭闔春來早，月到蓬萊夜未中。',16,'全唐诗/poet.song.96000.json','["風生閭闔春來早，月到蓬萊夜未中。"]'),
('3c663e7e-bb0f-4e3b-8d80-4112a5fec66c','題父墓亭','林若淵','宋','宋诗','song-poetry','','[]','虎踞龍蟠經幾春，靖康孤節照蒼旻。',32,'全唐诗/poet.song.96000.json','["虎踞龍蟠經幾春，靖康孤節照蒼旻。", "至今凜凜有生氣，愧死當年膜拜人。"]'),
('161cce46-a651-4d7a-b37b-243a1c063e99','詩一首','趙彥政','宋','宋诗','song-poetry','','[]','所歷登臨盡，愁新屈子居。',48,'全唐诗/poet.song.96000.json','["所歷登臨盡，愁新屈子居。", "青脩一嶂遠，紅蓼幾花疏。", "直節乾坤外，騷文雅頌餘。", "殷勤酹江月，生氣凜如初。"]'),
('e9b7329f-8492-4069-8ee1-97c5b001f9ca','山中訪友不遇','趙師固','宋','宋诗','song-poetry','','[]','久思成德士，家居山裹山。',48,'全唐诗/poet.song.96000.json','["久思成德士，家居山裹山。", "雲深何憚遠，路險不知難。", "幽鳥藏林語，殘花點石斑。", "行蹤無覓處，惆悵自空還。"]'),
('b8134d22-c4e2-4d20-ad67-f527145a62e3','石門巖','趙師立','宋','宋诗','song-poetry','','[]','勝境傳天下，曾封第七山。',48,'全唐诗/poet.song.96000.json','["勝境傳天下，曾封第七山。", "一巖懸石際，萬木插雲間。", "鳥過暮天碧，牛眠冬日閑。", "歌聲初隱隱，疑自武陵還。"]'),
('0ef72734-6ddd-4785-96aa-21f9c77cfa12','句','秦觀女','宋','宋诗','song-poetry','','[]','眼前雖有還鄉路，馬上曾無放我情。',16,'全唐诗/poet.song.96000.json','["眼前雖有還鄉路，馬上曾無放我情。"]'),
('2a580566-b57c-4ec0-bff5-037583efb7ad','句','賈如訥','宋','宋诗','song-poetry','','[]','洞房人不見，相望摘楊花。',12,'全唐诗/poet.song.96000.json','["洞房人不見，相望摘楊花。"]'),
('ddf8a95c-2a2a-4f7b-bd7a-52b21d7162ec','苕溪','賈安宅','宋','宋诗','song-poetry','','["\u592a\u6e56"]','廣苕山下源深，發此清流去不渾。',31,'全唐诗/poet.song.96000.json','["廣苕山下源深，發此清流去不渾。", "直扺太湖三百里，滔滔分入海天門。"]'),
('34aa1548-3df6-45f4-beff-494cabeb0f4a','留題山谷寺','陸宰','宋','宋诗','song-poetry','','[]','芙蓉已入雙林寂，山谷今傳佛祖衣。',32,'全唐诗/poet.song.96000.json','["芙蓉已入雙林寂，山谷今傳佛祖衣。", "千里客來何所遇，夜堂人靜雨霏霏。"]'),
('3d55c8f8-9ac6-4556-bc78-53170f31c070','留別東陽','陸宰','宋','宋诗','song-poetry','','[]','前身疑是此山僧，猿鶴相逢亦有情。',32,'全唐诗/poet.song.96000.json','["前身疑是此山僧，猿鶴相逢亦有情。", "珍重嶺頭風與月，百年常記老夫名。"]'),
('14bfcac6-9f5b-4652-89ca-48142b974898','句  其一','陸宰','宋','宋诗','song-poetry','','[]','奴愛才如蕭穎士，婢知詩鄭康成。',15,'全唐诗/poet.song.96000.json','["奴愛才如蕭穎士，婢知詩鄭康成。"]'),
('4f66beec-a369-4e59-957a-77952f986fb2','句  其二','陸宰','宋','宋诗','song-poetry','','[]','歲月悠悠悲往事，川原冉冉夢重遊。',16,'全唐诗/poet.song.96000.json','["歲月悠悠悲往事，川原冉冉夢重遊。"]'),
('a28abe82-b8a4-4fb6-8c90-d72a3354325c','建炎丞相成國呂忠穆公退老堂詩二首  其一','薛弼','宋','宋诗','song-poetry','','[]','濟南從古多名士，崛起皋夔薊北空。',64,'全唐诗/poet.song.96000.json','["濟南從古多名士，崛起皋夔薊北空。", "君喜有堂堪逸老，上嫌無職可酬功。", "蒼生日願起安石，綠野今難留晉公。", "盛烈屢勤銘鼎鼐，龍韜猶冀感雲風。"]'),
('abebd623-1055-43af-9b18-b232924a196f','建炎丞相成國呂忠穆公退老堂詩二首  其二','薛弼','宋','宋诗','song-poetry','','[]','卜築追尋九老游，江南最好是丹丘。',64,'全唐诗/poet.song.96000.json','["卜築追尋九老游，江南最好是丹丘。", "乞將金鼎調元手，暫向磻溪理釣舟。", "東閣蚤延天下雋，畫堂春鎖海中洲。", "他年共看車書一，舉目山河笑楚囚。"]'),
('2b9965f0-5133-4f8f-a711-d7f81e5c2ac5','句','薛弼','宋','宋诗','song-poetry','','[]','南縣富角鹽，沿田勞少休。',12,'全唐诗/poet.song.96000.json','["南縣富角鹽，沿田勞少休。"]'),
('8f9ff981-5311-42fa-8c74-05473847755d','龐祐甫卜居白蘋洲走筆寄感','何鑄','宋','宋诗','song-poetry','','[]','君愛白蘋洲，攜家面碧流。',48,'全唐诗/poet.song.96000.json','["君愛白蘋洲，攜家面碧流。", "皇程惟百里，宦跡只扁舟。", "過盡江淮地，何如宛洛游。", "行宮催種柳，禾黍滿神州。"]'),
('e006ab61-8ec5-4ad4-b9c8-6eb33eb980f1','鳬山廟','李宏','宋','宋诗','song-poetry','','[]','鳬山高與蒼旻訓示，根盤八里雄坤維。',386,'全唐诗/poet.song.96000.json','["鳬山高與蒼旻訓示，根盤八里雄坤維。", "油然出雲爲風雨，澤周一境無凶饑。", "重樓複殿據山腹，蜿蜒攫護神□□。", "威靈如在駭聞聽，至今父老能言之。", "斷碑刓缺尚可讀，湮埋歲久人無知。", "高高一峰獨秀出，上有蟬蛻真仙居。", "似聞嘗任石埭尹，化流德洽真民師。", "持竿戲投白龍餌，隱霧深韜玄豹姿。", "手披蕊笈校丹篆，足躡飛昇騰紫微。", "相逢邂逅一笑粲，真將莫逆論心期。", "從茲來往因無間，遺蹤所至猶可推。", "弦歌標鄉里猶在，望仙紀地名獨垂。", "棲真發寄偉曾稅駕，絕頂尚留丹竈基。", "近鄰眢井數盈九，石甃堅深端可窺。", "神既廟食還舊隱，仙亦偶坐應禱祈。", "合堂薦享異肴蔌，乞靈修敬傾里閭。", "政和天子謹祠祭，郡縣有請咸勿違。", "一朝飛章達旒扆，往往一夜曾躬披。", "俞音載錫降芝簡，龐賁徽名昭典彝。", "神兮仙兮服君賜，福庇斯民無已時。", "仙將出遊神速往，霓旌絳節相追隨。", "神既來歸仙至止，袞衣羽帔瞻光儀。", "繄予頂謁亦云屢，淋漓醉墨聊一揮。", "詞雖蕪纇事摭實，庶幾傳信祛群疑。"]'),
('6665cf04-06bc-4f94-8c37-d3c72b264715','遊天休觀道流索詩','李宏','宋','宋诗','song-poetry','','[]','霓旌羽蓋下飛仙，名揭司真列洞天。',64,'全唐诗/poet.song.96000.json','["霓旌羽蓋下飛仙，名揭司真列洞天。", "一派銀河懸落水，數峰石壁鎖霏煙。", "潭心雷殷龍應出，井口風迴虎未旋。", "端欲相從老巖壑，凌雲已覺意飄然。"]'),
('ab45d022-6522-47ec-8e5e-bee4825ae3ec','宿秋霜閣方丈','李宏','宋','宋诗','song-poetry','','[]','青山夭矯虯龍蟠，溪流瀉竭灘聲乾。',32,'全唐诗/poet.song.96000.json','["青山夭矯虯龍蟠，溪流瀉竭灘聲乾。", "履霜未落秋尚早，夜半已作貂裘寒。"]'),
('9ee3801b-2d50-4370-9910-22d1aac00262','和呂居仁涇縣旌德道中見寄三首  其一','李宏','宋','宋诗','song-poetry','','[]','筍輿破曉踏新霜，千里調安遠辦裝。',32,'全唐诗/poet.song.96000.json','["筍輿破曉踏新霜，千里調安遠辦裝。", "會約明年追勝集，茱萸細把記重陽。"]'),
('42b4f645-a109-4106-bc87-de8ec6845387','和呂居仁涇縣旌德道中見寄三首  其二','李宏','宋','宋诗','song-poetry','','[]','山環傑閣染深綠，石吐寒泉蹙浪花。',32,'全唐诗/poet.song.96000.json','["山環傑閣染深綠，石吐寒泉蹙浪花。", "一夜秋霜不成寐，感時憂國思無涯。"]'),
('33ffa97a-5fd5-4179-9dbd-5c7207ba9a02','和呂居仁涇縣旌德道中見寄三首  其三','李宏','宋','宋诗','song-poetry','','[]','賞溪漱玉聲湍激，石壁參天路阻長。',32,'全唐诗/poet.song.96000.json','["賞溪漱玉聲湍激，石壁參天路阻長。", "準擬解鞍能過我，新泉活火茗甌香。"]'),
('5dc8afd7-4eb1-4d7b-8808-641397acc031','舟中','李宏','宋','宋诗','song-poetry','','[]','湖闊帆風飽，山長眼力疲。',48,'全唐诗/poet.song.96000.json','["湖闊帆風飽，山長眼力疲。", "晚涼行進酒，秋色最宜詩。", "別意果作惡，虛名難療饑。", "此生無住着，投老欲何之。"]'),
('239a96ba-77df-407c-92b6-cf46392af78a','青山道中','李宏','宋','宋诗','song-poetry','','[]','田舍雞升屋，山家犬應門。',48,'全唐诗/poet.song.96000.json','["田舍雞升屋，山家犬應門。", "馬行黄葉路，水繞夕陽村。", "老覺貧爲累，吾知道可尊。", "此行聊爾耳，萬事信乾坤。"]'),
('72f05ca2-ab21-4582-bbde-98e724112ef6','陳村道中','李宏','宋','宋诗','song-poetry','','[]','筍輿乘晚上，詰曲過前衝。',48,'全唐诗/poet.song.96000.json','["筍輿乘晚上，詰曲過前衝。", "石怪形難似，山深不計重。", "亂流奔絕壑，險徑躡危峰。", "重難爲農苦，辛勤更歲凶。"]'),
('8c25fd89-5dff-4e97-80fc-b77e80710e99','存目','李宏','宋','宋诗','song-poetry','','[]','詩題：遊金泉觀首句：昔時謝女昇天處。',18,'全唐诗/poet.song.96000.json','["詩題：遊金泉觀首句：昔時謝女昇天處。"]'),
('88c810c6-6165-4fa7-959b-f0457869a4f7','偈頌二十九首  其一','釋清了','宋','宋诗','song-poetry','','[]','不假千頭說，熾然無閑歇。',58,'全唐诗/poet.song.96000.json','["不假千頭說，熾然無閑歇。", "深密密處光彩頓生，明歷歷時混融皎潔。", "若也和身放倒，隨流任真。", "始信百般計較不成，運用本無欠缺。"]'),
('c6d0bd9b-7980-49c1-a4f4-c3afe7032571','偈頌二十九首  其二','釋清了','宋','宋诗','song-poetry','','[]','傍參密旨，妙會玄宗。',51,'全唐诗/poet.song.96000.json','["傍參密旨，妙會玄宗。", "句在混沌前，豈涉今時路。", "在無舕人解語，無情者皆聞。", "通途消耗不分時，靈脈浩流無閑處。"]'),
('5a11142d-b323-49a0-a660-4de4b1d71a01','偈頌二十九首  其三','釋清了','宋','宋诗','song-poetry','','[]','暗裏抽橫骨，彌天句已彰。',52,'全唐诗/poet.song.96000.json','["暗裏抽橫骨，彌天句已彰。", "明中坐舌頭，匝地無紋彩。", "混不容其迹，照不留其痕。", "金烏子夜出乾坤，濃雲停午生嶽面。"]'),
('0d2505cf-9371-4473-8f71-8515e7c04740','偈頌二十九首  其四','釋清了','宋','宋诗','song-poetry','','[]','窮微喪本，體妙失宗。',20,'全唐诗/poet.song.96000.json','["窮微喪本，體妙失宗。", "一句截流，淵源及盡。"]'),
('2a7a466c-3d1b-40b4-b943-97cc13e90efb','偈頌二十九首  其五','釋清了','宋','宋诗','song-poetry','','[]','粗中辨細，門裏出身。',62,'全唐诗/poet.song.96000.json','["粗中辨細，門裏出身。", "石女不孤，機梭暗泄。", "細中辨粗，身裏出門。", "暖氣雖消巖上雪，冰壺未破劫前春。", "六門活計冷翛然，萬頃琉璃寒徹骨。"]'),
('8e5d6fbe-ceb8-4a50-bec5-2a915225a400','偈頌二十九首  其六','釋清了','宋','宋诗','song-poetry','','[]','居動而常寂，處暗而愈明。',38,'全唐诗/poet.song.96000.json','["居動而常寂，處暗而愈明。", "不墮二邊機，當頭誰敢觸。", "正按傍提有據，真慈妙應無窮。"]'),
('832cac7c-0c19-4db5-b44a-c9e3d5b5e46e','偈頌二十九首  其七','釋清了','宋','宋诗','song-poetry','','[]','虛玄及盡，見處偏枯。',20,'全唐诗/poet.song.96000.json','["虛玄及盡，見處偏枯。", "明湛不搖，想中滲漏。"]'),
('3bc4df7f-57d5-4e4c-be44-d925557a4d72','偈頌二十九首  其八','釋清了','宋','宋诗','song-poetry','','[]','藏身處，沒蹤跡，浩意融時誰辨的。',48,'全唐诗/poet.song.96000.json','["藏身處，沒蹤跡，浩意融時誰辨的。", "沒蹤跡處莫藏身，驀移步處妙難尋。", "枯根石裏花明秀，劫外威光密密新。"]'),
('0688d7b4-20c7-42b3-a45b-88606d7999b0','偈頌二十九首  其九','釋清了','宋','宋诗','song-poetry','','[]','無功妙旨，不涉玄徽。',64,'全唐诗/poet.song.96000.json','["無功妙旨，不涉玄徽。", "一念潛通，全機密運。", "易奏高山流水曲，難傳虛空夜明符。", "暗中靈句許誰知，化外威光須自看。", "不行青嶂路，爭到白雲根。"]'),
('b2536539-3eec-4d82-b2a3-db6bf48a7a40','偈頌二十九首  其一○','釋清了','宋','宋诗','song-poetry','','[]','家音歷歷，的要難通。',50,'全唐诗/poet.song.96000.json','["家音歷歷，的要難通。", "紹了非功，忘其擔荷。", "戶上有動從斷徑，坐中無照勝燃燈。", "既知活計現成，便合深沈消耗。"]'),
('83164e91-0362-4c20-aeb6-c076e1625cf0','偈頌二十九首  其一一','釋清了','宋','宋诗','song-poetry','','[]','剎塵一掃，大小量空，念劫兩融。',40,'全唐诗/poet.song.96000.json','["剎塵一掃，大小量空，念劫兩融。", "前後際斷，不離當處，圓應無窮。", "安住是中，周施不怠。"]'),
('a8af00d3-c6b1-4025-96d0-9b1522596b65','偈頌二十九首  其一二','釋清了','宋','宋诗','song-poetry','','[]','未休休去，未歇歇去。',24,'全唐诗/poet.song.96000.json','["未休休去，未歇歇去。", "豁然寶鏡當臺，無限清光滿戶。"]'),
('0602339a-37c6-4104-aba7-accee906c1ba','偈頌二十九首  其一三','釋清了','宋','宋诗','song-poetry','','[]','莫怪石頭饒舌，便道靈源明皎潔。',58,'全唐诗/poet.song.96000.json','["莫怪石頭饒舌，便道靈源明皎潔。", "功成照不失虛，妙盡明無間歇。", "如今果爾難藏，盡逐秋光漏泄。", "/爲報海內道人，參取箇中時節。"]'),
('f07d0a41-f3c0-4b5b-ac3f-07e6c6d88107','偈頌二十九首  其一四','釋清了','宋','宋诗','song-poetry','','[]','披毛遊火聚，焰裏藏身；戴角混塵泥，光中轉步。',42,'全唐诗/poet.song.96000.json','["披毛遊火聚，焰裏藏身；戴角混塵泥，光中轉步。", "靈珠絕點，卞玉無瑕。", "一念廓融，千機秀發。"]'),
('f942b575-9623-4794-aa05-be25b73225f9','偈頌二十九首  其一五','釋清了','宋','宋诗','song-poetry','','[]','裏許明如日，絲毫無隔礙。',42,'全唐诗/poet.song.96000.json','["裏許明如日，絲毫無隔礙。", "一靈不假胞胎，四大孰爲主宰。", "如今徹底露堂堂，運用隨緣常自在。"]'),
('8a7f6a25-0706-47c2-98cc-3e291ce97e41','偈頌二十九首  其一六','釋清了','宋','宋诗','song-poetry','','[]','終日分別，只是分別自心。',51,'全唐诗/poet.song.96000.json','["終日分別，只是分別自心。", "堪笑念彼觀音力，畢竟還著於本人。", "黄頭老衲，有理難伸。", "爲什麽有理難伸，賊是家親。"]'),
('9c7e70cd-8a46-42ab-9ab0-657230cbd01f','偈頌二十九首  其一七','釋清了','宋','宋诗','song-poetry','','[]','雨洗摩尼增秀色，全身不昧一絲頭。',32,'全唐诗/poet.song.96000.json','["雨洗摩尼增秀色，全身不昧一絲頭。", "靈源傾瀉無閑歇，添得滁山水逆流。"]'),
('bd7f1319-7f76-4bc9-9457-adc382143e79','偈頌二十九首  其一八','釋清了','宋','宋诗','song-poetry','','[]','沿流無定止，真照不留蹤。',48,'全唐诗/poet.song.96000.json','["沿流無定止，真照不留蹤。", "千峰秀處鶴難栖，萬水澄時魚自穩。", "樵人罷賞，釣客迷巢，古渡深雲，同歌絕韻。"]'),
('1be17c78-fc3b-4087-86a7-bfbf781adb5a','偈頌二十九首  其一九','釋清了','宋','宋诗','song-poetry','','[]','日月鎮長靈，古今常不改。',40,'全唐诗/poet.song.96000.json','["日月鎮長靈，古今常不改。", "如何特地新，各要施三拜。", "及盡無依體自玄，雙六盆中休喝彩。"]'),
('cf31e153-40d4-45e4-acdb-f5fa03019573','偈頌二十九首  其二○','釋清了','宋','宋诗','song-poetry','','[]','機回明位，妙盡轉身。',50,'全唐诗/poet.song.96000.json','["機回明位，妙盡轉身。", "一夢青山，滿船白月。", "子夜雲收碧漢，中秋露混銀河。", "蘆花深處驀相逢，談笑飲茶無處避。"]'),
('62fb062c-df2b-4070-b1b1-b49d8e29096f','偈頌二十九首  其二一','釋清了','宋','宋诗','song-poetry','','[]','百億毛頭，花開不犯春風。',60,'全唐诗/poet.song.96000.json','["百億毛頭，花開不犯春風。", "三冬雪裏，爭芳全彰浩意。", "雲凝谷曉，滴水冰生。", "活計現成，憑誰受用。", "頭上青灰三五斗，明明不墮曉來機。"]'),
('90d27c31-87bf-4c9d-811b-ed6f9b924662','偈頌二十九首  其二二','釋清了','宋','宋诗','song-poetry','','[]','祇恁麽，休尋覓，見成堂堂忘得失。',60,'全唐诗/poet.song.96000.json','["祇恁麽，休尋覓，見成堂堂忘得失。", "假使心通無量時，歷劫何曾異今日。", "聖僧堂裏坐，金剛門外立。", "廣長舌相耀乾坤，半夜烏飛白如漆。"]'),
('67ff1e23-7e1d-4b4f-8493-c8a9597e02c6','偈頌二十九首  其二三','釋清了','宋','宋诗','song-poetry','','[]','運步不當機，箇中無肯路。',40,'全唐诗/poet.song.96000.json','["運步不當機，箇中無肯路。", "明密浩難齊，未前超佛祖。", "及盡回途恁麽來，撒手相逢無回互。"]'),
('e3520413-c9a9-4fa5-80b8-1adf526926df','偈頌二十九首  其二四','釋清了','宋','宋诗','song-poetry','','[]','旨外明宗，玄中辨的。',64,'全唐诗/poet.song.96000.json','["旨外明宗，玄中辨的。", "古帆不掛，洞水逆流。", "黄蘆渡口奏陽春，偃月城頭吹畫角。", "豈止異苗繁茂，須知別有圓音。", "更休爛炒浮漚，便請乘時撒手。"]'),
('553b2286-9372-46e0-bbf8-17e9cabbc59b','偈頌二十九首  其二五','釋清了','宋','宋诗','song-poetry','','[]','純清絕點，似鏡長明。',40,'全唐诗/poet.song.96000.json','["純清絕點，似鏡長明。", "照不失虛，萬像體妙。", "細中之細，雪盡冰消。", "功就之功，任運現成。"]'),
('8fb5717d-a15d-4376-bbec-dc96953770bf','偈頌二十九首  其二六','釋清了','宋','宋诗','song-poetry','','[]','世尊有密語，古渡春殘。',46,'全唐诗/poet.song.96000.json','["世尊有密語，古渡春殘。", "迦葉不覆藏，落花流水。", "見聞覺知絕，四維上下通。", "玉鳳舞中霄，金輪舒半夜。"]'),
('54fd107b-579b-474b-9600-312113ad013f','偈頌二十九首  其二七','釋清了','宋','宋诗','song-poetry','','[]','幻滅滅故，非幻不滅。',36,'全唐诗/poet.song.96000.json','["幻滅滅故，非幻不滅。", "光無不透，明無不徹。", "長歌吹起棹頭風，永夜恣眠篷底月。"]'),
('a953c121-97a7-495c-9813-a821c1b0cd68','偈頌二十九首  其二八','釋清了','宋','宋诗','song-poetry','','[]','虛而靈，寂而妙。',18,'全唐诗/poet.song.96000.json','["虛而靈，寂而妙。", "明密浩然，猶落鑑照。"]'),
('0393fa5a-9710-468c-a183-fede6039e1d4','偈頌二十九首  其二九','釋清了','宋','宋诗','song-poetry','','[]','道得第一句，不被拄杖子瞞。',25,'全唐诗/poet.song.96000.json','["道得第一句，不被拄杖子瞞。", "識得拄杖子，猶是途中事。"]'),
('2f1125c6-be90-4775-9835-0c4df1cbdca8','答佛果頌','釋清了','宋','宋诗','song-poetry','','[]','運用堂堂本妙，徹底不落鑑照。',28,'全唐诗/poet.song.96000.json','["運用堂堂本妙，徹底不落鑑照。", "一言及盡鋒鋩，只箇更無孔竅。"]'),
('d3776b63-dfe5-4407-87f1-68a77a5b78a4','贈祥雲庵主頌','釋清了','宋','宋诗','song-poetry','','[]','相逢相揖眼如眉，百鳥銜花尚未歸。',32,'全唐诗/poet.song.96000.json','["相逢相揖眼如眉，百鳥銜花尚未歸。", "回首春風吹夢斷，舊山雲散月明時。"]'),
('b9072a6c-dfe5-478b-b14d-e973849afb47','偈頌十首  其一','釋清了','宋','宋诗','song-poetry','','[]','兀兀不忘機巧，灰來已得純。',49,'全唐诗/poet.song.96000.json','["兀兀不忘機巧，灰來已得純。", "虛明無間斷，凈妙絕疏親。", "密戶寒燈曉，靈花古洞春。", "回途賡雪韻，門裏綠苔新。"]'),
('ba75111d-1d42-47a8-ab65-59e0aff340a0','偈頌十首  其二','釋清了','宋','宋诗','song-poetry','','[]','湛寂凝然透，孤明徹底空。',48,'全唐诗/poet.song.96000.json','["湛寂凝然透，孤明徹底空。", "秋風生古韻，曉月上寒松。", "量外千差泯，機前六用通。", "應緣成底事，畢竟不留蹤。"]'),
('bd089b15-ba2a-42e4-9f2e-2d2fa320571d','偈頌十首  其三','釋清了','宋','宋诗','song-poetry','','[]','意句難分別，風騷格外求。',48,'全唐诗/poet.song.96000.json','["意句難分別，風騷格外求。", "提刀空四顧，駐步失全牛。", "落眼情塵脫，歸根景象幽。", "萬緣俱不到，佛祖莫能酬。"]'),
('6145b5ad-bd30-4181-8756-99efa1bcc6ad','偈頌十首  其四','釋清了','宋','宋诗','song-poetry','','[]','徹澄無凝礙，情塵迥脫然。',48,'全唐诗/poet.song.96000.json','["徹澄無凝礙，情塵迥脫然。", "全機忘照外，一句未分前。", "枯木雲籠透，寒潭月夜圓。", "回頭開正眼，芳草破春煙。"]'),
('f74d7a03-cd01-4234-b682-ca749f4a65c3','偈頌十首  其五','釋清了','宋','宋诗','song-poetry','','[]','只麽堆堆地，常光密露時。',48,'全唐诗/poet.song.96000.json','["只麽堆堆地，常光密露時。", "玄途明絕朕，妙體廓忘依。", "正去功中轉，傍來曉路歸。", "絲毫都及盡，不覺口如眉。"]'),
('5c4dbe6a-3174-47c0-b0a3-b0632b43a880','偈頌十首  其六','釋清了','宋','宋诗','song-poetry','','[]','絕點純清處，由來是半提。',48,'全唐诗/poet.song.96000.json','["絕點純清處，由來是半提。", "虛空休照鏡，混沌莫粧眉。", "隱隱忘兼带，寥寥罷曉機。", "雪消寒谷暖，花笑不萌枝。"]'),
('5874f3f0-f508-4535-a724-d80316fe7b82','偈頌十首  其七','釋清了','宋','宋诗','song-poetry','','[]','不犯清波句，澄江涵一鉤。',48,'全唐诗/poet.song.96000.json','["不犯清波句，澄江涵一鉤。", "棹頭忘一色，功盡喪全機。", "密混凝流處，融通向背時。", "古帆風靜夜，任運應高低。"]'),
('4e6e5667-02b7-4dd4-9f78-9813e60e4daf','偈頌十首  其八','釋清了','宋','宋诗','song-poetry','','[]','密密梭頭事，機絲不掛時。',48,'全唐诗/poet.song.96000.json','["密密梭頭事，機絲不掛時。", "木雞啼曉戶，石女夜生兒。", "已發寒灰焰，難埋古冢碑。", "荒郊春草綠，風暖共依依。"]'),
('a79f2c80-78de-4b49-be68-74aaa688e1b9','偈頌十首  其九','釋清了','宋','宋诗','song-poetry','','[]','鳥道通身去，迢迢劫外參。',48,'全唐诗/poet.song.96000.json','["鳥道通身去，迢迢劫外參。", "隨流忘朕兆，癡兀未曾閑。", "瞬視成途轍，揚眉落二三。", "只應無見頂，子夜白雲漫。"]'),
('410e8e73-04a1-4f05-befc-e635ea98b8ae','頌古四首  其一','釋清了','宋','宋诗','song-poetry','','[]','寒明一點墮空林，朕兆依俙已觸今。',32,'全唐诗/poet.song.96000.json','["寒明一點墮空林，朕兆依俙已觸今。", "目擊正容成滲漏，青天白日轉迷人。"]'),
('dcb29856-3b77-493f-8bd4-d59d1e067684','頌古四首  其二','釋清了','宋','宋诗','song-poetry','','[]','乾坤那畔類難齊，千聖從來不識伊。',32,'全唐诗/poet.song.96000.json','["乾坤那畔類難齊，千聖從來不識伊。", "家破人亡迷肯重，夜深寒塔影空垂。"]'),
('04e71a6e-f717-446e-bdfb-dc52c8a6a256','頌古四首  其三','釋清了','宋','宋诗','song-poetry','','[]','萬緣歇盡照無時，撒手忘依有路歸。',32,'全唐诗/poet.song.96000.json','["萬緣歇盡照無時，撒手忘依有路歸。", "劫外一壺春色暖，靈苗石上正芳菲。"]'),
('1a98a500-ecca-4f85-9587-5ce952182785','頌古四首  其四','釋清了','宋','宋诗','song-poetry','','[]','線道難分處，須知不是伊。',24,'全唐诗/poet.song.96000.json','["線道難分處，須知不是伊。", "牛頭按尾上，豈借大陽輝。"]'),
('dd4506c0-492f-44e2-a5be-fff47c39e6cc','宣和癸卯宴坐自讚','釋清了','宋','宋诗','song-poetry','','[]','三十六年作怪，撞入者箇皮袋。',58,'全唐诗/poet.song.96000.json','["三十六年作怪，撞入者箇皮袋。", "一千七百衲僧，被你熱瞞忒煞。", "如今坐斷舌頭，直下大千俱壞。", "劫外迢迢曉末明，休把虛空粧五彩。"]'),
('6f18556e-4e7a-4b3a-8891-9b30ef13becd','自贊','釋清了','宋','宋诗','song-poetry','','[]','信口胡說，七差八錯。',53,'全唐诗/poet.song.96000.json','["信口胡說，七差八錯。", "萬劫千生，不妨快活。", "情願生形形色色輪回，肯求諸聖解說。", "誰言遍界沒遮欄，雨過青山雲一抹。"]'),
('e2f3d257-c44a-4b3d-b2b7-3bf29916ba78','偈','釋清了','宋','宋诗','song-poetry','','[]','天曉濃霜白，依然境末分。',24,'全唐诗/poet.song.96000.json','["天曉濃霜白，依然境末分。", "出門無所辨，華鳥寂無聞。"]'),
('f21f8965-d606-419b-8539-e7e25e2e7ed1','頌古二首  其一','釋清了','宋','宋诗','song-poetry','','[]','離鈎三寸如何道，駐擬還同眼裏沙。',32,'全唐诗/poet.song.96000.json','["離鈎三寸如何道，駐擬還同眼裏沙。", "篷底月明載歸去，劫前風韻落誰家。"]'),
('4ac46bcc-25ad-49e4-a7bc-37cc150788b0','頌古二首  其二','釋清了','宋','宋诗','song-poetry','','[]','問佛分明答惠超，半斤八兩不合相饒。',33,'全唐诗/poet.song.96000.json','["問佛分明答惠超，半斤八兩不合相饒。", "叢林萬古爲殃禍，惡語傷人恨不消。"]'),
('431aac53-7598-47dc-9bbe-a1b49c60567b','贈清了頌','釋佛果','宋','宋诗','song-poetry','','[]','宣化渡頭作別，譬如兩鏡相照。',30,'全唐诗/poet.song.96000.json','["宣化渡頭作別，譬如兩鏡相照。", "何止千里同幾百個，全是向上一竅。"]'),
('cfadbfdc-77e8-49ab-9190-ea25fde907f3','句','蔡伸','宋','宋诗','song-poetry','','[]','山水同三峽，煙霞似十洲。',12,'全唐诗/poet.song.96000.json','["山水同三峽，煙霞似十洲。"]'),
('db7fcd5a-6505-466f-9dac-2b9dfa154f38','偕范賢良遊天王寺登城晚歸三絕  其一','樓炤','宋','宋诗','song-poetry','','[]','帝城高堞建朱旗，號召征人厚古陴。',32,'全唐诗/poet.song.96000.json','["帝城高堞建朱旗，號召征人厚古陴。", "祇是北風關隘重，紛紛策士說匡時。"]'),
('4c9d9d24-0a89-4312-b35b-7f824ea571f5','偕范賢良遊天王寺登城晚歸三絕  其二','樓炤','宋','宋诗','song-poetry','','[]','花柳逢春色自妍，天王宮殿五雲邊。',32,'全唐诗/poet.song.96000.json','["花柳逢春色自妍，天王宮殿五雲邊。", "署郎漫入招提境，不是探玄學慕仙。"]'),
('c3d3f148-e7ab-4999-818f-7289926fda34','偕范賢良遊天王寺登城晚歸三絕  其三','樓炤','宋','宋诗','song-poetry','','[]','日落園林淡蕩風，晚雲參錯若相攻。',32,'全唐诗/poet.song.96000.json','["日落園林淡蕩風，晚雲參錯若相攻。", "分明陣勢天邊列，諸葛神謀一望中。"]'),
('4f5bf1a7-a707-4692-8929-65a94057b667','壽太師  其一','吳順之','宋','宋诗','song-poetry','','[]','堯舜垂衣明日月，皋夔論道際風雲。',32,'全唐诗/poet.song.96000.json','["堯舜垂衣明日月，皋夔論道際風雲。", "須知天地生成德，間世真儒輔聖君。"]'),
('fa6fe8eb-b027-46a9-acb5-cbf60a504a30','壽太師  其二','吳順之','宋','宋诗','song-poetry','','[]','南北通和自古無，如今萬里混車書。',32,'全唐诗/poet.song.96000.json','["南北通和自古無，如今萬里混車書。", "傳聞每遣皇華使，外國人爭問起居。"]'),
('4056e3ea-455d-4864-b186-dd7976972ca6','壽太師  其三','吳順之','宋','宋诗','song-poetry','','[]','德望巖巖魯太山，功成天地亦清閑。',32,'全唐诗/poet.song.96000.json','["德望巖巖魯太山，功成天地亦清閑。", "不須百丈磨崖刻，碑在農桑樂業間。"]'),
('f7895b80-302e-463a-8bc5-ac593c198e53','壽太師  其四','吳順之','宋','宋诗','song-poetry','','[]','西風原上撥黄雲，歸作人間甕裏春。',32,'全唐诗/poet.song.96000.json','["西風原上撥黄雲，歸作人間甕裏春。", "拍手一樽歌既醉，閭閻俱是太平民。"]'),
('c8f90874-41ea-453a-8934-c030a9e0fc55','壽太師  其五','吳順之','宋','宋诗','song-poetry','','[]','老農含笑指家丁，偃伯靈臺始見生。',32,'全唐诗/poet.song.96000.json','["老農含笑指家丁，偃伯靈臺始見生。", "身手只今大如許，耳根不識鼓鼙聲。"]'),
('a698996d-dc19-463f-9f19-9675aebfeeb7','壽太師  其六','吳順之','宋','宋诗','song-poetry','','[]','年年周孔道何多，誰爲緇黄保不磨。',32,'全唐诗/poet.song.96000.json','["年年周孔道何多，誰爲緇黄保不磨。", "卻笑紛紛韓孟輩，空言無奈異端何。"]'),
('9cb9b21d-3e71-4655-a556-3b968f522fd9','壽太師  其七','吳順之','宋','宋诗','song-poetry','','[]','當年崧嶽降生申，底事先春五日期。',64,'全唐诗/poet.song.96000.json','["當年崧嶽降生申，底事先春五日期。", "要是窮冬正冰雪，斡回和氣遍華夷。", "群生無路答昇平，只有年年善頌聲。", "長願遙天無點翳，台星兩兩倍光明。"]'),
('78b04e13-30f2-47dd-b2fa-b0bf85ff0ccf','壽太師  其八','吳順之','宋','宋诗','song-poetry','','[]','下吏南州把郡符，除恩猶未放江湖。',32,'全唐诗/poet.song.96000.json','["下吏南州把郡符，除恩猶未放江湖。", "誕辰再拜無他祝，願獻蓬萊清淺圖。"]'),
('b0596f5d-38c3-4f1e-bfba-3e6cc1f79e10','壽太師  其九','吳順之','宋','宋诗','song-poetry','','[]','萬古叢中見玉英，天教正味合和羹。',32,'全唐诗/poet.song.96000.json','["萬古叢中見玉英，天教正味合和羹。", "枝頭春色無窮在，乞與年年薦壽觥。"]'),
('48bf8650-a3f8-4a48-b842-48d47f79eff2','杼峰','汪勃','宋','宋诗','song-poetry','','[]','夏后峰前思盛業，魯公亭畔憶孤忠。',32,'全唐诗/poet.song.96000.json','["夏后峰前思盛業，魯公亭畔憶孤忠。", "吳興勝地東南會，震澤嵎山在眼中。"]'),
('7d59ff7f-63b9-47fd-971a-106499934228','鳳巢山  其一','王蕃','宋','宋诗','song-poetry','','[]','古邑荒涼瞰小溪，青山高與白雲齊。',32,'全唐诗/poet.song.96000.json','["古邑荒涼瞰小溪，青山高與白雲齊。", "鳳凰飛去巢阿閣，未肯重來覓故棲。"]'),
('c6945781-06a0-45e8-a02c-a611871ba49e','鳳巢山  其二','王蕃','宋','宋诗','song-poetry','','[]','鳳凰飛去聽簫韶，燕雀群飛想見嘲。',32,'全唐诗/poet.song.96000.json','["鳳凰飛去聽簫韶，燕雀群飛想見嘲。", "記取舊時棲止處，莫教鷹隼誤來巢。"]'),
('58d57df2-438f-4e6f-bfe2-c49563ed9e65','政和壬辰留題石魚','王蕃','宋','宋诗','song-poetry','','[]','冬旱江成渚，維魚記石稜。',24,'全唐诗/poet.song.96000.json','["冬旱江成渚，維魚記石稜。", "滋濡春遂足，狼戾歲將□。"]'),
('eb0ab2ae-6496-438f-b333-63c075dc723c','句','王蕃','宋','宋诗','song-poetry','','[]','南畝桑麻無舊戶，西園桃李變新栽。',16,'全唐诗/poet.song.96000.json','["南畝桑麻無舊戶，西園桃李變新栽。"]'),
('3660ab0c-6dff-499c-96f0-8eba4ca9577d','致政張安卿承事挽詞三首  其一','祖德恭','宋','宋诗','song-poetry','','[]','孝養人誰及，清修少比倫。',48,'全唐诗/poet.song.96000.json','["孝養人誰及，清修少比倫。", "旋聞丹旐具，俄見軸車存。", "空嘆音塵遠，猶思燕席溫。", "安然向窀穸，感涕一銷魂。"]'),
('29e477b1-b60a-4958-a223-39bd8a1daf9c','致政張安卿承事挽詞三首  其二','祖德恭','宋','宋诗','song-poetry','','[]','清白傳家舊，天鐘間世才。',48,'全唐诗/poet.song.96000.json','["清白傳家舊，天鐘間世才。", "大椿宜更壽，喬木遽先摧。", "難止交情淚，空遺寶燭灰。", "幽墟歸葬處，慘慘暮雲堆。"]'),
('9866e9ea-847b-4b33-b6f7-1b79fdb50e76','致政張安卿承事挽詞三首  其三','祖德恭','宋','宋诗','song-poetry','','[]','重嘆張夫子，神襟遽弗寧。',48,'全唐诗/poet.song.96000.json','["重嘆張夫子，神襟遽弗寧。", "摧山傾嶽算，萎哲奄椿齡。", "舊室惟圖像，新阡但刻銘。", "何堪聽歌挽，埋玉在幽坰。"]'),
('bb53f9a2-6af0-4d28-870d-6836eb6a0262','次韻靜師仁叟山居  其一','葉椿','宋','宋诗','song-poetry','','[]','生涯卜築翠微深，門在煙蘿路幾尋。',64,'全唐诗/poet.song.96000.json','["生涯卜築翠微深，門在煙蘿路幾尋。", "竊果白猿窺誦易，棲松黄鶴聽調琴。", "泉聲漱石丁東玉，竹影搖風瑣碎金。", "雨霽乘閑種瑤草，和雲斸破古松陰。"]'),
('f0ef8711-fb0c-4774-bd17-e8b8fabb4553','次韻靜師仁叟山居  其二','葉椿','宋','宋诗','song-poetry','','[]','雪磴苔深人到稀，養成疏懶類頑癡。',64,'全唐诗/poet.song.96000.json','["雪磴苔深人到稀，養成疏懶類頑癡。", "半陰寒綠雨晴日，滿地落紅春盡時。", "天籟入松疑鼓瑟，怨禽啼月認吹箎。", "新篁遶舍綠陰合，靜對清流好賦詩。"]'),
('bcab7d34-5587-4578-805d-516b4a11bfa1','次韻王翔仲同遊山寺','葉椿','宋','宋诗','song-poetry','','[]','偶穿謝屐邀東陽，踏破煙霞到上方。',192,'全唐诗/poet.song.96000.json','["偶穿謝屐邀東陽，踏破煙霞到上方。", "遠水波平縑素展，遙山雪盡畫圖張。", "旋生蕙葉沿幽澗，未有花枝出矮牆。", "冉冉翠眉舒弱柳，盈盈青眼綴條桑。", "雲庵共訪霜眉老，瓦鼎初然柏子香。", "書史滿前真脫灑，軒窗無處不清涼。", "南枝玉蕾標容瘦，北苑雲凝氣味長。", "滌硯探題皆白雪，調琴奏曲盡清商。", "三分春色行將半，一月人生笑上常。", "莫羨蒿藜承雨露，自矜松柏耐冰霜。", "利途波浪從教險，人世榮枯未可量。", "且趁良辰恣行樂，時來衡陋自生光。"]'),
('6250d18f-5e0a-407d-a739-495df88762b2','大田山居','史詔','宋','宋诗','song-poetry','','[]','斗酒藏春甕，開軒有客迎。',48,'全唐诗/poet.song.96000.json','["斗酒藏春甕，開軒有客迎。", "烹鮮供母箸，督僕佐春耕。", "園果霜前熟，山禽雨後鳴。", "市朝風味好，輸我一般清。"]'),
('1c9cad3b-ea32-49b4-a87e-a28cab609b20','立春書懷','史詔','宋','宋诗','song-poetry','','[]','寂寞荒村景，凄其今日春。',48,'全唐诗/poet.song.96000.json','["寂寞荒村景，凄其今日春。", "趁時三盞酒，轉眼一年人。", "髪短勝添白，身閑亦耐貧。", "韶光容易老，何事逐風塵。"]'),
('838609e3-570b-4a2c-8ef3-4738d6265d0d','沈山','姚鵬','宋','宋诗','song-poetry','','[]','地偏少來客，山青多似春。',48,'全唐诗/poet.song.96000.json','["地偏少來客，山青多似春。", "聊憑杖履力，得與雲霞親。", "惟有月留我，更無塵污人。", "沈公不復見，清風嘯松聲。"]'),
('dce506a6-4742-4ce3-a839-e34e3be15343','題經山','姚鵬','宋','宋诗','song-poetry','','[]','古剎外塵境，青山伴一生。',48,'全唐诗/poet.song.96000.json','["古剎外塵境，青山伴一生。", "林深宿鳥托，洞冷秋雲橫。", "竹影過酒淥，松聲入琴清。", "俗物不在眼，聊足舒幽情。"]'),
('72fb7d0e-4cf4-4c63-b131-21125034d70b','末利花','顔博文','宋','宋诗','song-poetry','','[]','竹稍脫青錦，榕葉隨黄雲。',108,'全唐诗/poet.song.96000.json','["竹稍脫青錦，榕葉隨黄雲。", "嶺頭暑正煩，見此萼綠君。", "欲言嬌不吐，藏意久未分。", "最憐月初上，濃香夢中聞。", "蕭然六曲屏，西施带微醺。", "叢深珊瑚帳，枝轉翡翠裙。", "譬如追風騎，一抹萬馬群。", "銅瓶汲清泚，聊復爲子勤。", "願言少須臾，對此髯參軍。"]'),
('e00077c8-a4fd-4804-8754-4121ac2d807c','題李叔班山水橫卷  其一','顔博文','宋','宋诗','song-poetry','','[]','高峰柱層霄，遠水沒平野。',48,'全唐诗/poet.song.96000.json','["高峰柱層霄，遠水沒平野。", "當年居山客，半是愛山者。", "橋欹欲沈崖，路險不容馬。", "慎勿誇世人，正要知者寡。"]'),
('484ff193-bed3-4d72-96d3-eade722ac876','題李叔班山水橫卷  其二','顔博文','宋','宋诗','song-poetry','','[]','青山爲誰高，影壓三百里。',48,'全唐诗/poet.song.96000.json','["青山爲誰高，影壓三百里。", "竹深已迷橋，荷密半藏水。", "區區名利人，坐瞑真可鄙。", "慨想雲屋中，恐是古君子。"]'),
('48ba2722-ee99-4718-aa4f-bca71ec55bd0','題李叔班山水橫卷  其三','顔博文','宋','宋诗','song-poetry','','[]','急雨冷捎溪，寒煙曉橫塞。',48,'全唐诗/poet.song.96000.json','["急雨冷捎溪，寒煙曉橫塞。", "茅屋來軒車，中有隱者在。", "市朝一何有，雲水兩無礙。", "笑向塵世人，不知是何代。"]'),
('edc02d7b-a84c-4d82-adc7-7a7942425ecd','題李叔班山水橫卷  其四','顔博文','宋','宋诗','song-poetry','','[]','通江石泉滑，崩崖朝雪重。',48,'全唐诗/poet.song.96000.json','["通江石泉滑，崩崖朝雪重。", "牧兒心苦饑，牛寒挽不動。", "誰人倚長松，胸有九雲夢。", "西風吹屋倒，一笑無興共。"]'),
('dc649f25-61a1-4fd3-a9e4-ff041d66b112','王希深合新香煙氣清灑不類尋常可以爲道人開筆端消息','顔博文','宋','宋诗','song-poetry','','[]','玉水沈沈影，銅爐裊裊煙。',48,'全唐诗/poet.song.96000.json','["玉水沈沈影，銅爐裊裊煙。", "爲思丹鳳髓，不愛老龍涎。", "皂帽真閑客，黄衣小病仙。", "定知雲屋下，繡被有人眠。"]'),
('c7b98dc2-cfa4-4f4f-b2d3-16b0c3a6cce6','題龜峰鋪','顔博文','宋','宋诗','song-poetry','','[]','洪波春天翻四嶽，南極祝融亘幽朔。',160,'全唐诗/poet.song.96000.json','["洪波春天翻四嶽，南極祝融亘幽朔。", "高山千里龜出背，大木百尋龍掛角。", "白魚跳舟神禹出，鞭笞百鬼走雷電。", "犀走象駭不敢留，顛沛馮夷囚海若。", "大龜爬沙獨居後，火傘下照天一握。", "甘心枯死配玉靈，突兀子川露蒼殻。", "醉中對之爲一笑，欲持鐵網手自捉。", "窮通禍福爾嘗知，取火燒山恣鑽灼。", "青松翠竹舞西風，似客搖頭謂公莫。", "此事傳之亡是翁，請君更問山頭鶴。"]'),
('ac81e3b1-fedc-4da2-95d2-e9f69667e307','建炎丞相成國呂忠穆公退老堂  其一','謝升俊','宋','宋诗','song-poetry','','[]','當年直奮渭濱漁，遠業端爲萬世圖。',64,'全唐诗/poet.song.96000.json','["當年直奮渭濱漁，遠業端爲萬世圖。", "戡亂功猶存社稷，愛閑身已到江湖。", "竹間便好開三徑，池外何妨架一區。", "從此標名爲退老，時將杖屨許誰俱。"]'),
('c38155c7-f599-4609-976d-54f46db7bf02','建炎丞相成國呂忠穆公退老堂  其二','謝升俊','宋','宋诗','song-poetry','','[]','再造功成不自居，玉墀長見詠歸歟。',64,'全唐诗/poet.song.96000.json','["再造功成不自居，玉墀長見詠歸歟。", "青山流水看無厭，燠館涼臺興有餘。", "天子時時思舊德，蒼生日日傒新除。", "黑頭便上鋒車去，遙想槐庭席正虛。"]'),
('fb7f7f12-2b8a-4fae-805c-558f48bb94c0','廣福寺','王建','宋','宋诗','song-poetry','','[]','小松新檜未成行，勸督栽培想上方。',32,'全唐诗/poet.song.96000.json','["小松新檜未成行，勸督栽培想上方。", "簷外老榕知幾歲，亭亭孤立傲風霜。"]'),
('89e52b0c-d798-4433-97f3-d37e3cb12a96','即事','何大圭','宋','宋诗','song-poetry','','[]','茅屋松窗小隱家，茶煙漠漠水斜斜。',64,'全唐诗/poet.song.96000.json','["茅屋松窗小隱家，茶煙漠漠水斜斜。", "簷間乳燕未成語，庭下石榴爭放花。", "賴有詩書銷白日，倦隨車馬走黄沙。", "林泉舊約好徑去，風雨滿江垂釣車。"]'),
('9ac5d7e4-11c9-4db6-9980-c79f628101f2','贈鉛山余適正','朱履','宋','宋诗','song-poetry','','[]','下邳先生頭如雪，手把遺編未嘗輟。',320,'全唐诗/poet.song.96000.json','["下邳先生頭如雪，手把遺編未嘗輟。", "曾吟孝行三百篇，轉作蒙求義尤切。", "朝廷求書徧海隅，不問簪纓與巖穴。", "先生親寫此書進，郡守封題獻雙闕。", "可惜要路無知己，經年不報還蹉跌。", "或思慷慨詣公車，空守無金肘屢掣。", "僦屋窮居縣市西，生涯有路蒙鳩拙。", "圖書滿架不濟用，門巷蕭條空歲月。", "去年相見衣不完，今年相見衣頻結。", "奔波辛苦養妻子，未免長裾事干謁。", "東鄰右姓夸銅臭，西舍富兒稱金埒。", "牆屋文繡競紛華，盤饌腥羶恣羅列。", "相逢徒解問寒溫，誰把斗升濟涸轍。", "才高學富老益貧，口中漫有張儀舌。", "邇來聞說苦多病，閉門不出經時節。", "況當催暮歲崢嶸，朔風勁疾高岡裂。", "城居柴米價轉增，往往晨昏更悽屑。", "曾參居衛肘常見，夫子在陳糧亦絕。", "古地聖賢貫如此，莫學兒曹暗悲咽。", "束薪斗米助朝炊，卻恐莊周笑濡沫。"]'),
('7ac49e12-66df-452d-b14f-75715a864182','句','吳棫','宋','宋诗','song-poetry','','[]','春風藜杖起詩豪。',8,'全唐诗/poet.song.96000.json','["春風藜杖起詩豪。"]'),
('07288c36-8a35-4c02-9602-4fe66aa2f7a7','宿金鋪觀','吳景偲','宋','宋诗','song-poetry','','[]','褰裳夜入金鋪宿，清氣一宵吟不足。',32,'全唐诗/poet.song.96000.json','["褰裳夜入金鋪宿，清氣一宵吟不足。", "月在碧潭風在松，何必洞天三十六。"]'),
('ecf649fd-f4da-4ce6-84d5-5ed85b01118b','和潘良貴三江亭韻','薛朋龜','宋','宋诗','song-poetry','','[]','爽氣寒光四壁侵，青山千仞水千尋。',64,'全唐诗/poet.song.96000.json','["爽氣寒光四壁侵，青山千仞水千尋。", "遠觀吾里瀛洲路，悵望誰人魏闕心。", "春到已多鳴珮玉，酒酣應有解貂金。", "紫微太守經營巧，消得時賢次第吟。"]'),
('bc561778-5333-4298-bf93-7955a8f4c8bd','岱嶽篇雪中送華山人東遊','薛朋龜','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','七十二君已綿邈，乾坤只今留岱嶽。',144,'全唐诗/poet.song.96000.json','["七十二君已綿邈，乾坤只今留岱嶽。", "煙書雲篆吊秦碑，萬聖千靈朝漢朔。", "白日雕旛路相望，夜深仙樂張天上。", "日觀天門踴躍登，芒作雙鞋藜作杖。", "匹練吳門見幾人，向來寂寞空山春。", "溪花谷樹忽生色，一朝若爲山人新。", "君行正直年華謝，山雪紛紛向君下。", "去看九州玉削成，孤高始信岱嶽名。", "若趁長風竟飛舉，鵝毛柳絮同身輕。"]'),
('6de80961-4f94-4dc0-92d2-9f45e34a4bf6','江船','薛朋龜','宋','宋诗','song-poetry','','[]','夜色千山白，扁舟獨進遲。',48,'全唐诗/poet.song.96000.json','["夜色千山白，扁舟獨進遲。", "鄉心共帆急，世路與波隨。", "性野禽魚習，官寒故舊知。", "江梅如愛客，早放歲寒枝。"]'),
('07285067-eb5c-4147-814a-5242787787e1','露','薛朋龜','宋','宋诗','song-poetry','','[]','乘興訪村家，微微見露華。',48,'全唐诗/poet.song.96000.json','["乘興訪村家，微微見露華。", "暗滋三徑草，晴濺一庭花。", "夢入關河濕，涼生更漏賒。", "清江千萬里，何處點蒹葭。"]'),
('b3139e90-d918-4ecd-ac05-922a230ed355','見雁','薛朋龜','宋','宋诗','song-poetry','','[]','寒衣九月授他鄉，遂見征鴻序一行。',64,'全唐诗/poet.song.96000.json','["寒衣九月授他鄉，遂見征鴻序一行。", "秋色未深先避雪，邊聲忽到又隨霜。", "曾愁天路罹矰繳，只想中原食稻粱。", "漢使不歸書不繫，至今塞有客沾裳。"]'),
('ffc5fa81-0abe-478a-a56c-9b6bb1a355b6','剡中別吳客','薛朋龜','宋','宋诗','song-poetry','','[]','百道飛流向剡飛，高田不歉下田肥。',32,'全唐诗/poet.song.96000.json','["百道飛流向剡飛，高田不歉下田肥。", "吳人只道吳山好，黄獨如拳也救饑。"]'),
('95c187c9-4cfd-4e10-ba1a-67d38ed35fc9','詠秋葵','薛朋龜','宋','宋诗','song-poetry','','[]','安肯向春陰，群然發錦林。',48,'全唐诗/poet.song.96000.json','["安肯向春陰，群然發錦林。", "黄存秋後色，赤抱日邊心。", "喜附蘭階臭，羞誇菊砌金。", "敢忘涓滴潤，雨露不時臨。"]'),
('1c67a5fa-7f75-436d-a463-9bbf9f5dec22','鷲峰院','林孝雍','宋','宋诗','song-poetry','','[]','憶昔自胝舍，嵐光翠瀲侵。',48,'全唐诗/poet.song.96000.json','["憶昔自胝舍，嵐光翠瀲侵。", "金週沙界斷，紫碧洞天深。", "有匪瞻淇奧，忘機學漢陰。", "寥寥千古意，瑤瑟豈遺音。"]'),
('17f27604-074b-46bd-879e-e29013345e53','和葉樞相送芍藥二首  其一','胡澄','宋','宋诗','song-poetry','','[]','開遲依舊占芳辰，不怕群花笑後陳。',64,'全唐诗/poet.song.96000.json','["開遲依舊占芳辰，不怕群花笑後陳。", "四月明朝纔是夏，千葩夭艷尚含春。", "傳聞勝賞聯樞節，總有新詩泣鬼神。", "三十年前舊交友，白頭誰復嘆如新。"]'),
('38e374cb-72e8-4319-9d4f-7e7b203dfa47','和葉樞相送芍藥二首  其二','胡澄','宋','宋诗','song-poetry','','[]','鶗鴂一聲春已歸，蝶蜂無計戀花時。',32,'全唐诗/poet.song.96000.json','["鶗鴂一聲春已歸，蝶蜂無計戀花時。", "筆頭挽得春光住，卻是先生芍藥詩。"]'),
('001d5bf7-e957-46ee-98db-804cf56febaf','示邦人詩','蕭振','宋','宋诗','song-poetry','','[]','我本江海人，來守仙佛國。',168,'全唐诗/poet.song.96000.json','["我本江海人，來守仙佛國。", "年豐訟牒稀，公事不留積。", "豈無一樽酒，約客飛大白。", "重念此邦人，朝飽不謀夕。", "頃遭兩年荒，十九皆菜色。", "城中多餓殍，倒死臭燻陌。", "幸茲連歲豐，粒米棄狼籍。", "嬉嬉不營生，便爾輕牟麥。", "三日天不雨，沙田已龜坼。", "十家九無儲，何以度饑厄。", "我爲此邦憂，夜眠不安席。", "願天歲歲豐，願爾痛儉嗇。", "一年三年儲，三年九年食。", "堯湯雖在上，豐歉豈可測。"]'),
('6e07038e-8566-485a-9603-36dd68427ba0','仙官峰','蕭振','宋','宋诗','song-poetry','','[]','橫北勢巖巖，光搖斗極寒。',48,'全唐诗/poet.song.96000.json','["橫北勢巖巖，光搖斗極寒。", "當年爲道士，何日轉仙官。", "結得雲霞伴，從他龍虎蟠。", "憑君長鎮壓，魑魅敢相干。"]'),
('c5dea866-6329-4b35-8822-179814cdecdf','春陰即事','王洋','宋','宋诗','song-poetry','','[]','春風雖輕颺，摧折猶有補。',96,'全唐诗/poet.song.96000.json','["春風雖輕颺，摧折猶有補。", "適當穠華時，明知不須雨。", "浴蠶待桑錢，插禾候陽土。", "婦子三時勤，亦欲少歌舞。", "百草仰膏腴，少俟亦無苦。", "如何屯寒雲，專翳扶桑吐。", "事多不由人，十可八九數。", "不若姑置之，吾非拾翠侣。"]'),
('acea4a1b-ca23-4675-9ec4-dbeb333f4c4f','春苦風雨','王洋','宋','宋诗','song-poetry','','[]','東君始造家，積累亦不細。',144,'全唐诗/poet.song.96000.json','["東君始造家，積累亦不細。", "一從潛陽興，黄鍾本根蒂。", "二十四信風，以有此紅翠。", "如何縱飄敗，不作苞桑計。", "風雨不令子，豪猛但適意。", "萬紫雜千紅，用供一日費。", "一日費尚可，矜侈不少置。", "豈惟困芳菲，桑麻亦憔悴。", "溝塍浮新秧，蕩搖失生意。", "無乃大傷和，行敗乃翁事。", "願言期少安，百物思吐氣。", "吾不若訟讒，唯圖保終歲。"]'),
('72a27ec0-1ba8-44c4-a330-0df8b5346cb2','七月八日小雨','王洋','宋','宋诗','song-poetry','','[]','萬彙就槁死，一涼送生意。',288,'全唐诗/poet.song.96000.json','["萬彙就槁死，一涼送生意。", "問誰犯炎威，用事得屏翳。", "始自長夏來，龍骨嘔四裔。", "平原暴槁乾，生火自焚燧。", "藉令翻長河，不給野老淚。", "祝融固有逞，軒軒抱餘恚。", "商飈欲小展，不費一矢遺。", "人謀略殫窮，乃作鬼事計。", "此邦嚴百神，奉事罔失墜。", "惡衣不掩脛，致美盡一祭。", "有嚴者貴神，父老誦明記。", "適當牛女期，懸弧值嘉瑞。", "不知誰相傳，轟然動天地。", "走書集房祀，刻日共髙會。", "俄然駕雲駢，各以偉像至。", "原野照旌旗，閭閻便鼓吹。", "鞠躬偵顔色，大房薦籩胾。", "恍惚動百靈，相傳亦汪濊。", "今朝響雲車，風馬繼飄駛。", "意挾大江神，傾輸作霶霈。", "日影弄廉纖，簷馬鳴細碎。", "涓涓乍伶俜，赫赫復昌熾。", "神乎享已豐，何乃靳小施。", "婦怒罵少年，汝定事游戲。"]'),
('4db06319-e46d-4387-a17d-1677c9e01e14','十一月二十九夜大風明起書室皆敗葉','王洋','宋','宋诗','song-poetry','','[]','木老性倔強，朔風怒明威。',144,'全唐诗/poet.song.96000.json','["木老性倔強，朔風怒明威。", "初更即合戰，已乃聲鼓鼙。", "大塊信難測，三鼓氣不衰。", "我屋山僧居，破陋久不治。", "會當晴明日，仰見河漢移。", "微風鼓櫜籥，虛空同奔馳。", "夜無芙蓉人，慌惚疑褰帷。", "平明滿書齋，敗葉方紛披。", "孰爲呼吸者，作此怒張爲。", "天寒不成雪，恐坐強風師。", "撲塵整書架，糞挶不可遲。", "人非陳仲舉，用舍亦有宜。"]'),
('82c18399-cbd9-42ca-b36a-7b2064548b24','舟宿南尉岸下夜夕不寐思丁老小山戲成長韻','王洋','宋','宋诗','song-poetry','','[]','積少自成多，一元陶萬類。',288,'全唐诗/poet.song.96000.json','["積少自成多，一元陶萬類。", "破大可作小，壺中有天地。", "果謂真無窮，百慮同一致。", "若曰一毫芒，萬里鵬垂翅。", "變化無定形，古今俱幻事。", "老丁習真觀，幻事亦不棄。", "輸財買幻人，放意窮幻智。", "發屋仰偷天，鑿泉下汲繸。", "慌惚幻峰巒，共疑無足至。", "妻兒固俱賢，未免慮憔悴。", "拒諫設科條，縱語終莫遂。", "相顧色慘怛，但未垂怨淚。", "老丁恐敗事，往往陽怒恚。", "共知無奈何，奇計亦多秘。", "託言有鬼神，疾病果作祟。", "要盟質諸天，庶得捐驚悸。", "老丁如不聞，嬉笑無畏忌。", "起語家人言，常數不可避。", "吾老嗜奔湍，且可幻吾戲。", "戰敗豈吾過，時有利不利。", "子無徒面從，背我乃竊議。", "我意終不移，畢命乃殊嗜。", "吾聞利有幅，盈舒如在器。", "老丁自治産，費金亦其意。"]'),
('b7df45b6-c93f-4893-9fd9-c058f86ee77f','陪徐狄二子出東郊即事','王洋','宋','宋诗','song-poetry','','[]','與君同酸苦，思得一散愁。',288,'全唐诗/poet.song.96000.json','["與君同酸苦，思得一散愁。", "散愁何所適，共作郭外遊。", "是時窮冬節，寒威未肯收。", "茫茫一望間，豐瑞彌阡疇。", "老農挾雉子，嬉戲尋朋儔。", "問之向人語，明年報有秋。", "淮南塵土地，髙原少車溝。", "夏苗率畏旱，冬雪苦不優。", "若呈盈尺白，卒歲無所憂。", "常聞爭戰後，天意不自由。", "人心結恨憤，陰陽不旋流。", "皇天佑邦家，予賚徧九州。", "將欲掃凶醜，先爲除凶蟊。", "況此甸服內，大駕方豫游。", "賜之倉箱實，始應政事修。", "所以田野間，老農獲歌謳。", "愁中聞此語，悅如去罝罦。", "未諳鼎饋食，亦宜保乾餱。", "回頭顧二子，不用自拘囚。", "往來茅舍酒，三酌更獻酬。", "枯腸得滑潤，一笑散孤幽。", "放懷了無悶，萬事皆悠悠。", "晚歸足益健，自喜筋力柔。", "歸見城中人，揣我將何求。"]'),
('f1a3ac66-433e-4d01-8fb7-bb8421337910','十月十七日雨霽復至仙隱','王洋','宋','宋诗','song-poetry','','[]','秋雨閑十日，緬懷秋山空。',84,'全唐诗/poet.song.96000.json','["秋雨閑十日，緬懷秋山空。", "煙霞固舊態，敗葉鋪山紅。", "平生五大夫，投老一秃翁。", "相看各蕭索，事付不語中。", "二輪固代謝，四序彌初終。", "義霜素慘烈，温律復冲融。", "相期保歲寒，木末回春風。"]'),
('7f52d09b-89fd-4a4c-bc2e-d7acdc3bfc2f','安成令以長橋圖來且示王民瞻記喜其有成因成短章','王洋','宋','宋诗','song-poetry','','[]','楚人問晉勇，答曰好以暇。',144,'全唐诗/poet.song.96000.json','["楚人問晉勇，答曰好以暇。", "後人或疑之，鍼也其說駕。", "吾意政之餘，觀此得用舍。", "晉士儻不然，安能一戰霸。", "韓君令安成，不待朞月化。", "始如逆走丸，卒若快啖蔗。", "爲政行辟人，修梁插飛架。", "異時常病涉，舉邑僉矜詫。", "王子吐琳瑯，文章助光價。", "綠波凝暮朝，晧月迷清夜。", "誰云困兵革，不可事耕稼。", "聊書以記之，來者可憑藉。"]'),
('9108b9ba-7549-48d7-8979-f222246e13cc','寄題安福鳳林橋','王洋','宋','宋诗','song-poetry','','[]','二年廬陵城，不踏安成野。',204,'全唐诗/poet.song.96000.json','["二年廬陵城，不踏安成野。", "但聞古侯封，沃壤富書社。", "剸煩或容容，書考乃下下。", "韓君令安成，政事飾儒雅。", "考實見功多，程勞用力寡。", "邑南橫長溪，春流夏湍瀉。", "輿梁久弗支，冬涉猶病骻。", "韓君一咄嗟，民力競輸寫。", "脩梁插晴空，野色集平瓦。", "問君胡能然，一錢不入把。", "因民乃利民，胡往弗寬假。", "十年旌旗中，未得洗兵馬。", "羽書固所先，民簿乃付且。", "誰知安成令，從政識用舍。", "目前縱奔馳，心事日蕭灑。", "薛宣好男兒，正可上醇斚。", "吾雖不預觀，書以告來者。"]'),
('8e267170-fed7-4fcd-ab87-753168124302','真意堂','王洋','宋','宋诗','song-poetry','','[]','一室恐婦愁，三間良足用。',156,'全唐诗/poet.song.96000.json','["一室恐婦愁，三間良足用。", "積錢寬買園，此事不敢夢。", "弋陽千萬家，比屋接脩棟。", "相期生在勤，意象不少縱。", "饑字參不破，竟日自倥愡。", "設有花木山，僅作一身供。", "徐翁初來時，赤子不取重。", "徐徐汲壑谷，轆轤轉雙甕。", "耡夷荆棘開，改化溪山動。", "千年五柳陶，慕用常接踵。", "徐翁但神會，疏跡不勘縫。", "七絃已可忘，五柳不待種。", "見山若舉頭，孤雁亦須送。"]'),
('e5c5d69d-e687-400d-935a-20bd4b96acdb','絃歌堂','王洋','宋','宋诗','song-poetry','','[]','曹務日以渾，令君心自清。',288,'全唐诗/poet.song.96000.json','["曹務日以渾，令君心自清。", "散彼愁歎氣，化作懽愉聲。", "懽愉何所寄，寄此絃歌鳴。", "歌如珠纍纍，絃以桐鏗鏗。", "顧此三尺匣，中有萬古情。", "大絃含春温，赤甲隨勾萌。", "小絃羽雖細，一奏壯士驚。", "次第徵角招，向日葵心傾。", "商以表節義，皎皎秋霜明。", "斂之五音全，昭氏無虧成。", "鼓之播萬物，草木同敷榮。", "令君保此器，常得心和平。", "知君本抱道，巖壑依雲耕。", "缾粟朝不飽，强起從簪纓。", "素琴常在御，朝陽鳴簫笙。", "蕭然古槐下，時乎一再行。", "亭午百吏散，永日垂簾旌。", "舟車自衝會，我道無將迎。", "筆役眩朱墨，愷悌消紛爭。", "誅求絕敲榜，升合均缾罌。", "和風動千室，暖律鳴嚶嚶。", "坐令今上饒，乃類古武城。", "問君何能爾，但守一字誠。", "吾聞古良吏，惠養先孤惸。"]'),
('f71b54b3-3bdb-439b-918b-a627588e9f13','畫列子圖和韻','王洋','宋','宋诗','song-poetry','','[]','稻粱戒鳥啄，饋粟辭子陽。',168,'全唐诗/poet.song.96000.json','["稻粱戒鳥啄，饋粟辭子陽。", "神明久不死，宇宙一鳥翔。", "若人據槁梧，中自含宫商。", "其游車泠風，其息形坐忘。", "豆山瀛泗等，念往即褰裳。", "蓋云任去來，豈謂符弛張。", "老商顧之笑，是事何輕揚。", "雲風駕旬餘，日月輈兩傍。", "拊掌一戲笑，何異侏儒場。", "後人致引慕，竹林焚馨香。", "飄飄大人賦，氣奪千丈强。", "吾聞孔仲尼，道盛涵化光。", "雅言書當理，不見一日長。", "放乎子列子，君其樂彷徉。"]'),
('4f1f4bca-5151-4d27-9c27-b373276993c9','謝葉秀才惠書自言能書大字來書作小字甚工','王洋','宋','宋诗','song-poetry','','[]','大字韋將軍，小字徐開府。',48,'全唐诗/poet.song.96000.json','["大字韋將軍，小字徐開府。", "惠我數百言，字字了今古。", "江山得何助，文采乃如許。", "莫羞無稻粱，鴻飛自髙舉。"]'),
('1c76e373-eb4a-4589-89c2-96119e1b127e','紹興庚申解官廬陵留别歐陽隱士','王洋','宋','宋诗','song-poetry','','[]','梅雨翳江浦，我來初識君。',192,'全唐诗/poet.song.96000.json','["梅雨翳江浦，我來初識君。", "俯仰寒暑移，幾親芝蘭群。", "芝蘭本何心，悠然蕩清芬。", "不妨識度髙，解使靜躁分。", "我從困飄泊，朋從少知聞。", "投足自失所，造化本無垠。", "妻兒憚遠寓，豈復辨蕕薰。", "顧惟鄙野性，樂此川原尊。", "時觀前古俗，家傳付兒孫。", "常疑百年餘，下流名尚存。", "慚非撥煩手，未能解紛紜。", "虛懷飽暖戀，有愧民吏勤。", "無乃同鄉夫，或可覃後昆。", "脫身亦由人，孤翥隨騰鶱。", "豈不快宿願，誰能困籠樊。", "他年方外士，相期同策勳。"]'),
('fa9d6f28-978d-4dc2-ac97-0d563c6d50b0','送章季萬戶部','王洋','宋','宋诗','song-poetry','','[]','吳人不授館，楚人不分田。',168,'全唐诗/poet.song.96000.json','["吳人不授館，楚人不分田。", "此身天地間，泛若不繫船。", "憶昨罷吏役，白鷗同一川。", "欲乘萬里風，短翼無夤緣。", "使君霤宇大，下庇千萬賢。", "鷄鳴度關客，亦到尊俎前。", "賤子忝夙分，今已三四傳。", "嘗許策蹇步，十駕困屢鞭。", "公文如摛華，公筆如修椽。", "筆端色五采，密補造化權。", "浮沉既異路，會合真可憐。", "我無三徑地，直欲參四禪。", "後會寬作程，望舒圓復圓。", "他年赤松子，問訊玉堂仙。"]'),
('e2fca0ba-fb39-4ff2-868f-6a3c684310f4','同劉仲忱舍人先生鄭武子錢伯氏賦兩篇得聖歡二韻','王洋','宋','宋诗','song-poetry','','[]','客行仍别離，此恨亦已更。',48,'全唐诗/poet.song.96000.json','["客行仍别離，此恨亦已更。", "去語已莫留，來愁不須聘。", "七閩何貪賢，四海方仰聖。", "班驛是歸塗，頻宜發新詠。"]'),
('6b0015c8-10c9-47d2-9c75-00603b503119','鄭丈灼灸戲成','王洋','宋','宋诗','song-poetry','','[]','丈人國元龜，千古秘清廟。',192,'全唐诗/poet.song.96000.json','["丈人國元龜，千古秘清廟。", "側聞扈聖初，彤庭獻喜兆。", "從此氛霧開，屢錫休瑞報。", "珪璋厭紛華，江湖樂豐好。", "一冠脫孟勞，十年泛靈沼。", "近聞出清江，仗節觸烝罩。", "漁者有豫且，橫梁截隈奥。", "如何抱神智，失腳困泥淖。", "倉皇見夢祈，修門極悲叫。", "櫝藏得玄夫，光價逾納郜。", "再拜爭乞靈，灼鐵具熱燋。", "火攻固下策，奈此集衆譟。", "低頭謝群工，脫身圖後效。", "此戲亦太虐，臍腹困然膏。", "切勿再三瀆，瀆亦不汝告。", "舍爾觀朵頤，從吾襲髙蹈。"]'),
('1493a1ca-fb49-44d1-b90b-381556a01cb6','聞劉行簡給事休致作詩寄之','王洋','宋','宋诗','song-poetry','','[]','郡下一卷書，云自郵籖來。',288,'全唐诗/poet.song.96000.json','["郡下一卷書，云自郵籖來。", "剝啄驚晝眠，柴門手自開。", "上有驪珠光，照耀分塵埃。", "讀之未盡行，喜焰生寒灰。", "黄門白首郎，上疏稱乞骸。", "帝曰大布衣，錫汝陞文階。", "天孫鈆錄秘，論撰須儒魁。", "榮名不汝遺，汝往時欽哉。", "夕即拜帝命，雪涕何紛漼。", "恩許歸舊廬，徑臥南山齋。", "此翁山澤仙，不賦章綬材。", "誤因文彩露，遂落天網恢。", "一游三十年，所得非不諧。", "文名動青瑣，筆力幽黄能。", "左省豈不榮，珠庭重徘徊。", "巢父一掉頭，百挽終不回。", "吾意天地間，清風有根栽。", "人心感披拂，達者分條枚。", "二疏楊巨源，同上百尺臺。", "劉翁傳其風，蒼舒次隤敳。", "況復祖子孫，此道同胚胎。", "前劉脫功名，養氣如嬰孩。", "至今一箭詩，諷詠及陪臺。", "翁今亦何有，曠達忘悲哀。"]'),
('9bc396d0-26d0-4cea-9505-09e0b7d99695','我有一雙眼贈徐氏倣老徐體僕近與思遠賡和頗自言老有拒徐出游意恐以僕爲真老也故有此作','王洋','宋','宋诗','song-poetry','','[]','我有一雙眼，光可照明燭。',288,'全唐诗/poet.song.96000.json','["我有一雙眼，光可照明燭。", "我有一寸腸，時復潄醽醁。", "我有兩垂鬢，與君相映綠。", "我有一雙腳，比君非不足。", "眼能别妍醜，腸不慮榮辱。", "鬚鬢每自憐，足力能相逐。", "一一將比君，未便遽慚恧。", "胡爲被君輕，汙田對寒玉。", "君如邀我遊，我亦知所以。", "朝出任意游，暮歸同倒屣。", "況此郊野間，遠近在一視。", "東抵東家田，繞溪六七里。", "北向關外行，五里見淮水。", "我家園在西，鳴泉到清耳。", "南郊野叟村，殷勤種桃李。", "大抵浩蕩處，瀟灑異城市。", "春雲乍爲錦，餘霞忽成綺。", "興來思暫息，極目無涯涘。", "兩眼極恣橫，性情始歡喜。", "歸來看君詩，陳饋鋪八簋。", "羅列水陸珍，咀啖盡日美。", "我亦强自吟，合處粗相似。", "醉時所經歷，醉後詩在紙。", "連粘動成卷，持行不羞恥。"]'),
('a2842d1f-11d9-4d3a-bc93-d36fd2c3fe3c','還自伊山過金城宿覺慧寺贈始寧禪師','王洋','宋','宋诗','song-poetry','','[]','家山三百里，處處逐流水。',252,'全唐诗/poet.song.96000.json','["家山三百里，處處逐流水。", "舟行鑒影中，塵埃不須洗。", "人言田間苦，我言田舍好。", "濁醪三兩杯，沈憂積如掃。", "昨與田父言，别白皆有證。", "丈夫幸聽之，物物保性命。", "歸來過山僧，僧始見客喜。", "試與語囏難，不貪亦不止。", "我徐覺言煩，廼靜觀厥理。", "僧言禍與福，皆其自取爾。", "吾師有明言，報應有彼是。", "所作既不同，所遭亦如此。", "君言君自憶，我初不到耳。", "及君受報時，何用乏吾事。", "去年梁宋災，載屍滿城市。", "今年江淮南，囷窌有餘米。", "善惡無兩岐，末流見殊致。", "君後起念時，覺此而已矣。", "再拜謝髙僧，師言誠有味。", "解榻借僧裯，不覺已鼾鼻。", "展轉未厭眠，鷄鳴唤客起。"]'),
('3ae99f9b-7643-4bde-b68c-d100706f4978','贈穎師','王洋','宋','宋诗','song-poetry','','[]','昔有二大士，比跡相差池。',192,'全唐诗/poet.song.96000.json','["昔有二大士，比跡相差池。", "一隱盧老堂，一作貧舍兒。", "任緣本無意，音韻偶追隨。", "髙唱既絕詣，豹隱那得窺。", "穎公實靜者，妙賞心自知。", "以此墨守慮，遠繼白雪詞。", "首叙同契語，生死一推移。", "末祛唱酬跡，風月非所私。", "中間任遊戲，不假永篇題。", "自此探骨髓，杜蘭雜香蘼。", "翻思前作者，往往求其皮。", "彼非不論量，泛浪忽深思。", "但取偶世語，髙調終莫追。", "穎公整襟量，峭聳乘嶔危。", "冥捜尚論古，快警耳目疑。", "不從禪寂縳，此道信權奇。"]'),
('97389480-ae71-4827-b039-0a78e26dca0d','曾谹父約遊南巖短韻奉呈','王洋','宋','宋诗','song-poetry','','[]','南豐不藏善，逢人說南巖。',180,'全唐诗/poet.song.96000.json','["南豐不藏善，逢人說南巖。", "南巖亦何好，造物秘此緘。", "煙雲卬全提，松竹色半酣。", "去郭十里贏，守戍僧二三。", "乞身滿一日，幽事亦可探。", "行客問征途，居者縈轡銜。", "蕭條野店煙，夐静彌勒龕。", "念非塵外侣，誰分禪味甘。", "受傭作閑人，自縛亦可慚。", "于時日在房，山色染靄藍。", "一徑盤鬰青，群峰列空嵌。", "吟泉計涓滴，瀹鼎消塵凡。", "端如常德靜，可警疾步貪。", "揚鑣出雲門，回首憐煙嵐。", "公其吐妙語，勝事須指南。"]'),
('b9e10fa8-de5f-48a1-8e79-e0da4a638056','食鱠','王洋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','生長江湖中，厭食水中珍。',168,'全唐诗/poet.song.96000.json','["生長江湖中，厭食水中珍。", "從得脫死來，頗見鄉味親。", "每食無不飽，敢歎蔬茹貧。", "老妻生過計，爲我鱠鮮鱗。", "飣餖盤箸間，玉縷鋪繽紛。", "不知驚憂後，腸胃久不伸。", "瘧餘病尚在，欲飫嫌羶腥。", "所以縱對此，凛如見嚴賓。", "由知飲啄緣，豐儉各有因。", "所饗苟無分，對面難霑脣。", "可歎賦分薄，一炙亦艱辛。", "在近猶參商，其大應吳秦。", "歲事已轉轂，園葵行獻新。", "勿擬春蔬薄，春蔬久向人。"]'),
('233a8b50-0319-4fa4-ac9c-7dd8e53417e2','曾谹父將赴浮光九日無酒賦二詩次韻  其一','王洋','宋','宋诗','song-poetry','','[]','經營戒奔忙，髙士乃貴嬾。',72,'全唐诗/poet.song.96000.json','["經營戒奔忙，髙士乃貴嬾。", "不然繋匏瓜，何異列樗散。", "若人落閑社，旁觀助煩惋。", "况聞上方札，天子恨見晚。", "朝廷錄故舊，士女重嗟遠。", "父母謝使君，相看猶故眼。"]'),
('9096b5e2-7bb0-4f92-9583-9a97792a4519','曾谹父將赴浮光九日無酒賦二詩次韻  其二','王洋','宋','宋诗','song-poetry','','[]','中虛臥北窗，歲月驚兔脫。',72,'全唐诗/poet.song.96000.json','["中虛臥北窗，歲月驚兔脫。", "側目一愁胡，已寒不須潑。", "吾聞金鼎象，次第有本末。", "千里尚疏封，五漿何用設。", "它年激沱江，大捄相如渴。", "丈夫屬有念，行行勿騷屑。"]'),
('0df8ae21-f766-4e91-bb05-51d78ab44b4c','和曾吉父飲南坡四詩  其一','王洋','宋','宋诗','song-poetry','','[]','買山如買金，去草如去惡。',48,'全唐诗/poet.song.96000.json','["買山如買金，去草如去惡。", "開山一代師，前者無是作。", "向無邱壑心，雖有亦不樂。", "何須待髙秋，風帽已可落。"]'),
('66546315-8c05-493c-ab43-2532306b091b','和曾吉父飲南坡四詩  其二','王洋','宋','宋诗','song-poetry','','[]','寒暑有至公，物物無避處。',48,'全唐诗/poet.song.96000.json','["寒暑有至公，物物無避處。", "岧嶤半天中，乃截雲雨路。", "炎薰障南林，清風來北戶。", "幽事未可量，如君美無度。"]'),
('d027c0b2-b303-443f-8cc2-418550184456','和曾吉父飲南坡四詩  其三','王洋','宋','宋诗','song-poetry','','[]','若無敗人意，何適非好懷。',48,'全唐诗/poet.song.96000.json','["若無敗人意，何適非好懷。", "飛輪了無轍，爲作明鏡臺。", "有酒不共飲，定知何日開。", "魚鳥亦知意，門前日日來。"]'),
('1677c437-4f26-47c9-b833-fc508f657c60','和曾吉父飲南坡四詩  其四','王洋','宋','宋诗','song-poetry','','[]','終年困塵土，一日同宴嬉。',72,'全唐诗/poet.song.96000.json','["終年困塵土，一日同宴嬉。", "詩價重車渠，酒色空琉璃。", "月出散林莾，攬之有餘輝。", "山林信可樂，所樂無四時。", "況渠善窈窕，與我昏爲期。", "會須挽凌波，同載月明歸。"]'),
('f5b2555e-5719-4ed0-9b18-10fbb4fea9b9','秀實行邑回寄示佳章次韻','王洋','宋','宋诗','song-poetry','','[]','皇皇宇宙間，快意本何限。',84,'全唐诗/poet.song.96000.json','["皇皇宇宙間，快意本何限。", "有如抱畦畛，相對不見面。", "汝南箕穎士，白首仕州縣。", "偶來江西遊，溪山副良願。", "口誦陶令章，手持古書卷。", "老氣益健敏，落筆增蒨絢。", "尚願姑置之，有人圖自獻。"]'),
('3afe31ad-dc09-4947-a6d5-ce4a2c17324c','秀實監丞時惠佳章逋債稍多今因休暇再報一章當時同遊已踰三月輙泛語以謝','王洋','宋','宋诗','song-poetry','','[]','人生萍梗蹤，端若邂逅期。',132,'全唐诗/poet.song.96000.json','["人生萍梗蹤，端若邂逅期。", "奈何人常言，會合信有時。", "鄙人初謁郡，故事科童兒。", "竹馬豈其情，驩笑亦强隨。", "豈緣特達賢，惜此駑鈍姿。", "乃信非偶然，三葉親華枝。", "此老輩行髙，心事故崛奇。", "逃禪昔蘇晉，辭榮今介推。", "十年守一官，不樂亦不悲。", "獨設詩中禪，健勇了未衰。", "談空不可攀，且報今年詩。"]'),
('3ab43533-f4e2-47ef-a3ce-4a7eb66dbc12','秀實再以前韻寵惠佳篇謹再次元韻','王洋','宋','宋诗','song-poetry','','[]','名利世所重，燋爛以爲期。',132,'全唐诗/poet.song.96000.json','["名利世所重，燋爛以爲期。", "出處不自由，語默多因時。", "陳侯有餘佞，又以傳其兒。", "蘇秦掉頰舌，代厲俱詭隨。", "此風幾百年，尚作柔佞姿。", "武子衒富豪，擊碎珊瑚枝。", "褒姒出巧譖，歸放加伯奇。", "茫茫天宇間，窮達不可推。", "不須謀快樂，亦勿生愁悲。", "但看憂樂人，往往心神衰。", "長年飽喫飯，此事前賢詩。"]'),
('5203c65d-32a1-4851-8ffa-09f7c6abe985','次韵劉希顔李泰發龍井壽聖請獻辨才詩','王洋','宋','宋诗','song-poetry','','[]','古人重好古，今人徒賞今。',192,'全唐诗/poet.song.96000.json','["古人重好古，今人徒賞今。", "賞今拘近俗，何以勞寸心。", "昔者臞面仙，分符此來臨。", "邦君舍華軒，老人獨散襟。", "從容塵領間，消息禪慮深。", "道人本絕俗，猗蘭故相尋。", "風流右將軍，寂寞支道林。", "泉石誠膏肓，此病難與箴。", "缾盂飽粥飯，巾㲲替裳簪。", "萬家辭近市，寸碧依搖岑。", "邇來四十年，何人發孤吟。", "亦有好事者，杖藜訪層陰。", "鵝溪喚畫像，金薤鏘瑤林。", "賞遇既落落，風神見森森。", "此道果有繼，不憂風雨侵。", "誰言殊緇俗，二士鄴與欽。"]'),
('a484dd40-c285-438b-b1fe-54087b3be773','次韻辛起李長篇','王洋','宋','宋诗','song-poetry','','[]','十年爪牙官，百世傳風流。',252,'全唐诗/poet.song.96000.json','["十年爪牙官，百世傳風流。", "每思先賢範，爛漫涕不收。", "爭奪世界中，蕭灑自十洲。", "辛使東洲望，翹材錯薪槱。", "干戈一相尋，賢愚自相仇。", "六鰲失所負，群賢困道周。", "人如辛使者，往往官屢休。", "用舍方坎壈，身世同蜉蝣。", "但聞公卿間，飽誦才業優。", "爵祿縱可辭，歲月那得媮。", "向來成名時，石室書盍紬。", "奈何俯仰中，窘路拘驊騮。", "嘶鳴合亨塗，飄泊仍海陬。", "嗟予才每下，粗能别薰蕕。", "識面苦不早，論交亦何尤。", "長裾曳非難，騖棹驚莫留。", "既懷難會戀，那無輕去愁。", "方今草寇猖，健兒炊矛頭。", "金盤集衛霍，藜糝甘軻邱。", "不知到死處，真得飽暖不。", "行當捫牽牛，快願同桴浮。"]'),
('573d1166-ca1d-4710-8ff5-f54ae0dc4b6a','次韻酬尹少稷','王洋','宋','宋诗','song-poetry','','[]','尹子於爲文，跳弄同戲劇。',228,'全唐诗/poet.song.96000.json','["尹子於爲文，跳弄同戲劇。", "舉頭發天藏，俛首取地蟄。", "誰謂熱洛河，可使當劉秩。", "揮毫射虎豹，引手唾決拾。", "馭風千里空，命的一箭疾。", "吾意召雷霆，已下六丁敕。", "置之西崑山，歌樂華胥國。", "遂令長吟哦，姓名注瑤籍。", "置之風露場，不飲亦不食。", "鸞鶴迎玉簫，雲漢配靈匹。", "雄辭水翻瓴，壯勢虎挾乙。", "剪裁霜月明，窺探化工密。", "少留千首詩，聊示萬人敵。", "不然薦清廟，三歎奉寥閴。", "未驚鄒海濤，已過髠轂炙。", "竊料充選拔，數塗當處一。", "恐緣奉髙堂，薪芼事朝夕。", "且安顔氏瓢，未縱參軍逸。", "我意似子才，終難守環壁。"]'),
('f4a63050-7da7-4872-8de4-9d1748637464','次韻李叔飛','王洋','宋','宋诗','song-poetry','','[]','溪山春蘭林，桃李花槐市。',120,'全唐诗/poet.song.96000.json','["溪山春蘭林，桃李花槐市。", "戲友二三生，興來遠返趾。", "墨客冠再彈，蒼官仕三已。", "矜豪柳索强，引分梅知止。", "綠芳草齊亞，粉面花襯綺。", "慶暖具杯觴，送寒操杖几。", "態度略不齊，將妍俱可喜。", "人心獨當然，造物聊戲耳。", "烏帽以舊留，青鞋請今始。", "相逢浩蕩春，切勿通爵里。"]'),
('d42b34ef-28ce-49dc-b694-163d7d59e35f','次韻政老夜坐有懷','王洋','宋','宋诗','song-poetry','','[]','客行犯蕭條，物態如寒冰。',180,'全唐诗/poet.song.96000.json','["客行犯蕭條，物態如寒冰。", "借問松窗人，久客將何營。", "答言慕幽禪，懷抱徹欲清。", "當年困流俗，鑽紙如癡蠅。", "一朝脫塵網，決若飛鳥驚。", "齋盂趁後輩，臥㲲陪老生。", "從兹輩行間，往往推先鳴。", "此道本無學，精粗不可評。", "忽然辨疆域，獨得分專城。", "物外懷抱好，醒來毛髮輕。", "餘事不着意，自然造純精。", "憐君生卑微，也縳利與名。", "持身抱餘恨，寫物多遁情。", "以此遊世間，心慮何由平。", "再拜謝師言，得閑頻寄聲。"]'),
('6c3c6177-371a-4631-87bd-d6406f8f2f2c','觀講師有感','王洋','宋','宋诗','song-poetry','','[]','一僧據几坐，衆僧列其間。',288,'全唐诗/poet.song.96000.json','["一僧據几坐，衆僧列其間。", "紛紛士與女，其外復相環。", "娟娟誰家女，粉面垂煙鬟。", "既爲時俗粧，復著道士冠。", "一聞法師唱，先衆低朱顔。", "俯仰皆中度，儀矩如素閑。", "衆僧推舉首，往往務旁觀。", "云是良家子，良人綴朝端。", "二十哭其夫，蕙幃守奇單。", "誓保歲寒節，悼往時汍瀾。", "鄰女聞好色，願見無由緣。", "孺枝無雜匹，對鏡有孤鸞。", "如此十餘載，里巷不敢讙。", "歲久厭俗累，幡然學僧禪。", "朝朝事香火，常念舍囂煩。", "遂來佛寺中，圓頂雜長髯。", "未能問以此，吁嗟涕以潸。", "女子本柔靜，閨房不肯安。", "當初紅顔時，何必同惸鰥。", "所行雖失節，尚可求芝蘭。", "如今餘艷態，卻來叩幽關。", "進退兩無據，此道何漫漫。", "京城富貴家，妍麗出塵寰。", "不肯自愛重，白日呈妖嫺。"]'),
('d62e257a-85e9-40dd-a4e9-7bc22fe204c4','和伯氏寄周秀實','王洋','宋','宋诗','song-poetry','','[]','相親即嘘濡，相忘即江湖。',204,'全唐诗/poet.song.96000.json','["相親即嘘濡，相忘即江湖。", "事理去取間，情分乃異區。", "周侯瑚璉器，晚乃擲道途。", "異書窺蔡叟，潛論發王符。", "夜諷恒至卯，朝飯或逾晡。", "置之轉徙流，奈此臭味殊。", "置之翰墨場，勇往無於菟。", "雖乏三寸舌，自保千金軀。", "山巔富蔬菜，渚牙長菰蒲。", "屈曲一徑寬，於焉寄其孥。", "非藥亦非餌，問君何歡娛。", "所樂麋鹿游，緇白初不渝。", "我於聞道新，齧肺方噬膚。", "喜翁新經過，已辦煮瓠壺。", "我有甑中塵，翁無竹裏廚。", "相見期一笑，良勝醉叫呼。", "水花正充容，小𣏾隨輕鳬。"]'),
('91634c53-23ee-4213-9d8e-ab07bad14c0e','和尹少稷經幹','王洋','宋','宋诗','song-poetry','','[]','昔年初見君，山頭日卓午。',168,'全唐诗/poet.song.96000.json','["昔年初見君，山頭日卓午。", "但言奉親歡，不道作詩苦。", "稍稍窺藩籬，清風滌袢暑。", "論文及古人，一笑乃相許。", "早知没津涯，矧肯起城府。", "結交得若人，渠彌有環渚。", "風帆笑沉著，健足不留佇。", "如何黄卷中，尚對古人語。", "田間把犂鉏，筆端灑風雨。", "我亦正宫懸，非君更全堵。", "往作九奏歌，屈指爲君數。", "矧今獨壯年，獻爵未酬旅。", "古鼎太廟牲，時花洛城女。", "如君作文章，兩壘竟安與。"]'),
('1ab9812c-2c5a-4c8d-a18f-165089339c6f','再和','王洋','宋','宋诗','song-poetry','','[]','故人客玄都，結茅臨子午。',168,'全唐诗/poet.song.96000.json','["故人客玄都，結茅臨子午。", "慈親哺童稚，十口共甘苦。", "門橫百琅玕，永日不受暑。", "浮名博煙霞，掉臂終不許。", "聽我讀新詩，小侯趨大府。", "揮毫散珠玉，風帆轉驚渚。", "北郭鄭仙翁，襟懷兩虚佇。", "尹氏才振古，仙翁筆端語。", "矛戈角森橫，畚鍤起雲雨。", "應笑窮巷生，蓬蒿半垣堵。", "所喜樂豐登，粒米不須數。", "況從名士游，真可釋羈旅。", "願君分餘光，下照及鄰女。", "切勿閟好音，文典實不與。"]'),
('b3a8f55d-28c8-4121-b8d2-6dbf2486c33c','和鄭丈侍郎','王洋','宋','宋诗','song-poetry','','[]','鴻濛棲神契，脫落力自由。',216,'全唐诗/poet.song.96000.json','["鴻濛棲神契，脫落力自由。", "諒此丈夫事，寧爲兒女憂。", "丈人志宇宙，纖芥無滯留。", "靜觀四大室，俛仰七十秋。", "詩寬江海涯，心無花月愁。", "請言平生志，曠度無陰謀。", "浩瀁馳三峽，涇渭分九流。", "霜皮峻千尺，回首走萬牛。", "大歷竹馬遊，即今誰在不。", "被髮下大荒，萬象散莫收。", "一舉攝倒景，百篇醒醉眸。", "矧此無妄疾，固可勿藥瘳。", "時當天宇清，皮人獻功裘。", "願公强舉巵，起慰瀟灑侯。", "列星搖參光，蟲鳥逃窮捜。", "前山方刻窟，粗可少獻酬。", "不作紅粉涴，那憂華髮羞。", "洪崖與浮邱，彩筆俱豐優。"]'),
('98df2ad4-4421-4f54-9aa5-95087da3fe8d','和李希言仙山書事','王洋','宋','宋诗','song-poetry','','[]','五年萍梗蹤，所向隨波流。',252,'全唐诗/poet.song.96000.json','["五年萍梗蹤，所向隨波流。", "請言初起時，皇輿向吳頭。", "觸目多變異，論心鮮朋儔。", "願借谷生筆，慚非奕者秋。", "憶昨元年中，紫墟拜松楸。", "搶攘逃賊庭，斂退勇自收。", "況知踳駮才，豈副英俊求。", "摧折縱俯仰，旋澁難調柔。", "放意山水間，恐合成窮捜。", "人事喜乖誤，奔茫赴南州。", "每緣身外交，不愜心事幽。", "有時塵壤際，獨羡滄海舟。", "平生欲往願，夢想從之遊。", "近者明詔寬，汰核真良謀。", "飛集任鳬雁，縱遣無半留。", "乃得陪髙人，一散百慮憂。", "艱難健兒貴，武爵輕公侯。", "吾徒合何如，甘分宜相投。", "況彼四士者，髙清懷遠邱。", "雍容秦中吟，激烈塞上謳。", "得失有如此，飄零晤良游。"]'),
('dea6ac1d-d7f9-4f25-9cc0-237798dcea75','酬鄧子','王洋','宋','宋诗','song-poetry','','[]','我年數七十，不過春五來。',96,'全唐诗/poet.song.96000.json','["我年數七十，不過春五來。", "素心歲月盡，白髪日夜催。", "縱懷獨往願，欲去心先回。", "惟思百境空，洗此一念埃。", "喜逢鄧仲子，妙語驚奔雷。", "未登黄金臺，要是白玉杯。", "安能駕飛車，與子相追陪。", "姑借喝月術，救我年齡穨。"]'),
('d778b92a-cd01-4785-8b0c-8e6f97c09f5e','子楚煮雪水瀹團茶乃舉陶翰林語以詩見戲不敢不酬','王洋','宋','宋诗','song-poetry','','[]','平生何居士，一壑清江濆。',108,'全唐诗/poet.song.96000.json','["平生何居士，一壑清江濆。", "達觀真大士，獨往乃聲聞。", "我亦策蹇步，不甘子絕群。", "追逐到滅景，回視嗟紛紜。", "今朝玉府開，群仙剪瑤裙。", "迷空散天花，萬疊屯寒雲。", "賞心會兩遂，百憂銷一焚。", "雙鳳已鳴似，神椎抗孤軍。", "更看陰沴盡，髙簷挂晴曛。"]'),
('1b48d337-6ec3-4656-9f1e-943e0d2352eb','謝吳提幹惠詩文','王洋','宋','宋诗','song-poetry','','[]','排門雪三尺，閉戶饑腸鳴。',108,'全唐诗/poet.song.96000.json','["排門雪三尺，閉戶饑腸鳴。", "擁騎遠方來，骨法秀以清。", "袖出一卷書，中有怖俗情。", "上言井有德，爲費四字銘。", "下言酒傷道，顛倒虞心兵。", "中流障百川，絕口無縱橫。", "君子皆是術，殄病人自驚。", "子其欲修我，匪以校我榮。", "再拜採雜佩，斯云得香蘅。"]'),
('95d7b22c-d8ae-487b-9c02-8429f72ccb25','代徐思遠謝張季萬','王洋','宋','宋诗','song-poetry','','[]','淳風嘆遼遠，友道傷澆漓。',288,'全唐诗/poet.song.96000.json','["淳風嘆遼遠，友道傷澆漓。", "交情比一線，斷續同羈縻。", "仁惇既難合，義重亦不支。", "寒谷少温律，衡門自寒扉。", "亦聞豪俠地，風月滿臺池。", "可憐伏雌客，出往無所施。", "淮鄉有病客，波浪逐淪彌。", "中流失舟檝，宛在水中泜。", "請叙先世德，繚遶窮方維。", "始奉華陰組，繼迹東南馳。", "道有海內譽，經爲淮上師。", "聞風事鑽仰，極力忘憊疲。", "求精析晉豕，辨僞正褒漦。", "大逐千里鵬，小察一寸鰭。", "旌善類騁駿，誅姦如戮鯢。", "魚蟲蛙蝦蛤，瑣瑣俱不遺。", "筆陣驥逸野，詞鋒江斬螭。", "導江派海尾，疏源河鑿岯。", "立言經寓宇，刊行結防隄。", "禮樂尊中國，春秋揮四夷。", "書謡切頌帝，詩化淑歌妃。", "德苑心潛遠，文帷性自嬉。", "謀心千古近，張目萬人睢。", "觀範推難習，同肩歎莫追。"]'),
('1ffe94e5-705b-4330-8aa2-00b8adc25db5','和沈子美梅詩','王洋','宋','宋诗','song-poetry','','[]','一氣如權衡，俯仰在緹室。',288,'全唐诗/poet.song.96000.json','["一氣如權衡，俯仰在緹室。", "鼓行橐籥間，草木俱應律。", "物物各有長，輩行皆屈膝。", "誰能長百花，寒梅最先密。", "自此啟端兆，次乃排等秩。", "微者或易傷，大者或不實。", "剪除困陵暴，糞掃如扑抶。", "駢開類爭妍，粉敗若老佚。", "採擷既紛紛，棄置復鬰鬰。", "大抵爭春花，柔弱忌寒冽。", "方知歲前梅，義勇過箭疾。", "有如比紅兒，觀者亦呵叱。", "有如當皺玉，卻欲數梨橘。", "又如奏金石，秋蟲並啁唧。", "又如持豨苓，便擬簉芝术。", "又如白玉堂，光耀映蓬蓽。", "以此難著語，老眼徒屢熨。", "前賢有題韻，靈還不容乞。", "欲寫文君容，相如口猶吃。", "投章自清絕，報聘我戰栗。", "昨者得君詩，冬景當暖日。", "猝然遇彊敵，不戰勢已屈。", "堂堂既難當，惴惴良自失。", "花前嫫姆陋，篆外青黄質。"]'),
('aa9c3a8d-7aed-44eb-a10d-c60792041b17','梅','王洋','宋','宋诗','song-poetry','','[]','心妙意難到，理淺語易俗。',48,'全唐诗/poet.song.96000.json','["心妙意難到，理淺語易俗。", "惟此公共美，路坦行自跼。", "彊勉思攀陪，雖懇不見錄。", "料想何水曹，平生一夔足。"]'),
('0b73414c-a617-447c-9ac9-5d8bbb14dce5','觀徐園金橘有感','王洋','宋','宋诗','song-poetry','','[]','金丸不逐肉，聚族居士園。',144,'全唐诗/poet.song.96000.json','["金丸不逐肉，聚族居士園。", "此園豈不佳，百卉念已繁。", "主人特愛重，列圍限兒孫。", "歲晚甘液成，饋薦籩豆存。", "楚楚小䍦欄，彌戴覆護恩。", "向來叢棘中，豈不茂本根。", "零落草木傍，未得依蘭蓀。", "一朝被華藻，如奉貢篚尊。", "輝輝黄金實，採摘勤加餐。", "乃知物貴賤，得失同一原。", "收用貴瑚璉，棄置輕邱樊。", "臨風一感歎，相向無復言。"]'),
('37566a6e-f4f5-4a67-b65a-27716dd276a3','枯柏','王洋','宋','宋诗','song-poetry','','[]','齋前兩柏樹，其大皆十圍。',288,'全唐诗/poet.song.96000.json','["齋前兩柏樹，其大皆十圍。", "我初營屋時，正與兩柏期。", "其一傍北亭，其一近南籬。", "相去十步間，當夏無炎曦。", "我翁時來遊，對此顔貌怡。", "群從來其間，或飲或賦詩。", "賓客來其間，顧盻屢解頤。", "桃李幾番春，不逐物態移。", "霜雪苦侵刻，曾不顔色衰。", "亦知堅貞性，凛凛不可期。", "夫何今年秋，予來自京師。", "哭親苫塊間，喘息絕自持。", "忽見南籬柏，索索但枯枝。", "徘徊柏樹下，終日懷嗟咨。", "家人對我言，柏死已經時。", "今年春夏交，老翁初見之。", "悲傷復愛惜，不忍加斧斯。", "意謂糞壤間，所處非所宜。", "材已中棟梁，安得死茅茨。", "爲此感慨久，子豈盡得知。", "我既聞此言，不覺重紛洟。", "豈爲小圃內，失此歲寒姿。", "蓋念天與人，響答良不疑。", "方夏巨柏死，致秋哲人萎。"]'),
('d63a7442-609a-41fe-a2d0-abfb2abb8ec7','八月道宫聞鶯','王洋','宋','宋诗','song-poetry','','[]','密林囀圓吭，流韻入清杳。',108,'全唐诗/poet.song.96000.json','["密林囀圓吭，流韻入清杳。", "當時太晚計，花前來不早。", "致使惜春人，聞聲恨先老。", "正緣幽谷春，朋友在久要。", "爭春快先鳴，無乃失友道。", "日塢集芳欄，名園唱清曉。", "得路共遷騰，此事不草草。", "即今秋色髙，金衣尚鮮好。", "歌舞興未闌，秋空樂晴昊。"]'),
('8d0a7913-36cf-4d46-8309-e071ff4058fe','和谹父尋春之作','王洋','宋','宋诗','song-poetry','','[]','穠華女兒紅，芳草王孫綠。',108,'全唐诗/poet.song.96000.json','["穠華女兒紅，芳草王孫綠。", "小大各盡態，低昻俱悅目。", "久雨脫滯著，振衣樂休沐。", "晴空吟思開，命簡句可屬。", "起看花覆墻，淨掃雲爲屋。", "幸會二三老，風騷命奴僕。", "欲說未說情，三篇兩篇足。", "玉人花暎面，眉黛添香醁。", "杯酒戒失身，無如飽捫腹。"]'),
('aff09f7f-6e6c-4cb7-897e-a7a68d7b93a4','路居士山水歌','王洋','宋','宋诗','song-poetry','','[]','人年八十百慮昏，丈人耳目方聰明。',384,'全唐诗/poet.song.96000.json','["人年八十百慮昏，丈人耳目方聰明。", "他人到此筋力疲，丈人勝如年少時。", "老中强健閑中忙，經卷丹爐肘後方。", "金書千軸造理窟，赤城七篇談坐忘。", "我年三十始相識，丈人年已幾六十。", "往來出處三十年，體無作用神安然。", "靜窺了不見根底，我謂君心秪如此。", "那知能事有别腸，筆下風光窮妙理。", "龜溪道人古衲師，心辭聲利常無爲。", "晨鐘粥鉢半爐火，午日茶甌一局棋。", "一朝共語小窗前，袖出小卷含風煙。", "爲言老路手作此，畫出王郎訪戴船。", "明朝見我微笑語，漏泄丹青奈緇侣。", "别有一段壺中天，果若知音定分付。", "輕輕一軸數尺長，奇峰突兀烟茫茫。", "其間細屑千萬狀，領略試爲哦新章。", "初畫寒林宿鳥驚，山蹊漸曉人漸行。", "四僧趁飯分先後，人立渡頭沙岸口。", "一舟閑泊石岸中，一舟半渡凌雲空。", "兩舟一釣一垂網，上有雁落蘆花風。", "兩橋近山轉清絕，客攜笻杖半卼臲。", "定是當年鶴氅翁，神氣飄飄犯寒雪。", "山腰佛寺樓閣明，下有茅店臨沙汀。", "刹竿挺立照山影，風幡髣髴聞談僧。"]'),
('3c3e3584-116d-4739-b973-ec18f29b8631','明妃曲','王洋','宋','宋诗','song-poetry','','[]','漢宫沈沈凝紫煙，妾身一入知幾年。',323,'全唐诗/poet.song.96000.json','["漢宫沈沈凝紫煙，妾身一入知幾年。", "樓髙秋月照清夜，亭暖春花熏醉眠。", "憶初送我辭親戚，便擬光華列旌戟。", "君門安得似人間，咫尺千山萬山隔。", "花月朝朝空暮暮，長戀朱顔不如故。", "內家車子散金錢，安得此身霑雨露。", "忽聞花宫選羅綺，單于來朝漢天子。", "但言妾欲嫁單于，萬一君王賞桃李。", "大明宫內宴呼韓，出水芙蓉鑑裏看。", "徘徊顧影花顔靚，綽約豐容廣殿寒。", "當日君王喜且驚，欲留失信去關情。", "若教不殺毛延壽，方信蛾眉畫不成。", "茫茫漢塞連沙漠，柳色陽關斷腸處。", "故鄉阡陌想依然，馬上琵琶向誰語。", "命薄身存有重輕，天山從此靜埃塵。", "山西健將如君否，此日安危託婦人。", "人生景物疾如馳，翻覆由來萬事非。", "莫笑巫山女粗醜，朝尋楚宫暮柴扉。", "男兒莫厭款段馬，女兒莫羡金縷衣。", "君不見巫山歌舞賽神罷，野老至今懷秭歸。"]'),
('28d4a0c9-7ceb-4be5-b739-7bcbb3a59921','乙酉閏八月二十一日出南城遊峴山壁間讀東坡詩感而有作','王洋','宋','宋诗','song-poetry','','[]','水晶宫名凡幾區，此州絕景天下無。',192,'全唐诗/poet.song.96000.json','["水晶宫名凡幾區，此州絕景天下無。", "寒溪十里出明鏡，峭壁千仞涵清虛。", "平生邱壑胸次間，長情自恨無時閑。", "干戈逐我出鄉曲，散浪卻不拘塵寰。", "往時足健輕追逐，吳會山川看未足。", "行來恰值積雨餘，萬疊峰巒發新綠。", "溪山長好人長閑，不信此州翻地軸。", "流落須論塞上翁，髙唱慚無郢中曲。", "千年陵谷多遷變，髙名長在唯稱賢。", "峴山上下碑在否，見說父老猶潸然。", "襄陽但記羊叔子，霅上風流亦如此。", "壁間誰記萬瓦詩，歎息前賢淚如洗。"]'),
('f1a06180-5b40-49d6-8041-3da7cdd3b0b4','鄰僧以木龕養蜂一日墜地僧見蜜積燎煙薰蜂蜂大駭散因割取幾盡適覩此事感而有作','王洋','宋','宋诗','song-poetry','','[]','採花供課能滿庾，不自營巢庇風雨。',240,'全唐诗/poet.song.96000.json','["採花供課能滿庾，不自營巢庇風雨。", "壘土削板非愛君，君自歸之若安堵。", "一聲衙集律令嚴，兩股挾持筋力苦。", "棟宇不牢偶墮地，盡見室家窺積聚。", "王緣積久頗厚實，招寇慢藏誰自取。", "山僧平日恐物傷，忍向么微施數罟。", "豈嫌嚼蠟味太薄，一割未厭猶再鼓。", "初猶忍戀縱追螫，俄困薰灼難力拒。", "驚飛浪走觸藩籬，往往散墮折肱股。", "害身即是養身人，愛本爲仇慈是虎。", "嘗聞釋氏戒奪食，此道胡爲今不數。", "刀頭得蜜吾何有，出力爲君傍作主。", "勸僧切勿苦有情，盍用慈悲銘肺腑。", "且留餘食供歲事，庶得春風容慢舞。", "丁寧更喻衆蜂王，自此亦可寬祖簿。"]'),
('db667429-1132-4c23-904d-5b90da0d3e36','讀中興頌碑','王洋','宋','宋诗','song-poetry','','[]','峨峨蜀道艱難路，萬里行人走征戍。',192,'全唐诗/poet.song.96000.json','["峨峨蜀道艱難路，萬里行人走征戍。", "招搖夜發川谷驚，回首長安滿煙霧。", "朔方日已催天明，朱輝散射朝霞升。", "旌旗指顧豺虎靜，風雨汛掃煙雲清。", "臣能奸君子詐父，身有妖雛不知顧。", "江中鹿死始悲嗟，帳下豬驚猶躁怒。", "萬年枝上春風回，明明九廟無風埃。", "扶鞋綴組命書重，崇邑大縣華封開。", "如何李父干天路，禍未单誅已交惡。", "子儀不保墳土乾，淮陽豈爲幽燕懼。", "太宗功業三代前，煌煌建立今古傳。", "兩宫哀笳十五曲，至今談者猶潸然。"]'),
('0e4eb25a-63f4-42d9-a3ea-0bbe1546ecc8','吳興苦雨','王洋','宋','宋诗','song-poetry','','[]','黄流渾渾彌川瀆，此邦不求長自足。',64,'全唐诗/poet.song.96000.json','["黄流渾渾彌川瀆，此邦不求長自足。", "人家蠶治怕桑寒，階下决明隨意綠。", "朝來横急如少止，忙亂車溝畎秧水。", "還君膏澤莫貪功，放出扶桑照千里。"]'),
('c4c2fed9-0330-4ec5-a355-d97509ecf700','病眼','王洋','宋','宋诗','song-poetry','','[]','寄身雖閑念未除，敵念賴有前賢書。',128,'全唐诗/poet.song.96000.json','["寄身雖閑念未除，敵念賴有前賢書。", "如何昏花接旬月，古史散落經耘耡。", "我知稟賦分量淺，費出稍泰尋空虛。", "衣服飲食悉若此，耳目形體應相如。", "此如用多隨困闕，不似緩節安虛徐。", "解衾臥穩省開目，細瑣悉悉分蟲魚。", "異時意氣尚掀舉，欲取功烈規名譽。", "從天且乞一雙眼，此外不敢求贏餘。"]'),
('a39b1a6e-e652-40d4-b755-42c538779824','憫旱','王洋','宋','宋诗','song-poetry','','[]','天心愛民非不勤，民心有恨天必聞。',96,'全唐诗/poet.song.96000.json','["天心愛民非不勤，民心有恨天必聞。", "爲嫌流水入城郭，指撝山澤收浮雲。", "浮雲未肯便承命，往來空中無定性。", "平時風伯讒口多，忍看雲師自奔横。", "願得天公張網羅，要令滅跡須嚴科。", "雷公傳聲澤靈死，嗚呼奈爾風伯何。"]'),
('3e9a7aa8-998f-4913-9624-97d85e6dc6e0','近冬至祭肉未給因叙其事','王洋','宋','宋诗','song-poetry','','[]','去年至日猶從俗，今年至日曾無肉。',229,'全唐诗/poet.song.96000.json','["去年至日猶從俗，今年至日曾無肉。", "食無臠{炙火=肉}情勿傷，祭不毛血貧太酷。", "起與婦謀宜早計，我典春衫君剪髻。", "但得豚肩略揜豆，敢事三牲共日祭。", "婦將捩髪猶忸怩，請君憑几聽致詞。", "所聞奉祀貴誠潔，誠果不立豐何爲。", "自爲君婦今有年，君家儉德相流傳。", "以其所養昔固爾，稱所豐儉今宜然。", "况聞隆殺古有制，禮貴視時成愷悌。", "順成八蜡乃得通，聖治功成方饗帝。", "方今大禮曾未充，倉廩不與昔日同。", "無財無田不可祭，子有籩豆那能豐。", "且求遠去酌行潦，在野不應嫌薄少。", "待得故鄉兵馬空，共買羔羊薦清醥。"]');
